/* Auto-generated from observapedia data files — 1599 terms */
export const GLOSSARY_TERMS = [{"term":"Artificial Intelligence","abbr":"AI","category":"AI/ML","definition":"The simulation of human intelligence processes by computer systems, including learning from experience, recognizing patterns, understanding language and making decisions. AI encompasses machine learning, deep learning, natural language processing and robotics.","related":["Machine Learning","Deep Learning","Neural Network"]},{"term":"Machine Learning","abbr":"ML","category":"AI/ML","definition":"A subset of AI that enables systems to learn and improve from experience without being explicitly programmed. Machine learning algorithms build models from training data and use them to make predictions or decisions on new data.","related":["Artificial Intelligence","Supervised Learning","Unsupervised Learning","Training Data"]},{"term":"Deep Learning","abbr":null,"category":"AI/ML","definition":"A subset of machine learning using artificial neural networks with multiple layers (deep architectures) to learn hierarchical representations of data. Deep learning powers modern applications in computer vision, natural language processing and speech recognition.","related":["Machine Learning","Neural Network","Backpropagation","Convolutional Neural Network"]},{"term":"Neural Network","abbr":null,"category":"AI/ML","definition":"A computational model inspired by biological neural networks in animal brains, consisting of interconnected nodes (neurons) organized in layers. Neural networks learn by adjusting connection weights through training, enabling them to approximate complex functions.","related":["Deep Learning","Neuron","Activation Function","Backpropagation"]},{"term":"Supervised Learning","abbr":null,"category":"AI/ML","definition":"A machine learning paradigm where models are trained on labeled data (input-output pairs) to learn the mapping between inputs and outputs. Common applications include classification and regression tasks.","related":["Machine Learning","Unsupervised Learning","Training Data","Label"]},{"term":"Unsupervised Learning","abbr":null,"category":"AI/ML","definition":"A machine learning approach where models are trained on unlabeled data to discover hidden patterns, structures or relationships. Common tasks include clustering, dimensionality reduction and anomaly detection.","related":["Machine Learning","Supervised Learning","Clustering","Dimensionality Reduction"]},{"term":"Reinforcement Learning","abbr":"RL","category":"AI/ML","definition":"A machine learning paradigm where an agent learns by interacting with an environment, receiving rewards or penalties for actions. The agent optimizes its behavior to maximize cumulative reward over time.","related":["Machine Learning","Reward","Policy","Q-Learning","Policy Gradient"]},{"term":"Transfer Learning","abbr":null,"category":"AI/ML","definition":"A machine learning technique where a model trained on one task is adapted for another task, leveraging knowledge learned in the source domain. Transfer learning significantly reduces training time and data requirements for new tasks.","related":["Machine Learning","Fine-Tuning","Pre-trained Model","Domain Adaptation"]},{"term":"Federated Learning","abbr":null,"category":"AI/ML","definition":"A machine learning approach where model training is distributed across multiple decentralized devices or organizations without centralizing raw data. Federated learning preserves privacy while enabling collaborative model improvement.","related":["Machine Learning","Privacy","Distributed Training","Differential Privacy"]},{"term":"Semi-Supervised Learning","abbr":null,"category":"AI/ML","definition":"A machine learning approach that combines small amounts of labeled data with large amounts of unlabeled data during training. Semi-supervised learning is useful when labeling data is expensive or time-consuming.","related":["Supervised Learning","Unsupervised Learning","Self-Training","Pseudo-Labeling"]},{"term":"Convolutional Neural Network","abbr":"CNN","category":"AI/ML","definition":"A neural network architecture designed for processing grid-like data such as images. CNNs use convolutional layers with learned filters to extract spatial features hierarchically, making them highly effective for computer vision tasks.","related":["Deep Learning","Neural Network","Convolution","Pooling","ResNet"]},{"term":"Recurrent Neural Network","abbr":"RNN","category":"AI/ML","definition":"A neural network architecture with loops that allow it to process sequential data by maintaining hidden state across time steps. RNNs are used for tasks involving sequences, such as time series prediction and language modeling.","related":["Deep Learning","LSTM","GRU","Sequence Modeling","Sequential Data"]},{"term":"Long Short-Term Memory","abbr":"LSTM","category":"AI/ML","definition":"A specialized RNN architecture designed to learn long-term dependencies in sequential data. LSTMs use memory cells with gates that control information flow, solving the vanishing gradient problem that affects standard RNNs.","related":["Recurrent Neural Network","GRU","Vanishing Gradient","Sequence Modeling"]},{"term":"Gated Recurrent Unit","abbr":"GRU","category":"AI/ML","definition":"A simplified variant of LSTM that uses fewer gates and parameters while maintaining similar performance. GRUs are computationally more efficient than LSTMs and work well for many sequence modeling tasks.","related":["Recurrent Neural Network","LSTM","Sequence Modeling"]},{"term":"Transformer","abbr":null,"category":"AI/ML","definition":"A neural network architecture based on self-attention mechanisms that processes entire sequences in parallel rather than sequentially. Transformers have become the foundation for modern large language models and have achieved state-of-the-art results across many AI tasks.","related":["Self-Attention","Attention Mechanism","Large Language Model","BERT","GPT"]},{"term":"Attention Mechanism","abbr":null,"category":"AI/ML","definition":"A neural network component that allows models to focus on relevant parts of input data by computing weighted combinations of all input elements. Attention mechanisms improve model interpretability and performance on sequence-to-sequence tasks.","related":["Transformer","Self-Attention","Query-Key-Value"]},{"term":"Self-Attention","abbr":null,"category":"AI/ML","definition":"An attention mechanism that computes relationships between elements within the same sequence, allowing each element to attend to other elements. Self-attention is the core mechanism enabling the parallelization and effectiveness of Transformer architectures.","related":["Attention Mechanism","Transformer","Multi-Head Attention"]},{"term":"Residual Network","abbr":"ResNet","category":"AI/ML","definition":"A deep neural network architecture that introduces skip connections allowing gradients to flow directly through layers. Skip connections enable training of very deep networks by mitigating the vanishing gradient problem.","related":["Deep Learning","Convolutional Neural Network","Vanishing Gradient"]},{"term":"Generative Adversarial Network","abbr":"GAN","category":"AI/ML","definition":"A framework where two neural networks (generator and discriminator) compete in a game-theoretic setting. The generator creates synthetic data while the discriminator learns to distinguish real from generated data, driving both networks to improve.","related":["Deep Learning","Generative Model","Generator","Discriminator"]},{"term":"Autoencoder","abbr":null,"category":"AI/ML","definition":"A neural network architecture that learns to compress data into a lower-dimensional latent representation and then reconstruct the original data. Autoencoders are used for dimensionality reduction, anomaly detection and feature learning.","related":["Deep Learning","Dimensionality Reduction","Encoder","Decoder"]},{"term":"Variational Autoencoder","abbr":"VAE","category":"AI/ML","definition":"A generative autoencoder that learns a probabilistic latent space, enabling both dimensionality reduction and generation of new data. VAEs use reparameterization and KL divergence to ensure the latent space is well-structured for sampling.","related":["Autoencoder","Generative Model","Latent Space","Probabilistic Model"]},{"term":"Vision Transformer","abbr":"ViT","category":"AI/ML","definition":"A transformer-based architecture adapted for computer vision that treats image patches as sequences. Vision Transformers have achieved competitive or superior performance compared to convolutional networks on image classification tasks.","related":["Transformer","Convolutional Neural Network","Image Classification"]},{"term":"Natural Language Processing","abbr":"NLP","category":"AI/ML","definition":"A subfield of AI focused on enabling computers to understand, interpret and generate human language. NLP applications include machine translation, sentiment analysis, question answering and chatbots.","related":["Large Language Model","Text Classification","Named Entity Recognition","Tokenization"]},{"term":"Large Language Model","abbr":"LLM","category":"AI/ML","definition":"A transformer-based neural network trained on massive amounts of text data to predict and generate language. Large language models exhibit emergent capabilities including reasoning, few-shot learning and instruction following.","related":["Transformer","Natural Language Processing","Foundation Model","Prompt Engineering"]},{"term":"BERT","abbr":"BERT","category":"AI/ML","definition":"Bidirectional Encoder Representations from Transformers — a pre-trained language model that uses masked language modeling and next sentence prediction. BERT has become a foundation model for many downstream NLP tasks.","related":["Language Model","Transformer","Pre-trained Model","Transfer Learning"]},{"term":"GPT","abbr":"GPT","category":"AI/ML","definition":"Generative Pre-trained Transformer — a family of large language models trained on autoregressive language modeling. GPT models exhibit strong performance on language generation and understanding tasks with minimal fine-tuning.","related":["Large Language Model","Transformer","Autoregressive Model"]},{"term":"Tokenization","abbr":null,"category":"AI/ML","definition":"The process of breaking text into smaller units (tokens) such as words, subwords or characters. Tokenization is a crucial preprocessing step for NLP models, affecting model performance and vocabulary size.","related":["Text Preprocessing","Vocabulary","Subword Tokenization","BPE"]},{"term":"Embedding","abbr":null,"category":"AI/ML","definition":"A dense vector representation of a word, phrase or document in a continuous vector space. Embeddings capture semantic meaning, allowing similar items to be represented by nearby vectors in high-dimensional space.","related":["Word2Vec","Tokenization","Semantic Similarity","Vector Space"]},{"term":"Word2Vec","abbr":null,"category":"AI/ML","definition":"A technique for learning word embeddings by predicting context words (skip-gram model) or predicting a target word from context (CBOW model). Word2Vec was revolutionary in demonstrating that embeddings capture semantic relationships.","related":["Embedding","Word Representation","Skip-Gram","Distributed Representation"]},{"term":"GloVe","abbr":null,"category":"AI/ML","definition":"Global Vectors for Word Representation — a method for learning word embeddings by combining matrix factorization and local context window methods. GloVe embeddings capture both global statistics and local context.","related":["Embedding","Word Representation","Word2Vec"]},{"term":"Named Entity Recognition","abbr":"NER","category":"AI/ML","definition":"An NLP task that identifies and classifies entities (persons, organizations, locations) in text. NER is foundational for information extraction, question answering and knowledge graph construction.","related":["Natural Language Processing","Text Classification","Sequence Labeling"]},{"term":"Sentiment Analysis","abbr":null,"category":"AI/ML","definition":"An NLP task that determines the emotional tone or opinion expressed in text (positive, negative, neutral). Sentiment analysis is used in social media monitoring, customer feedback analysis and market research.","related":["Text Classification","Opinion Mining","Natural Language Processing"]},{"term":"Machine Translation","abbr":null,"category":"AI/ML","definition":"The automatic translation of text from one language to another using computational methods. Neural machine translation using sequence-to-sequence models and transformers has dramatically improved translation quality.","related":["Natural Language Processing","Sequence-to-Sequence","Transformer"]},{"term":"Question Answering","abbr":"QA","category":"AI/ML","definition":"An NLP task where systems are trained to answer questions based on provided context or knowledge. Question answering is central to chatbots, search systems and virtual assistants.","related":["Natural Language Processing","Text Comprehension","Reading Comprehension"]},{"term":"Text Classification","abbr":null,"category":"AI/ML","definition":"An NLP task that assigns predefined categories to text documents. Applications include spam detection, content moderation, topic classification and intent detection.","related":["Natural Language Processing","Supervised Learning","Sentiment Analysis"]},{"term":"Text Summarization","abbr":null,"category":"AI/ML","definition":"An NLP task that generates concise summaries of longer text. Abstractive summarization generates new text while extractive summarization selects existing sentences from the source.","related":["Natural Language Processing","Sequence-to-Sequence","Abstractive Summarization"]},{"term":"Prompt Engineering","abbr":null,"category":"AI/ML","definition":"The art of crafting input prompts to elicit desired outputs from language models. Effective prompt engineering involves phrasing, context provision and few-shot examples to guide model behavior.","related":["Large Language Model","Few-Shot Learning","In-Context Learning"]},{"term":"Few-Shot Learning","abbr":null,"category":"AI/ML","definition":"A machine learning approach where models learn from a small number of examples and generalize to new tasks. Few-shot learning leverages knowledge from pre-training to rapidly adapt to new problems.","related":["Transfer Learning","Meta-Learning","In-Context Learning","Large Language Model"]},{"term":"Zero-Shot Learning","abbr":null,"category":"AI/ML","definition":"A machine learning approach where models make predictions on tasks without seeing any training examples. Zero-shot learning relies on semantic knowledge and cross-task generalization from pre-training.","related":["Few-Shot Learning","Transfer Learning","Large Language Model"]},{"term":"In-Context Learning","abbr":null,"category":"AI/ML","definition":"A capability of large language models to learn from examples provided in the prompt context without gradient updates. In-context learning enables rapid adaptation and is a key feature of modern LLMs.","related":["Few-Shot Learning","Large Language Model","Prompt Engineering"]},{"term":"Chain of Thought","abbr":"CoT","category":"AI/ML","definition":"A prompting technique that encourages language models to explain their reasoning step-by-step before providing an answer. Chain of thought prompting significantly improves performance on reasoning-heavy tasks.","related":["Prompt Engineering","Large Language Model","Reasoning"]},{"term":"Computer Vision","abbr":null,"category":"AI/ML","definition":"A subfield of AI that enables machines to interpret and understand visual information from images and videos. Computer vision applications include object detection, image classification, segmentation and facial recognition.","related":["Convolutional Neural Network","Object Detection","Image Classification","Semantic Segmentation"]},{"term":"Image Classification","abbr":null,"category":"AI/ML","definition":"A computer vision task that assigns predefined categories to images. Image classification is fundamental for applications like content moderation, medical imaging and autonomous systems.","related":["Computer Vision","Convolutional Neural Network","Deep Learning"]},{"term":"Object Detection","abbr":null,"category":"AI/ML","definition":"A computer vision task that identifies and localizes objects within images by drawing bounding boxes. Object detection is crucial for autonomous vehicles, surveillance systems and inventory management.","related":["Computer Vision","Convolutional Neural Network","YOLO","R-CNN"]},{"term":"YOLO","abbr":"YOLO","category":"AI/ML","definition":"You Only Look Once — a real-time object detection algorithm that frames detection as a single regression problem. YOLO is fast, accurate and widely used in production computer vision systems.","related":["Object Detection","Convolutional Neural Network","Real-Time Detection"]},{"term":"R-CNN","abbr":null,"category":"AI/ML","definition":"Region-based Convolutional Neural Network — a family of object detection methods that first identify region proposals and then classify them. R-CNN variants (Fast R-CNN, Faster R-CNN) improved speed and accuracy.","related":["Object Detection","Convolutional Neural Network","Region Proposal"]},{"term":"Semantic Segmentation","abbr":null,"category":"AI/ML","definition":"A computer vision task that assigns a class label to each pixel in an image. Semantic segmentation is used in autonomous driving, medical imaging and scene understanding.","related":["Computer Vision","Image Segmentation","Pixel-Wise Classification"]},{"term":"Instance Segmentation","abbr":null,"category":"AI/ML","definition":"A computer vision task that identifies individual objects (instances) within an image and segments their boundaries. Instance segmentation combines object detection and semantic segmentation.","related":["Semantic Segmentation","Object Detection","Mask R-CNN"]},{"term":"Panoptic Segmentation","abbr":null,"category":"AI/ML","definition":"A unified computer vision task combining semantic and instance segmentation to label all pixels with both a class and instance ID. Panoptic segmentation provides comprehensive scene understanding.","related":["Semantic Segmentation","Instance Segmentation"]},{"term":"Face Recognition","abbr":null,"category":"AI/ML","definition":"A computer vision task that identifies individuals from facial images. Face recognition uses deep learning to extract distinctive facial features and match them against a gallery of known faces.","related":["Computer Vision","Biometric Identification","Facial Landmark Detection"]},{"term":"Pose Estimation","abbr":null,"category":"AI/ML","definition":"A computer vision task that detects body joints and estimates the spatial configuration of human poses in images. Pose estimation is used in action recognition, fitness tracking and human-computer interaction.","related":["Computer Vision","Keypoint Detection","Skeletal Tracking"]},{"term":"Depth Estimation","abbr":null,"category":"AI/ML","definition":"A computer vision task that infers the depth (distance from camera) of pixels in an image. Depth estimation enables 3D scene reconstruction and is crucial for robotics and autonomous systems.","related":["Computer Vision","3D Reconstruction","Stereo Vision"]},{"term":"Optical Character Recognition","abbr":"OCR","category":"AI/ML","definition":"A technology that converts images of printed or handwritten text into machine-readable digital text. OCR enables document digitization, information extraction and accessibility applications.","related":["Computer Vision","Text Detection","Scene Text Recognition"]},{"term":"Backpropagation","abbr":null,"category":"AI/ML","definition":"An algorithm for computing gradients in neural networks by efficiently propagating errors backward through layers. Backpropagation enables training of deep networks and is fundamental to modern deep learning.","related":["Gradient Descent","Neural Network","Chain Rule"]},{"term":"Gradient Descent","abbr":null,"category":"AI/ML","definition":"An optimization algorithm that iteratively updates model parameters in the direction of steepest descent of the loss function. Gradient descent is the foundation of neural network training.","related":["Backpropagation","Optimization","Learning Rate","Convergence"]},{"term":"Stochastic Gradient Descent","abbr":"SGD","category":"AI/ML","definition":"A variant of gradient descent that updates parameters using gradients computed on mini-batches or single samples. SGD is computationally efficient and often achieves better generalization than batch gradient descent.","related":["Gradient Descent","Optimization","Mini-Batch"]},{"term":"Adam Optimizer","abbr":null,"category":"AI/ML","definition":"Adaptive Moment Estimation — an optimization algorithm that combines advantages of momentum and RMSprop. Adam adapts learning rates for each parameter and is widely used for training deep learning models.","related":["Gradient Descent","Momentum","RMSprop","Optimization"]},{"term":"Momentum","abbr":null,"category":"AI/ML","definition":"An optimization technique that accumulates gradients over time to accelerate convergence in consistent directions. Momentum helps escape local minima and stabilizes training in neural networks.","related":["Gradient Descent","Optimization","Nesterov Momentum"]},{"term":"Learning Rate","abbr":null,"category":"AI/ML","definition":"A hyperparameter that controls the step size taken by optimization algorithms. Learning rate is critical for training stability and convergence speed; too high causes divergence while too low causes slow convergence.","related":["Gradient Descent","Hyperparameter","Learning Rate Scheduling"]},{"term":"Learning Rate Scheduling","abbr":null,"category":"AI/ML","definition":"A technique that adjusts the learning rate during training according to a predefined schedule. Learning rate scheduling helps balance fast convergence early in training with fine-tuning later.","related":["Learning Rate","Optimization","Warm-Up"]},{"term":"Batch Normalization","abbr":null,"category":"AI/ML","definition":"A technique that normalizes inputs to neural network layers to have zero mean and unit variance. Batch normalization accelerates training, allows higher learning rates and acts as regularization.","related":["Normalization","Layer Normalization","Neural Network"]},{"term":"Layer Normalization","abbr":null,"category":"AI/ML","definition":"A normalization technique that normalizes inputs across features for each training example independently. Layer normalization is particularly effective in transformers and avoids issues with small batch sizes.","related":["Batch Normalization","Normalization"]},{"term":"Dropout","abbr":null,"category":"AI/ML","definition":"A regularization technique that randomly deactivates neurons during training to prevent co-adaptation. Dropout acts as an ensemble method and significantly reduces overfitting without increasing computational cost.","related":["Regularization","Overfitting","Regularization Techniques"]},{"term":"Early Stopping","abbr":null,"category":"AI/ML","definition":"A regularization technique that halts training when validation performance stops improving. Early stopping prevents overfitting and saves computational resources.","related":["Regularization","Validation Set","Overfitting"]},{"term":"L1 Regularization","abbr":null,"category":"AI/ML","definition":"A regularization technique that adds the sum of absolute parameter values to the loss function. L1 regularization encourages sparse solutions where many parameters become zero.","related":["Regularization","L2 Regularization","Overfitting"]},{"term":"L2 Regularization","abbr":null,"category":"AI/ML","definition":"A regularization technique that adds the sum of squared parameter values to the loss function. L2 regularization penalizes large weights and encourages solutions with small parameter values.","related":["Regularization","L1 Regularization","Weight Decay","Overfitting"]},{"term":"Weight Decay","abbr":null,"category":"AI/ML","definition":"A regularization technique that reduces model parameters by a constant factor during each optimization step. Weight decay is equivalent to L2 regularization in gradient descent.","related":["L2 Regularization","Regularization","Optimization"]},{"term":"Convergence","abbr":null,"category":"AI/ML","definition":"The state reached when an optimization algorithm stops improving the loss function or reaches acceptable performance. Convergence analysis ensures training stability and efficiency.","related":["Gradient Descent","Loss Function","Training"]},{"term":"Loss Function","abbr":null,"category":"AI/ML","definition":"A mathematical function that quantifies the difference between predicted and actual values, guiding model learning. The choice of loss function determines what the model optimizes for.","related":["Objective Function","Optimization","Backpropagation"]},{"term":"Cross-Entropy Loss","abbr":null,"category":"AI/ML","definition":"A loss function commonly used for classification tasks that measures the difference between predicted probability distributions and actual labels. Cross-entropy is derived from information theory.","related":["Loss Function","Classification","Softmax"]},{"term":"Mean Squared Error","abbr":"MSE","category":"AI/ML","definition":"A loss function that measures the average squared difference between predicted and actual values. MSE is commonly used for regression tasks and is sensitive to large errors.","related":["Loss Function","Regression","Mean Absolute Error"]},{"term":"Vanishing Gradient Problem","abbr":null,"category":"AI/ML","definition":"A phenomenon where gradients become exponentially small during backpropagation through many layers, making training very slow. LSTMs and skip connections are designed to mitigate this problem.","related":["Gradient Descent","Backpropagation","LSTM","ResNet"]},{"term":"Exploding Gradient Problem","abbr":null,"category":"AI/ML","definition":"A phenomenon where gradients become exponentially large during backpropagation, causing numerical instability. Gradient clipping is commonly used to prevent exploding gradients.","related":["Gradient Descent","Vanishing Gradient Problem","Gradient Clipping"]},{"term":"Gradient Clipping","abbr":null,"category":"AI/ML","definition":"A technique that caps gradient values to a maximum threshold to prevent exploding gradients. Gradient clipping is particularly important for training RNNs and transformers.","related":["Exploding Gradient Problem","Gradient Descent"]},{"term":"Training Data","abbr":null,"category":"AI/ML","definition":"A dataset used to train machine learning models by adjusting parameters to fit the data. Quality and quantity of training data significantly impact model performance.","related":["Validation Set","Test Set","Dataset","Data Augmentation"]},{"term":"Validation Set","abbr":null,"category":"AI/ML","definition":"A dataset used to evaluate model performance during training and tune hyperparameters. The validation set helps prevent overfitting and guides early stopping.","related":["Training Data","Test Set","Hyperparameter","Cross-Validation"]},{"term":"Test Set","abbr":null,"category":"AI/ML","definition":"A dataset held out from training and used only for final evaluation of model performance. The test set provides an unbiased estimate of how well the model will perform on new data.","related":["Training Data","Validation Set","Evaluation Metrics"]},{"term":"Cross-Validation","abbr":null,"category":"AI/ML","definition":"A technique for evaluating model performance by dividing data into k folds, training on k-1 folds and testing on the remaining fold. Cross-validation provides more robust performance estimates than a single train-test split.","related":["Validation Set","Test Set","k-Fold","Evaluation Metrics"]},{"term":"Data Augmentation","abbr":null,"category":"AI/ML","definition":"A technique that artificially increases training data by applying transformations (rotation, flip, crop for images). Data augmentation improves model robustness and reduces overfitting when data is limited.","related":["Training Data","Overfitting","Regularization"]},{"term":"Imbalanced Data","abbr":null,"category":"AI/ML","definition":"A dataset where classes are not equally represented, causing standard models to be biased toward the majority class. Techniques like oversampling, undersampling and cost-sensitive learning address this problem.","related":["Class Imbalance","Sampling","Precision","Recall"]},{"term":"Class Imbalance","abbr":null,"category":"AI/ML","definition":"A scenario where some classes in a classification problem have far fewer examples than others. Class imbalance requires special handling such as stratified sampling or weighted loss functions.","related":["Imbalanced Data","Sampling","Cost-Sensitive Learning"]},{"term":"Precision","abbr":null,"category":"AI/ML","definition":"An evaluation metric for classification that measures the fraction of predicted positive examples that are actually positive. Precision is important when false positives are costly.","related":["Recall","F1-Score","Confusion Matrix","Classification Metrics"]},{"term":"Recall","abbr":null,"category":"AI/ML","definition":"An evaluation metric for classification that measures the fraction of actual positive examples that are correctly predicted. Recall is important when false negatives are costly.","related":["Precision","F1-Score","Confusion Matrix","Classification Metrics"]},{"term":"F1-Score","abbr":null,"category":"AI/ML","definition":"An evaluation metric that is the harmonic mean of precision and recall, providing a balanced measure of classification performance. F1-score is useful for imbalanced datasets.","related":["Precision","Recall","Classification Metrics"]},{"term":"Accuracy","abbr":null,"category":"AI/ML","definition":"An evaluation metric that measures the fraction of correct predictions. While simple, accuracy can be misleading on imbalanced datasets.","related":["Precision","Recall","Classification Metrics"]},{"term":"ROC Curve","abbr":"ROC","category":"AI/ML","definition":"Receiver Operating Characteristic — a curve plotting true positive rate against false positive rate at various classification thresholds. ROC curves visualize classifier performance across thresholds.","related":["AUC","Classification Metrics","Threshold"]},{"term":"AUC","abbr":"AUC","category":"AI/ML","definition":"Area Under the Curve — typically refers to the area under the ROC curve, providing a single-number summary of classifier performance. AUC ranges from 0 to 1, with 1 representing perfect classification.","related":["ROC Curve","Classification Metrics"]},{"term":"Confusion Matrix","abbr":null,"category":"AI/ML","definition":"A table summarizing classification results by showing true positives, false positives, true negatives and false negatives. The confusion matrix enables computation of multiple evaluation metrics.","related":["Precision","Recall","Classification Metrics"]},{"term":"Mean Average Precision","abbr":"mAP","category":"AI/ML","definition":"An evaluation metric for object detection that averages the precision at different recall levels. mAP is the standard metric for evaluating detection models.","related":["Precision","Object Detection","Evaluation Metrics"]},{"term":"BLEU Score","abbr":null,"category":"AI/ML","definition":"Bilingual Evaluation Understudy — a metric for evaluating machine translation quality by comparing n-gram overlap with reference translations. BLEU scores range from 0 to 1.","related":["Machine Translation","Evaluation Metrics"]},{"term":"ROUGE Score","abbr":null,"category":"AI/ML","definition":"Recall-Oriented Understudy for Gisting Evaluation — a family of metrics for evaluating text summarization and machine translation. ROUGE measures n-gram overlap between generated and reference text.","related":["Text Summarization","Machine Translation","Evaluation Metrics"]},{"term":"Perplexity","abbr":null,"category":"AI/ML","definition":"An evaluation metric for language models that measures how well a probability model predicts a test sample. Lower perplexity indicates better predictions.","related":["Language Model","Evaluation Metrics"]},{"term":"Clustering","abbr":null,"category":"AI/ML","definition":"An unsupervised learning task that groups similar data points into clusters without predefined labels. Clustering is used for customer segmentation, document organization and anomaly detection.","related":["Unsupervised Learning","K-Means","Hierarchical Clustering","DBSCAN"]},{"term":"K-Means","abbr":null,"category":"AI/ML","definition":"A clustering algorithm that partitions data into k clusters by minimizing within-cluster variance. K-Means is simple, scalable and widely used despite requiring k to be specified beforehand.","related":["Clustering","Centroid","Euclidean Distance"]},{"term":"Hierarchical Clustering","abbr":null,"category":"AI/ML","definition":"A clustering approach that builds a tree of clusters (dendrogram) by iteratively merging or splitting clusters. Hierarchical clustering provides intuitive visualizations and doesn't require specifying the number of clusters.","related":["Clustering","Dendrogram","Agglomerative Clustering"]},{"term":"DBSCAN","abbr":null,"category":"AI/ML","definition":"Density-Based Spatial Clustering of Applications with Noise — a clustering algorithm that groups points based on density without requiring the number of clusters. DBSCAN can discover arbitrary-shaped clusters and identify outliers.","related":["Clustering","Density-Based Clustering","Outlier Detection"]},{"term":"Dimensionality Reduction","abbr":null,"category":"AI/ML","definition":"A technique that reduces the number of features in a dataset while preserving important information. Dimensionality reduction improves computational efficiency and visualization while reducing overfitting.","related":["Feature Selection","Principal Component Analysis","t-SNE","Autoencoder"]},{"term":"Principal Component Analysis","abbr":"PCA","category":"AI/ML","definition":"A linear dimensionality reduction technique that finds principal components (directions of maximum variance) in data. PCA is widely used for data visualization, noise reduction and feature engineering.","related":["Dimensionality Reduction","Feature Engineering","Linear Transformation"]},{"term":"t-SNE","abbr":null,"category":"AI/ML","definition":"t-Distributed Stochastic Neighbor Embedding — a nonlinear dimensionality reduction technique particularly effective for visualization. t-SNE preserves local structure and creates visually interpretable 2D/3D embeddings.","related":["Dimensionality Reduction","Visualization","UMAP"]},{"term":"UMAP","abbr":null,"category":"AI/ML","definition":"Uniform Manifold Approximation and Projection — a dimensionality reduction technique that preserves both local and global structure. UMAP is faster than t-SNE while producing similar or better visualizations.","related":["Dimensionality Reduction","t-SNE","Visualization"]},{"term":"Feature Engineering","abbr":null,"category":"AI/ML","definition":"The process of creating new features from raw data to improve model performance. Effective feature engineering is often more important than algorithm selection for machine learning success.","related":["Feature Selection","Feature Extraction","Feature Scaling"]},{"term":"Feature Selection","abbr":null,"category":"AI/ML","definition":"The process of choosing a subset of relevant features for model training. Feature selection reduces overfitting, improves interpretability and decreases computational cost.","related":["Feature Engineering","Dimensionality Reduction"]},{"term":"Feature Scaling","abbr":null,"category":"AI/ML","definition":"A preprocessing technique that transforms features to a common scale (e.g., standardization or normalization). Feature scaling improves model convergence and prevents features with larger scales from dominating.","related":["Feature Engineering","Normalization","Standardization"]},{"term":"Normalization","abbr":null,"category":"AI/ML","definition":"A preprocessing technique that scales features to a fixed range (usually [0, 1]). Normalization is useful when the scale of features varies widely.","related":["Feature Scaling","Standardization"]},{"term":"Standardization","abbr":null,"category":"AI/ML","definition":"A preprocessing technique that transforms features to have zero mean and unit variance. Standardization is often preferred for algorithms that assume normally distributed data.","related":["Feature Scaling","Normalization"]},{"term":"Attention","abbr":null,"category":"AI/ML","definition":"A neural network mechanism that allows models to focus on relevant parts of input by computing weighted combinations. Attention is fundamental to modern architectures and improves interpretability.","related":["Transformer","Self-Attention","Multi-Head Attention"]},{"term":"Multi-Head Attention","abbr":null,"category":"AI/ML","definition":"An attention variant that uses multiple attention heads in parallel, allowing models to attend to different representation subspaces. Multi-head attention is a key component of transformers.","related":["Attention","Transformer","Self-Attention"]},{"term":"Sequence-to-Sequence","abbr":"Seq2Seq","category":"AI/ML","definition":"A neural network architecture consisting of an encoder that processes input and a decoder that generates output. Seq2seq models are foundational for machine translation, summarization and question answering.","related":["Encoder","Decoder","Attention","Transformer"]},{"term":"Encoder","abbr":null,"category":"AI/ML","definition":"A neural network component that processes input data and produces a compact representation (encoding). Encoders are used in autoencoders, seq2seq models and embedding networks.","related":["Decoder","Representation Learning","Embedding"]},{"term":"Decoder","abbr":null,"category":"AI/ML","definition":"A neural network component that takes a compact representation and generates output data. Decoders are used in autoencoders, seq2seq models and generative models.","related":["Encoder","Sequence-to-Sequence","Generative Model"]},{"term":"Generative Model","abbr":null,"category":"AI/ML","definition":"A machine learning model that learns to generate new samples from a data distribution. Generative models include VAEs, GANs, diffusion models and autoregressive models.","related":["Discriminative Model","GAN","VAE","Diffusion Model"]},{"term":"Discriminative Model","abbr":null,"category":"AI/ML","definition":"A machine learning model that learns to classify or distinguish between data samples. Discriminative models directly model the decision boundary between classes.","related":["Generative Model","Classification","Supervised Learning"]},{"term":"Anomaly Detection","abbr":null,"category":"AI/ML","definition":"A machine learning task that identifies unusual or anomalous patterns in data. Anomaly detection is used in fraud detection, system monitoring and quality control.","related":["Unsupervised Learning","Outlier Detection","Autoencoder"]},{"term":"Outlier Detection","abbr":null,"category":"AI/ML","definition":"A technique for identifying data points that deviate significantly from the normal pattern. Outlier detection is closely related to anomaly detection.","related":["Anomaly Detection","DBSCAN","Isolation Forest"]},{"term":"Representation Learning","abbr":null,"category":"AI/ML","definition":"The process of learning meaningful feature representations from raw data. Representation learning enables downstream tasks to benefit from learned abstractions.","related":["Feature Learning","Deep Learning","Embedding"]},{"term":"Contrastive Learning","abbr":null,"category":"AI/ML","definition":"A self-supervised learning approach that learns representations by contrasting similar and dissimilar samples. Contrastive learning has achieved strong results in computer vision and NLP.","related":["Self-Supervised Learning","Representation Learning","SimCLR"]},{"term":"Self-Supervised Learning","abbr":null,"category":"AI/ML","definition":"A learning paradigm where labels are automatically derived from unlabeled data itself. Self-supervised learning enables models to learn rich representations from massive unlabeled datasets.","related":["Unsupervised Learning","Contrastive Learning","Masked Language Modeling"]},{"term":"Meta-Learning","abbr":null,"category":"AI/ML","definition":"Learning how to learn — a paradigm where models are trained to quickly adapt to new tasks with few examples. Meta-learning is crucial for few-shot learning applications.","related":["Few-Shot Learning","Transfer Learning","MAML"]},{"term":"Knowledge Distillation","abbr":null,"category":"AI/ML","definition":"A technique where a smaller student model learns from a larger teacher model by matching its outputs. Knowledge distillation enables deployment of efficient models while maintaining performance.","related":["Model Compression","Transfer Learning"]},{"term":"Quantization","abbr":null,"category":"AI/ML","definition":"A technique that reduces model size and computational requirements by representing weights and activations with lower precision. Quantization enables deployment on edge devices.","related":["Model Compression","Knowledge Distillation"]},{"term":"Pruning","abbr":null,"category":"AI/ML","definition":"A model compression technique that removes less important weights or neurons from a trained model. Pruning reduces model size and inference latency with minimal performance loss.","related":["Model Compression","Quantization"]},{"term":"Model Compression","abbr":null,"category":"AI/ML","definition":"A set of techniques including pruning, quantization and knowledge distillation to reduce model size. Model compression enables deployment on resource-constrained devices.","related":["Pruning","Quantization","Knowledge Distillation"]},{"term":"Explainability","abbr":null,"category":"AI/ML","definition":"The ability to understand and interpret why a machine learning model makes specific predictions. Explainability is crucial for building trust and meeting regulatory requirements.","related":["Interpretability","SHAP","LIME"]},{"term":"Interpretability","abbr":null,"category":"AI/ML","definition":"The degree to which humans can understand the reasoning behind model predictions. Interpretable models are preferred in high-stakes domains like healthcare and finance.","related":["Explainability","Feature Importance"]},{"term":"SHAP","abbr":null,"category":"AI/ML","definition":"SHapley Additive exPlanations — a game-theoretic approach to explaining model predictions based on cooperative game theory. SHAP values provide consistent and locally accurate model explanations.","related":["Explainability","Interpretability","Feature Importance"]},{"term":"LIME","abbr":null,"category":"AI/ML","definition":"Local Interpretable Model-Agnostic Explanations — a technique that explains model predictions by fitting interpretable models around specific instances. LIME works with any black-box model.","related":["Explainability","Interpretability"]},{"term":"Feature Importance","abbr":null,"category":"AI/ML","definition":"A measure of how much each feature contributes to model predictions. Feature importance helps identify influential features and aids model interpretation.","related":["Interpretability","SHAP","Permutation Importance"]},{"term":"Benchmark Dataset","abbr":null,"category":"AI/ML","definition":"A standardized dataset used to evaluate and compare model performance. Benchmark datasets enable reproducible research and fair comparison across methods.","related":["Dataset","Evaluation Metrics","ImageNet"]},{"term":"ImageNet","abbr":null,"category":"AI/ML","definition":"A large-scale visual database containing over 14 million images organized by WordNet. ImageNet has been instrumental in advancing computer vision through annual classification challenges.","related":["Benchmark Dataset","Computer Vision","Object Classification"]},{"term":"MNIST","abbr":null,"category":"AI/ML","definition":"A dataset of 70,000 handwritten digits (0-9) with 28x28 pixel grayscale images. MNIST is a classic benchmark for image classification and neural network research.","related":["Benchmark Dataset","Image Classification"]},{"term":"CIFAR-10","abbr":null,"category":"AI/ML","definition":"A dataset of 60,000 32x32 pixel color images across 10 object categories (airplane, automobile, bird, etc.). CIFAR-10 is a popular benchmark for image classification research.","related":["Benchmark Dataset","Image Classification"]},{"term":"COCO Dataset","abbr":null,"category":"AI/ML","definition":"Common Objects in Context — a large-scale dataset with over 330,000 images containing object detection, instance segmentation and keypoint annotations. COCO is the standard benchmark for object detection.","related":["Benchmark Dataset","Object Detection","Instance Segmentation"]},{"term":"SQuAD","abbr":null,"category":"AI/ML","definition":"Stanford Question Answering Dataset — a reading comprehension dataset with over 100,000 questions from Wikipedia articles. SQuAD is a standard benchmark for evaluating question answering systems.","related":["Benchmark Dataset","Question Answering"]},{"term":"Diffusion Model","abbr":null,"category":"AI/ML","definition":"A generative model that learns to remove noise from data iteratively. Diffusion models have achieved state-of-the-art results in image and text generation.","related":["Generative Model","Denoising","Stable Diffusion"]},{"term":"Stable Diffusion","abbr":null,"category":"AI/ML","definition":"A text-to-image diffusion model that generates high-quality images from text descriptions. Stable Diffusion is open-source and efficient enough to run on consumer GPUs.","related":["Diffusion Model","Text-to-Image Generation"]},{"term":"EfficientNet","abbr":null,"category":"AI/ML","definition":"A family of convolutional neural networks that achieve state-of-the-art accuracy with significantly fewer parameters and lower computational cost. EfficientNet uses compound scaling to balance model depth, width and resolution.","related":["Convolutional Neural Network","Image Classification"]},{"term":"MobileNet","abbr":null,"category":"AI/ML","definition":"A lightweight convolutional neural network architecture designed for mobile and edge devices. MobileNet uses depthwise separable convolutions to reduce parameters and computation.","related":["Convolutional Neural Network","Model Compression","Edge AI"]},{"term":"ViLBERT","abbr":null,"category":"AI/ML","definition":"Vision and Language BERT — a pre-trained model for vision-language tasks that uses transformers to jointly process images and text. ViLBERT enables zero-shot and few-shot vision-language understanding.","related":["Multimodal Learning","Transformer","BERT"]},{"term":"CLIP","abbr":null,"category":"AI/ML","definition":"Contrastive Language-Image Pre-Training — a model trained to understand relationships between images and text through contrastive learning. CLIP enables zero-shot image classification and retrieval.","related":["Contrastive Learning","Multimodal Learning","Zero-Shot Learning"]},{"term":"Multimodal Learning","abbr":null,"category":"AI/ML","definition":"A machine learning approach that integrates information from multiple modalities (vision, text, audio). Multimodal models enable understanding of complex relationships between different data types.","related":["Vision-Language Model","Audio-Visual Learning"]},{"term":"Vision-Language Model","abbr":null,"category":"AI/ML","definition":"A model that understands and generates content involving both images and text. Vision-language models enable applications like visual question answering and image captioning.","related":["Multimodal Learning","CLIP","ViLBERT"]},{"term":"Speech Recognition","abbr":null,"category":"AI/ML","definition":"A task that converts spoken audio into written text. Modern speech recognition uses deep learning and transformer-based models for high accuracy.","related":["Natural Language Processing","Audio Processing","Wav2Vec"]},{"term":"Text-to-Speech","abbr":"TTS","category":"AI/ML","definition":"A task that synthesizes natural-sounding speech from text. Text-to-speech uses neural vocoders and attention mechanisms for high-quality speech generation.","related":["Speech Synthesis","Audio Generation"]},{"term":"Wav2Vec","abbr":null,"category":"AI/ML","definition":"A self-supervised learning approach for speech representation learning that learns directly from raw waveforms. Wav2Vec has improved speech recognition performance across languages.","related":["Speech Recognition","Self-Supervised Learning"]},{"term":"Chatbot","abbr":null,"category":"AI/ML","definition":"An AI system designed to simulate conversation with users through text or voice. Modern chatbots use large language models for natural and contextual interactions.","related":["Large Language Model","Natural Language Processing","Question Answering"]},{"term":"Recommendation System","abbr":null,"category":"AI/ML","definition":"A machine learning system that predicts user preferences and suggests items they might like. Recommendation systems use collaborative filtering, content-based filtering and hybrid approaches.","related":["Collaborative Filtering","Content-Based Filtering","Matrix Factorization"]},{"term":"Collaborative Filtering","abbr":null,"category":"AI/ML","definition":"A recommendation approach that suggests items based on the preferences of similar users or items. Collaborative filtering works by finding users with similar tastes and their preferences.","related":["Recommendation System","Content-Based Filtering"]},{"term":"Content-Based Filtering","abbr":null,"category":"AI/ML","definition":"A recommendation approach that suggests items similar to those the user has liked before. Content-based filtering analyzes item features to make recommendations.","related":["Recommendation System","Collaborative Filtering"]},{"term":"Time Series Prediction","abbr":null,"category":"AI/ML","definition":"A machine learning task that forecasts future values based on historical time series data. Time series prediction uses RNNs, transformers and statistical methods.","related":["Recurrent Neural Network","LSTM","Forecasting"]},{"term":"Forecasting","abbr":null,"category":"AI/ML","definition":"The prediction of future events or values based on historical data and trends. Forecasting is used in stock prediction, weather, demand planning and more.","related":["Time Series Prediction","Regression"]},{"term":"Regression","abbr":null,"category":"AI/ML","definition":"A supervised learning task that predicts continuous numeric values. Linear regression, polynomial regression and neural network regression are common approaches.","related":["Supervised Learning","Classification","Linear Regression"]},{"term":"Classification","abbr":null,"category":"AI/ML","definition":"A supervised learning task that assigns discrete categories to data points. Classification is used for email spam detection, disease diagnosis and many other applications.","related":["Supervised Learning","Binary Classification","Multi-Class Classification"]},{"term":"Binary Classification","abbr":null,"category":"AI/ML","definition":"A classification task with only two possible output classes. Binary classification is the simplest and most common form of classification.","related":["Classification","Logistic Regression","Binary Classifier"]},{"term":"Multi-Class Classification","abbr":null,"category":"AI/ML","definition":"A classification task with more than two possible output classes. Multi-class classification uses softmax activation and cross-entropy loss.","related":["Classification","Softmax","Multi-Label Classification"]},{"term":"Named Entity Linking","abbr":null,"category":"AI/ML","definition":"An NLP task that links entity mentions in text to entries in a knowledge base. Named entity linking helps disambiguate and ground entities.","related":["Named Entity Recognition","Knowledge Graph","Entity Disambiguation"]},{"term":"Knowledge Graph","abbr":null,"category":"AI/ML","definition":"A structured representation of knowledge as entities and relationships between them. Knowledge graphs enable semantic search, reasoning and question answering.","related":["Named Entity Linking","Semantic Web","Knowledge Base"]},{"term":"Entity Embedding","abbr":null,"category":"AI/ML","definition":"A continuous vector representation of entities learned from data. Entity embeddings enable similarity computation and downstream machine learning tasks.","related":["Embedding","Knowledge Graph","Representation Learning"]},{"term":"Semantic Search","abbr":null,"category":"AI/ML","definition":"A search approach that understands the semantic meaning of queries and documents. Semantic search uses embeddings to find semantically similar content.","related":["Embedding","Information Retrieval","Vector Search"]},{"term":"Information Retrieval","abbr":null,"category":"AI/ML","definition":"The field dealing with the retrieval of relevant documents or information from a collection. Information retrieval is foundational for search engines and recommendation systems.","related":["Semantic Search","Ranking","BM25"]},{"term":"Ranking","abbr":null,"category":"AI/ML","definition":"A machine learning task that orders items by relevance to a query. Learning-to-rank models optimize ranking metrics like NDCG and MAP.","related":["Information Retrieval","Learning-to-Rank"]},{"term":"Learning-to-Rank","abbr":"LTR","category":"AI/ML","definition":"A machine learning approach for optimizing ranking of search results. Learning-to-rank uses pairwise or listwise loss functions to optimize ranking metrics.","related":["Ranking","Information Retrieval"]},{"term":"Bayesian Network","abbr":null,"category":"AI/ML","definition":"A probabilistic graphical model that represents conditional dependencies between random variables. Bayesian networks enable probabilistic inference and causal reasoning.","related":["Probabilistic Model","Graphical Model","Conditional Probability"]},{"term":"Gaussian Mixture Model","abbr":"GMM","category":"AI/ML","definition":"A probabilistic model that represents data as a mixture of Gaussian distributions. GMMs are used for clustering and density estimation.","related":["Probabilistic Model","Clustering","EM Algorithm"]},{"term":"Hidden Markov Model","abbr":"HMM","category":"AI/ML","definition":"A probabilistic model for sequential data where hidden states transition over time and emit observations. HMMs are used for speech recognition and sequence labeling.","related":["Probabilistic Model","Sequence Modeling","Markov Chain"]},{"term":"Markov Chain","abbr":null,"category":"AI/ML","definition":"A stochastic model describing sequences of events where the probability of each event depends only on the previous state. Markov chains are used in text generation and sequence modeling.","related":["Probabilistic Model","Hidden Markov Model"]},{"term":"Probabilistic Model","abbr":null,"category":"AI/ML","definition":"A machine learning model that explicitly models probability distributions over data. Probabilistic models enable uncertainty quantification and principled inference.","related":["Bayesian Network","Gaussian Mixture Model","Hidden Markov Model"]},{"term":"Expectation-Maximization","abbr":"EM","category":"AI/ML","definition":"An iterative algorithm for finding maximum likelihood estimates in models with latent variables. EM is widely used for clustering and learning probabilistic models.","related":["Probabilistic Model","Gaussian Mixture Model","Likelihood"]},{"term":"Model Serving","abbr":null,"category":"AI/ML","definition":"The practice of deploying trained machine learning models to serve predictions in production. Model serving requires managing model versions, inference latency and throughput.","related":["Model Deployment","Inference","API"]},{"term":"Inference","abbr":null,"category":"AI/ML","definition":"The process of using a trained model to make predictions on new data. Inference is typically faster than training as it doesn't require gradient computation.","related":["Model Serving","Prediction","Batch Inference"]},{"term":"Batch Inference","abbr":null,"category":"AI/ML","definition":"Making predictions on multiple data points simultaneously rather than one at a time. Batch inference is more efficient than online inference for throughput-optimized scenarios.","related":["Inference","Real-Time Inference"]},{"term":"Real-Time Inference","abbr":null,"category":"AI/ML","definition":"Making predictions with low latency requirements for individual requests. Real-time inference requires optimized models and efficient serving infrastructure.","related":["Inference","Latency","Model Serving"]},{"term":"Model Drift","abbr":null,"category":"AI/ML","definition":"A phenomenon where model performance degrades over time due to changes in data distribution. Detecting and addressing model drift is crucial for maintaining production ML systems.","related":["Concept Drift","Data Drift","Monitoring"]},{"term":"Data Drift","abbr":null,"category":"AI/ML","definition":"A change in the statistical distribution of input data over time. Data drift causes model performance degradation if not detected and addressed.","related":["Model Drift","Concept Drift"]},{"term":"Concept Drift","abbr":null,"category":"AI/ML","definition":"A change in the relationship between inputs and outputs over time. Concept drift makes historical patterns less relevant for future predictions.","related":["Model Drift","Data Drift"]},{"term":"A/B Testing","abbr":null,"category":"AI/ML","definition":"A statistical experiment comparing two versions of a model or system. A/B testing is essential for validating model improvements in production.","related":["Experimentation","Hypothesis Testing","Statistical Significance"]},{"term":"Canary Deployment","abbr":null,"category":"AI/ML","definition":"A deployment strategy that gradually rolls out a new model to a small percentage of users before full deployment. Canary deployment enables safe testing of model updates.","related":["Model Deployment","Blue-Green Deployment"]},{"term":"Blue-Green Deployment","abbr":null,"category":"AI/ML","definition":"A deployment strategy maintaining two identical production environments where one is active and the other is standby. Blue-green deployment enables instant rollback.","related":["Model Deployment","Canary Deployment"]},{"term":"TensorFlow","abbr":null,"category":"AI/ML","definition":"An open-source machine learning framework developed by Google for building and training neural networks. TensorFlow supports distributed training, deployment and research applications.","related":["Machine Learning Framework","PyTorch","Keras"]},{"term":"PyTorch","abbr":null,"category":"AI/ML","definition":"An open-source machine learning framework developed by Meta with dynamic computation graphs. PyTorch is popular in research for its flexibility and ease of use.","related":["Machine Learning Framework","TensorFlow"]},{"term":"Keras","abbr":null,"category":"AI/ML","definition":"A high-level neural networks API that runs on top of TensorFlow, Theano and CNTK. Keras simplifies model building with a user-friendly interface.","related":["TensorFlow","Machine Learning Framework"]},{"term":"Scikit-learn","abbr":null,"category":"AI/ML","definition":"A Python library for machine learning with simple and efficient tools for data analysis and modeling. Scikit-learn is widely used for classical machine learning tasks.","related":["Machine Learning Framework","Python Libraries"]},{"term":"Hugging Face","abbr":null,"category":"AI/ML","definition":"A platform and library for building, sharing and using pre-trained language and multimodal models. Hugging Face hosts thousands of open-source models.","related":["Natural Language Processing","Model Hub","Transformers Library"]},{"term":"OpenAI","abbr":null,"category":"AI/ML","definition":"A research organization developing and deploying large-scale AI systems. OpenAI created GPT models and operates the popular ChatGPT and API services.","related":["Large Language Model","Artificial Intelligence"]},{"term":"Google DeepMind","abbr":null,"category":"AI/ML","definition":"A research lab combining Google's DeepMind and Brain teams focused on AI research. DeepMind has created AlphaGo, AlphaFold and other breakthrough AI systems.","related":["Artificial Intelligence","Research"]},{"term":"Meta AI","abbr":null,"category":"AI/ML","definition":"Meta's artificial intelligence research organization. Meta AI develops models, tools and infrastructure for machine learning research and applications.","related":["Artificial Intelligence","Research"]},{"term":"XGBoost","abbr":null,"category":"AI/ML","definition":"An open-source gradient boosting framework for regression and classification. XGBoost is highly effective and widely used in machine learning competitions.","related":["Gradient Boosting","Machine Learning"]},{"term":"LightGBM","abbr":null,"category":"AI/ML","definition":"A fast, distributed gradient boosting framework for classification, regression and ranking. LightGBM uses leaf-wise tree growth for improved efficiency.","related":["Gradient Boosting","Machine Learning"]},{"term":"Overfitting","abbr":null,"category":"AI/ML","definition":"A phenomenon where a model learns the training data too well, including noise, resulting in poor generalization. Overfitting is prevented through regularization, early stopping and validation.","related":["Generalization","Underfitting","Regularization"]},{"term":"Underfitting","abbr":null,"category":"AI/ML","definition":"A phenomenon where a model is too simple to capture the underlying patterns in data. Underfitting results in poor performance on both training and test data.","related":["Overfitting","Generalization","Model Complexity"]},{"term":"Generalization","abbr":null,"category":"AI/ML","definition":"The ability of a machine learning model to perform well on unseen data. Good generalization is the ultimate goal of model training.","related":["Overfitting","Test Set","Validation"]},{"term":"Bias-Variance Tradeoff","abbr":null,"category":"AI/ML","definition":"A fundamental concept in machine learning where bias (underfitting) and variance (overfitting) have an inverse relationship. Balancing bias and variance is key to good model performance.","related":["Bias","Variance","Overfitting","Underfitting"]},{"term":"Bias","abbr":null,"category":"AI/ML","definition":"In machine learning, the error from overly simplistic models that underfit. Bias represents systematic errors in model predictions.","related":["Bias-Variance Tradeoff","Variance","Error"]},{"term":"Variance","abbr":null,"category":"AI/ML","definition":"In machine learning, the sensitivity of a model to fluctuations in training data. High variance leads to overfitting where models fit noise in data.","related":["Bias-Variance Tradeoff","Bias","Overfitting"]},{"term":"Activation Function","abbr":null,"category":"AI/ML","definition":"A mathematical function applied to neural network outputs to introduce nonlinearity. Common activation functions include ReLU, Sigmoid and Tanh.","related":["Neural Network","ReLU","Sigmoid"]},{"term":"ReLU","abbr":null,"category":"AI/ML","definition":"Rectified Linear Unit — an activation function that outputs zero for negative inputs and the input value for positive inputs. ReLU is simple, fast and widely used in deep networks.","related":["Activation Function","Neural Network"]},{"term":"Sigmoid","abbr":null,"category":"AI/ML","definition":"An activation function that maps inputs to a value between 0 and 1. Sigmoid is commonly used in the output layer for binary classification.","related":["Activation Function","Logistic Function"]},{"term":"Softmax","abbr":null,"category":"AI/ML","definition":"An activation function that converts a vector of values to a probability distribution. Softmax is used in multi-class classification to produce output probabilities.","related":["Activation Function","Multi-Class Classification","Probability"]},{"term":"Weight Initialization","abbr":null,"category":"AI/ML","definition":"The process of setting initial weights in neural networks before training. Proper weight initialization affects convergence speed and training stability.","related":["Neural Network","Training","Xavier Initialization"]},{"term":"Xavier Initialization","abbr":null,"category":"AI/ML","definition":"A weight initialization scheme that maintains activation and gradient magnitudes across layers. Xavier initialization improves training of deep networks.","related":["Weight Initialization","He Initialization"]},{"term":"Hyperparameter","abbr":null,"category":"AI/ML","definition":"A parameter set before training that controls the learning process. Examples include learning rate, batch size, and network architecture choices.","related":["Hyperparameter Tuning","Learning Rate","Batch Size"]},{"term":"Hyperparameter Tuning","abbr":null,"category":"AI/ML","definition":"The process of finding optimal hyperparameter values to maximize model performance. Hyperparameter tuning uses techniques like grid search and random search.","related":["Hyperparameter","Grid Search","Random Search"]},{"term":"Grid Search","abbr":null,"category":"AI/ML","definition":"A hyperparameter optimization technique that exhaustively searches over a specified parameter grid. Grid search is simple but computationally expensive for large search spaces.","related":["Hyperparameter Tuning","Random Search"]},{"term":"Random Search","abbr":null,"category":"AI/ML","definition":"A hyperparameter optimization technique that samples randomly from hyperparameter distributions. Random search is more efficient than grid search for high-dimensional spaces.","related":["Hyperparameter Tuning","Grid Search"]},{"term":"Batch Size","abbr":null,"category":"AI/ML","definition":"The number of samples processed before updating model parameters during training. Batch size affects memory usage, convergence speed and generalization.","related":["Hyperparameter","Training","Mini-Batch"]},{"term":"Epoch","abbr":null,"category":"AI/ML","definition":"One complete pass through the training dataset during model training. Models typically require multiple epochs to converge.","related":["Training","Iteration","Convergence"]},{"term":"Iteration","abbr":null,"category":"AI/ML","definition":"A single update of model parameters based on a mini-batch of training data. Multiple iterations occur within each epoch.","related":["Epoch","Training","Mini-Batch"]},{"term":"Logistic Regression","abbr":null,"category":"AI/ML","definition":"A linear classification algorithm that models the probability of binary outcomes using the logistic function. Despite its name, logistic regression is a classification method, not regression.","related":["Classification","Linear Model","Sigmoid"]},{"term":"Decision Tree","abbr":null,"category":"AI/ML","definition":"A tree-based model that makes predictions by learning a series of if-then-else decision rules. Decision trees are interpretable and form the basis for ensemble methods like random forests.","related":["Random Forest","Classification","Regression"]},{"term":"Random Forest","abbr":null,"category":"AI/ML","definition":"An ensemble method that combines multiple decision trees trained on random subsets of data. Random forests reduce overfitting and improve generalization.","related":["Decision Tree","Ensemble Learning","Bagging"]},{"term":"Gradient Boosting","abbr":null,"category":"AI/ML","definition":"An ensemble method that sequentially builds trees, each correcting errors made by previous trees. Gradient boosting achieves state-of-the-art performance on many tabular datasets.","related":["Ensemble Learning","XGBoost","Decision Tree"]},{"term":"Ensemble Learning","abbr":null,"category":"AI/ML","definition":"A machine learning approach that combines multiple models to make better predictions. Ensemble methods typically outperform individual models.","related":["Random Forest","Gradient Boosting","Bagging","Boosting"]},{"term":"Bagging","abbr":null,"category":"AI/ML","definition":"Bootstrap Aggregating — an ensemble method that trains models on random samples with replacement. Bagging reduces variance and enables parallel training.","related":["Ensemble Learning","Bootstrap","Random Forest"]},{"term":"Boosting","abbr":null,"category":"AI/ML","definition":"An ensemble method that sequentially trains models, giving more weight to misclassified examples. Boosting reduces both bias and variance.","related":["Ensemble Learning","AdaBoost","Gradient Boosting"]},{"term":"AdaBoost","abbr":null,"category":"AI/ML","definition":"Adaptive Boosting — an ensemble method that adjusts sample weights to focus on hard-to-classify examples. AdaBoost often achieves better generalization than individual classifiers.","related":["Boosting","Ensemble Learning"]},{"term":"Support Vector Machine","abbr":"SVM","category":"AI/ML","definition":"A discriminative classifier that finds the hyperplane maximizing the margin between classes. SVMs work well for binary classification and can handle non-linear problems with kernel tricks.","related":["Classification","Kernel Method","Hyperplane"]},{"term":"Kernel Method","abbr":null,"category":"AI/ML","definition":"A technique that implicitly maps data to higher-dimensional spaces without explicit computation. Kernel methods enable non-linear learning in algorithms like SVMs.","related":["Support Vector Machine","Kernel Trick","Non-Linear Learning"]},{"term":"Kernel Trick","abbr":null,"category":"AI/ML","definition":"A mathematical technique that enables efficient computation in high-dimensional spaces by computing dot products in the original space. The kernel trick is foundational for many non-linear algorithms.","related":["Kernel Method","Support Vector Machine"]},{"term":"Hyperplane","abbr":null,"category":"AI/ML","definition":"A subspace with dimension one less than the ambient space that divides space into two half-spaces. Hyperplanes are used as decision boundaries in linear classifiers.","related":["Support Vector Machine","Classification"]},{"term":"Margin","abbr":null,"category":"AI/ML","definition":"The distance from the decision boundary to the nearest training examples. Maximizing the margin improves model robustness and generalization.","related":["Support Vector Machine","Classification"]},{"term":"Naive Bayes","abbr":null,"category":"AI/ML","definition":"A probabilistic classifier based on Bayes' theorem that assumes feature independence. Despite the naive assumption, Naive Bayes often works well for text and spam classification.","related":["Probabilistic Model","Classification","Bayes' Theorem"]},{"term":"Bayes' Theorem","abbr":null,"category":"AI/ML","definition":"A mathematical formula describing how to update probabilities given new evidence. Bayes' theorem is fundamental to probabilistic reasoning and Bayesian statistics.","related":["Probabilistic Model","Naive Bayes","Conditional Probability"]},{"term":"Conditional Probability","abbr":null,"category":"AI/ML","definition":"The probability of an event given that another event has occurred. Conditional probability is denoted as P(A|B) and is fundamental to probabilistic modeling.","related":["Probability","Bayes' Theorem"]},{"term":"Maximum Likelihood Estimation","abbr":"MLE","category":"AI/ML","definition":"A statistical method for estimating model parameters by finding values that maximize the likelihood of observed data. MLE is widely used in machine learning.","related":["Likelihood","Parameter Estimation","Probabilistic Model"]},{"term":"Likelihood","abbr":null,"category":"AI/ML","definition":"The probability of observing data given a particular set of model parameters. Likelihood is used to optimize model parameters.","related":["Maximum Likelihood Estimation","Probability"]},{"term":"Posterior Distribution","abbr":null,"category":"AI/ML","definition":"In Bayesian statistics, the probability distribution of parameters given observed data. The posterior combines prior beliefs with evidence from data.","related":["Bayesian Inference","Prior Distribution","Bayes' Theorem"]},{"term":"Prior Distribution","abbr":null,"category":"AI/ML","definition":"In Bayesian statistics, the probability distribution representing beliefs about parameters before observing data. The prior is updated with data to obtain the posterior.","related":["Bayesian Inference","Posterior Distribution"]},{"term":"Bayesian Inference","abbr":null,"category":"AI/ML","definition":"A statistical method for updating beliefs about parameters as new evidence arrives. Bayesian inference uses prior distributions, likelihood and Bayes' theorem.","related":["Bayes' Theorem","Posterior Distribution","Prior Distribution"]},{"term":"Monte Carlo Method","abbr":null,"category":"AI/ML","definition":"A computational technique using random sampling to approximate solutions to mathematical problems. Monte Carlo methods are used for inference in probabilistic models.","related":["MCMC","Sampling","Stochastic"]},{"term":"Markov Chain Monte Carlo","abbr":"MCMC","category":"AI/ML","definition":"A sampling technique that uses Markov chains to draw samples from complex probability distributions. MCMC is widely used for Bayesian inference.","related":["Monte Carlo Method","Markov Chain","Bayesian Inference"]},{"term":"Isolation Forest","abbr":null,"category":"AI/ML","definition":"An anomaly detection algorithm that isolates anomalies by randomly selecting features and split values. Isolation Forest is effective and efficient for high-dimensional data.","related":["Anomaly Detection","Outlier Detection"]},{"term":"Local Outlier Factor","abbr":"LOF","category":"AI/ML","definition":"An anomaly detection algorithm that identifies outliers by comparing local density of points. LOF works well for multimodal distributions.","related":["Anomaly Detection","Density-Based Clustering"]},{"term":"One-Class SVM","abbr":null,"category":"AI/ML","definition":"A variant of support vector machines for unsupervised anomaly detection. One-class SVM finds the smallest hypersphere containing most training data.","related":["Anomaly Detection","Support Vector Machine"]},{"term":"Isolation Forest Anomaly Detection","abbr":null,"category":"AI/ML","definition":"An unsupervised anomaly detection approach using isolation forests that partition data randomly. The algorithm assumes anomalies are isolated and easier to separate.","related":["Anomaly Detection","Isolation Forest"]},{"term":"Matrix Factorization","abbr":null,"category":"AI/ML","definition":"A technique for decomposing matrices into products of smaller matrices. Matrix factorization is used in recommendation systems and dimensionality reduction.","related":["Dimensionality Reduction","Recommendation System","Singular Value Decomposition"]},{"term":"Singular Value Decomposition","abbr":"SVD","category":"AI/ML","definition":"A matrix factorization technique that decomposes matrices into orthogonal matrices and singular values. SVD is used for dimensionality reduction and noise removal.","related":["Matrix Factorization","Linear Algebra"]},{"term":"Non-Negative Matrix Factorization","abbr":"NMF","category":"AI/ML","definition":"A matrix factorization technique where factors are constrained to be non-negative. NMF is useful for interpretable dimensionality reduction and topic modeling.","related":["Matrix Factorization","Topic Modeling"]},{"term":"Topic Modeling","abbr":null,"category":"AI/ML","definition":"An unsupervised learning technique that discovers abstract topics in documents. Latent Dirichlet Allocation (LDA) is a popular topic modeling approach.","related":["Unsupervised Learning","LDA","Document Analysis"]},{"term":"Latent Dirichlet Allocation","abbr":"LDA","category":"AI/ML","definition":"A probabilistic model for topic modeling that represents documents as mixtures of topics. LDA is widely used for understanding document collections.","related":["Topic Modeling","Probabilistic Model"]},{"term":"Document Similarity","abbr":null,"category":"AI/ML","definition":"A measure of how similar two documents are based on their content. Document similarity is computed using embeddings, TF-IDF or other representation methods.","related":["Semantic Similarity","Text Representation"]},{"term":"TF-IDF","abbr":null,"category":"AI/ML","definition":"Term Frequency-Inverse Document Frequency — a numerical statistic that reflects how important a word is to a document in a collection. TF-IDF is used for text representation and ranking.","related":["Text Representation","Information Retrieval"]},{"term":"Cosine Similarity","abbr":null,"category":"AI/ML","definition":"A similarity measure that computes the cosine of the angle between two vectors. Cosine similarity is widely used for comparing document embeddings and text vectors.","related":["Semantic Similarity","Vector Space","Distance Metric"]},{"term":"Euclidean Distance","abbr":null,"category":"AI/ML","definition":"A distance metric computing the straight-line distance between two points. Euclidean distance is commonly used in clustering and nearest-neighbor algorithms.","related":["Distance Metric","Similarity","K-Means"]},{"term":"Manhattan Distance","abbr":null,"category":"AI/ML","definition":"A distance metric computing the sum of absolute differences (L1 norm). Manhattan distance is useful when movement is restricted to grid-like structures.","related":["Distance Metric","Euclidean Distance"]},{"term":"Distance Metric","abbr":null,"category":"AI/ML","definition":"A mathematical function measuring the distance between data points. Choice of distance metric affects clustering, classification and similarity computation.","related":["Euclidean Distance","Manhattan Distance","Cosine Similarity"]},{"term":"Semantic Similarity","abbr":null,"category":"AI/ML","definition":"A measure of how similar the meanings of two text snippets are. Semantic similarity is computed using embeddings and word vector representations.","related":["Embedding","Document Similarity","Cosine Similarity"]},{"term":"Siamese Network","abbr":null,"category":"AI/ML","definition":"A neural network architecture with two or more identical subnetworks used to compare inputs. Siamese networks are effective for similarity learning and face recognition.","related":["Metric Learning","Contrastive Learning"]},{"term":"Metric Learning","abbr":null,"category":"AI/ML","definition":"A machine learning approach that learns distance metrics to improve similarity computation. Metric learning is used for face recognition and person re-identification.","related":["Siamese Network","Contrastive Learning","Distance Metric"]},{"term":"Person Re-identification","abbr":"Re-ID","category":"AI/ML","definition":"A computer vision task that identifies the same person across multiple camera views. Re-ID uses metric learning and appearance features.","related":["Computer Vision","Metric Learning","Face Recognition"]},{"term":"Cross-Modal Retrieval","abbr":null,"category":"AI/ML","definition":"A retrieval task that finds items in one modality (e.g., images) given queries in another modality (e.g., text). Cross-modal retrieval uses multimodal embeddings.","related":["Multimodal Learning","Information Retrieval","Embedding"]},{"term":"Image Captioning","abbr":null,"category":"AI/ML","definition":"A task that generates natural language descriptions of images. Image captioning combines computer vision and natural language generation.","related":["Computer Vision","Natural Language Processing","Sequence-to-Sequence"]},{"term":"Visual Question Answering","abbr":"VQA","category":"AI/ML","definition":"A task that answers questions about images using computer vision and natural language understanding. VQA combines vision and language for complex reasoning.","related":["Multimodal Learning","Question Answering","Computer Vision"]},{"term":"Action Recognition","abbr":null,"category":"AI/ML","definition":"A computer vision task that identifies human actions in videos. Action recognition uses 3D CNNs and temporal convolutions.","related":["Computer Vision","Temporal Modeling","Video Analysis"]},{"term":"Temporal Modeling","abbr":null,"category":"AI/ML","definition":"A technique for capturing temporal dynamics and dependencies in sequential or video data. Temporal modeling is crucial for action recognition and video understanding.","related":["Recurrent Neural Network","3D Convolution","Action Recognition"]},{"term":"3D Convolution","abbr":"3D CNN","category":"AI/ML","definition":"A convolution operation that extends 2D convolutions to three dimensions (height, width, time). 3D CNNs are used for video analysis and volumetric data.","related":["Convolutional Neural Network","Temporal Modeling","Video Analysis"]},{"term":"Optical Flow","abbr":null,"category":"AI/ML","definition":"A technique that estimates pixel motion between consecutive video frames. Optical flow is used for action recognition, video compression and motion analysis.","related":["Computer Vision","Motion Estimation","Video Analysis"]},{"term":"Video Analysis","abbr":null,"category":"AI/ML","definition":"The application of computer vision techniques to understand and extract information from video sequences. Video analysis includes action recognition, tracking and summarization.","related":["Computer Vision","Action Recognition","Temporal Modeling"]},{"term":"Object Tracking","abbr":null,"category":"AI/ML","definition":"A computer vision task that follows objects across video frames. Object tracking is used in surveillance, robotics and video analysis.","related":["Computer Vision","Video Analysis","Object Detection"]},{"term":"Scene Understanding","abbr":null,"category":"AI/ML","definition":"The task of comprehensively understanding visual scenes including objects, relationships and contexts. Scene understanding requires multiple computer vision tasks.","related":["Computer Vision","Object Detection","Semantic Segmentation"]},{"term":"3D Reconstruction","abbr":null,"category":"AI/ML","definition":"A computer vision task that builds 3D models from 2D images or point clouds. 3D reconstruction is used in robotics, augmented reality and autonomous systems.","related":["Computer Vision","Depth Estimation","Point Cloud"]},{"term":"Point Cloud","abbr":null,"category":"AI/ML","definition":"A set of 3D points in space representing the geometry of a scene or object. Point clouds are acquired by depth sensors and used in 3D vision tasks.","related":["3D Reconstruction","Depth Estimation","3D Detection"]},{"term":"3D Object Detection","abbr":null,"category":"AI/ML","definition":"A computer vision task that detects and localizes objects in 3D space from images or point clouds. 3D object detection is crucial for autonomous driving.","related":["Object Detection","Point Cloud","3D Reconstruction"]},{"term":"Autonomous Driving","abbr":null,"category":"AI/ML","definition":"A computer vision and AI application enabling vehicles to perceive, navigate and control themselves without human input. Autonomous driving uses multiple computer vision and sensor fusion techniques.","related":["Computer Vision","Sensor Fusion","Object Detection"]},{"term":"Sensor Fusion","abbr":null,"category":"AI/ML","definition":"A technique that combines data from multiple sensors to create a more accurate and robust representation. Sensor fusion is critical for autonomous systems.","related":["Autonomous Driving","Data Integration"]},{"term":"Robotics","abbr":null,"category":"AI/ML","definition":"A field combining mechanical engineering and AI to build systems that perceive and interact with the environment. Robotics uses computer vision, control theory and machine learning.","related":["Computer Vision","Control Theory","Sensor Fusion"]},{"term":"Reinforcement Learning Agent","abbr":null,"category":"AI/ML","definition":"An entity that learns to take actions in an environment to maximize cumulative rewards. Reinforcement learning agents are used in robotics, games and autonomous systems.","related":["Reinforcement Learning","Robotics","Policy"]},{"term":"Policy","abbr":null,"category":"AI/ML","definition":"In reinforcement learning, a function that maps states to actions, determining agent behavior. Policies can be deterministic or stochastic.","related":["Reinforcement Learning","Policy Gradient","Value Function"]},{"term":"Value Function","abbr":null,"category":"AI/ML","definition":"In reinforcement learning, a function that estimates the expected future reward for a state or state-action pair. Value functions guide decision-making.","related":["Reinforcement Learning","Q-Learning","Policy Gradient"]},{"term":"Q-Learning","abbr":null,"category":"AI/ML","definition":"A reinforcement learning algorithm that learns an optimal action-value function (Q-function) through interactions with the environment. Q-learning is model-free and off-policy.","related":["Reinforcement Learning","Value Function","Temporal Difference Learning"]},{"term":"Policy Gradient","abbr":null,"category":"AI/ML","definition":"A reinforcement learning algorithm that directly optimizes the policy by following the gradient of expected rewards. Policy gradient methods include REINFORCE and Actor-Critic.","related":["Reinforcement Learning","Policy","Gradient"]},{"term":"Actor-Critic","abbr":null,"category":"AI/ML","definition":"A reinforcement learning algorithm combining policy gradient (actor) and value function (critic) methods. Actor-critic methods achieve better stability and sample efficiency.","related":["Reinforcement Learning","Policy Gradient","Value Function"]},{"term":"Temporal Difference Learning","abbr":"TD Learning","category":"AI/ML","definition":"A reinforcement learning approach that combines Monte Carlo and dynamic programming. TD learning updates value estimates based on other estimates.","related":["Reinforcement Learning","Q-Learning","Value Function"]},{"term":"Reward Shaping","abbr":null,"category":"AI/ML","definition":"A technique that modifies the reward signal in reinforcement learning to guide agent learning. Well-designed reward shaping accelerates learning.","related":["Reinforcement Learning","Reward"]},{"term":"Exploration-Exploitation Tradeoff","abbr":null,"category":"AI/ML","definition":"A fundamental problem in reinforcement learning: deciding whether to explore new actions or exploit known good actions. Epsilon-greedy and UCB are common strategies.","related":["Reinforcement Learning","Epsilon-Greedy","Bandit Problem"]},{"term":"Epsilon-Greedy","abbr":null,"category":"AI/ML","definition":"An exploration strategy that with probability epsilon chooses a random action and otherwise exploits the best known action. Epsilon-greedy balances exploration and exploitation.","related":["Exploration-Exploitation Tradeoff","Reinforcement Learning"]},{"term":"Bandit Problem","abbr":null,"category":"AI/ML","definition":"A reinforcement learning problem with a single state and multiple actions with unknown rewards. Bandit algorithms are foundational for contextual decision-making.","related":["Reinforcement Learning","Exploration-Exploitation Tradeoff"]},{"term":"Reward","abbr":null,"category":"AI/ML","definition":"A numerical signal indicating the immediate value of an action or state in reinforcement learning. Rewards guide agent learning toward desired behavior.","related":["Reinforcement Learning","Policy","Value Function"]},{"term":"Neural Architecture Search","abbr":"NAS","category":"AI/ML","definition":"An automated machine learning technique that searches for optimal neural network architectures. NAS reduces manual architecture design and discovers novel architectures.","related":["Hyperparameter Tuning","AutoML","Architecture Design"]},{"term":"AutoML","abbr":null,"category":"AI/ML","definition":"Automated Machine Learning — a field that automates the process of selecting algorithms, hyperparameters and data preprocessing. AutoML makes machine learning accessible to non-experts.","related":["Neural Architecture Search","Hyperparameter Tuning"]},{"term":"Bayesian Optimization","abbr":null,"category":"AI/ML","definition":"A hyperparameter optimization technique using Bayesian inference to model the objective function. Bayesian optimization is sample-efficient and discovers good hyperparameters with few evaluations.","related":["Hyperparameter Tuning","Gaussian Process"]},{"term":"Gaussian Process","abbr":null,"category":"AI/ML","definition":"A probabilistic model that places distributions over functions, useful for regression and optimization. Gaussian processes quantify uncertainty in predictions.","related":["Probabilistic Model","Bayesian Optimization","Regression"]},{"term":"Evolutionary Algorithm","abbr":null,"category":"AI/ML","definition":"A metaheuristic optimization technique inspired by biological evolution using selection, mutation and crossover. Evolutionary algorithms explore large search spaces without gradients.","related":["Genetic Algorithm","Optimization","Population-Based Training"]},{"term":"Genetic Algorithm","abbr":null,"category":"AI/ML","definition":"An evolutionary algorithm that evolves solutions through natural selection and genetic operators. Genetic algorithms are effective for combinatorial optimization problems.","related":["Evolutionary Algorithm","Population-Based Training"]},{"term":"Population-Based Training","abbr":"PBT","category":"AI/ML","definition":"A training approach inspired by population-based evolutionary methods that trains populations of neural networks. PBT enables efficient hyperparameter adaptation during training.","related":["Evolutionary Algorithm","Hyperparameter Tuning"]},{"term":"MobileViT","abbr":null,"category":"AI/ML","definition":"Mobile Vision Transformer — a lightweight vision transformer designed for mobile devices. MobileViT combines CNNs and transformers for efficient inference.","related":["Vision Transformer","MobileNet","Efficient Architecture"]},{"term":"DenseNet","abbr":null,"category":"AI/ML","definition":"Densely Connected Network — a CNN architecture where each layer receives input from all previous layers. Dense connections improve gradient flow and reduce parameters.","related":["Convolutional Neural Network","ResNet"]},{"term":"Inception Network","abbr":null,"category":"AI/ML","definition":"A deep CNN architecture with parallel convolutional branches of different filter sizes. Inception modules capture multi-scale features efficiently.","related":["Convolutional Neural Network","GoogLeNet"]},{"term":"GoogLeNet","abbr":null,"category":"AI/ML","definition":"A deep CNN architecture that introduced the Inception module for efficient multi-scale feature extraction. GoogLeNet achieved state-of-the-art results on ImageNet.","related":["Inception Network","Convolutional Neural Network"]},{"term":"SqueezeNet","abbr":null,"category":"AI/ML","definition":"A lightweight CNN that achieves AlexNet-level accuracy with 50x fewer parameters. SqueezeNet uses Fire modules for parameter efficiency.","related":["Model Compression","MobileNet","Efficient Architecture"]},{"term":"ShuffleNet","abbr":null,"category":"AI/ML","definition":"An efficient CNN architecture that uses channel shuffle to reduce computation while maintaining accuracy. ShuffleNet is designed for mobile devices.","related":["MobileNet","Model Compression","Efficient Architecture"]},{"term":"Neural ODE","abbr":null,"category":"AI/ML","definition":"A neural network that models continuous dynamics using ODEs. Neural ODEs have constant memory cost and enable flexible computation.","related":["Deep Learning","Differential Equations"]},{"term":"Graph Neural Network","abbr":"GNN","category":"AI/ML","definition":"A neural network designed to process graph-structured data with nodes and edges. GNNs enable learning on molecules, social networks and knowledge graphs.","related":["Deep Learning","Graph Convolutional Network","Message Passing"]},{"term":"Graph Convolutional Network","abbr":"GCN","category":"AI/ML","definition":"A graph neural network that extends CNNs to graph data by aggregating node features from neighbors. GCNs are effective for semi-supervised learning on graphs.","related":["Graph Neural Network","Convolution"]},{"term":"Graph Attention Network","abbr":"GAT","category":"AI/ML","definition":"A graph neural network using attention mechanisms to weight node neighbors. GAT enables adaptive feature aggregation on graphs.","related":["Graph Neural Network","Attention Mechanism"]},{"term":"Message Passing","abbr":null,"category":"AI/ML","definition":"A framework for graph neural networks where nodes update their representations by exchanging messages with neighbors. Message passing is foundational for GNNs.","related":["Graph Neural Network","Graph Convolution"]},{"term":"Knowledge Graph Embedding","abbr":null,"category":"AI/ML","definition":"A technique that learns continuous vector representations of entities and relations in knowledge graphs. Embeddings enable knowledge graph completion and reasoning.","related":["Knowledge Graph","Embedding","Entity Embedding"]},{"term":"Mixture of Experts","abbr":"MoE","category":"AI/ML","definition":"A neural network ensemble approach where multiple expert networks specialize on different inputs and a gating network routes inputs. MoE enables efficient scaling.","related":["Ensemble Learning","Neural Network","Sparse Models"]},{"term":"Sparse Model","abbr":null,"category":"AI/ML","definition":"A neural network where only a small fraction of parameters are active for each input. Sparse models reduce computation and enable efficient scaling.","related":["Mixture of Experts","Pruning"]},{"term":"Capsule Network","abbr":null,"category":"AI/ML","definition":"A neural network architecture using capsules (groups of neurons) to represent entities. Capsule networks capture pose and deformation variations.","related":["Convolutional Neural Network","Neural Network"]},{"term":"Linear Attention","abbr":null,"category":"AI/ML","definition":"An attention variant with linear complexity replacing the quadratic softmax attention. Linear attention enables efficient long sequence processing.","related":["Attention Mechanism","Transformer","Computational Efficiency"]},{"term":"Flash Attention","abbr":null,"category":"AI/ML","definition":"An optimized attention implementation that reduces memory access and improves GPU utilization. Flash Attention enables faster and more memory-efficient transformers.","related":["Attention Mechanism","Computational Efficiency"]},{"term":"Cross-Attention","abbr":null,"category":"AI/ML","definition":"An attention mechanism where queries come from one sequence and keys/values from another. Cross-attention enables multimodal interaction in models.","related":["Attention Mechanism","Transformer","Multimodal Learning"]},{"term":"Rotary Embeddings","abbr":"RoPE","category":"AI/ML","definition":"A positional encoding method using rotation matrices for transformers. Rotary embeddings improve extrapolation and generalization.","related":["Positional Encoding","Transformer"]},{"term":"Alibi Attention","abbr":null,"category":"AI/ML","definition":"A positional encoding approach using relative position biases in attention. ALiBi improves length extrapolation without explicit position embeddings.","related":["Positional Encoding","Attention Mechanism"]},{"term":"Sparse Attention","abbr":null,"category":"AI/ML","definition":"An attention pattern that connects only a sparse subset of positions rather than all positions. Sparse attention reduces computation for long sequences.","related":["Attention Mechanism","Computational Efficiency"]},{"term":"Local Attention","abbr":null,"category":"AI/ML","definition":"An attention pattern where each position only attends to nearby positions. Local attention is efficient for long sequences.","related":["Attention Mechanism","Sparse Attention"]},{"term":"Longformer","abbr":null,"category":"AI/ML","definition":"A transformer variant with local windowed attention and task-specific attention patterns. Longformer efficiently handles long documents.","related":["Transformer","Local Attention","Language Model"]},{"term":"Big Bird","abbr":null,"category":"AI/ML","definition":"A sparse attention transformer that enables efficient processing of long sequences. Big Bird combines block-local, random and global attention patterns.","related":["Transformer","Sparse Attention","Language Model"]},{"term":"Performer","abbr":null,"category":"AI/ML","definition":"A transformer variant using kernel methods to approximate attention with linear complexity. Performers enable efficient attention for long sequences.","related":["Transformer","Attention Mechanism","Kernel Methods"]},{"term":"Linformer","abbr":null,"category":"AI/ML","definition":"A linear complexity transformer using low-rank approximations of attention. Linformer scales quadratically in sequence length while maintaining performance.","related":["Transformer","Linear Attention"]},{"term":"Efficient Transformer","abbr":null,"category":"AI/ML","definition":"A class of transformers designed to reduce computational and memory complexity. Efficient transformers enable processing of longer sequences.","related":["Transformer","Computational Efficiency","Linear Attention"]},{"term":"Prefix Tuning","abbr":null,"category":"AI/ML","definition":"A parameter-efficient fine-tuning method that prepends learnable prefix tokens to input sequences. Prefix tuning avoids catastrophic forgetting.","related":["Fine-Tuning","Transfer Learning","Prompt-Based Learning"]},{"term":"Adapter Modules","abbr":null,"category":"AI/ML","definition":"Small trainable modules inserted into pre-trained models for task-specific adaptation. Adapters enable efficient multi-task learning.","related":["Fine-Tuning","Transfer Learning","Parameter Efficiency"]},{"term":"LoRA","abbr":null,"category":"AI/ML","definition":"Low-Rank Adaptation — a parameter-efficient fine-tuning method using low-rank weight updates. LoRA significantly reduces trainable parameters.","related":["Fine-Tuning","Parameter Efficiency","Transfer Learning"]},{"term":"QLoRA","abbr":null,"category":"AI/ML","definition":"Quantized LoRA — combines quantization with LoRA for extremely efficient fine-tuning on consumer GPUs. QLoRA enables 7B parameter models on a single GPU.","related":["LoRA","Quantization","Fine-Tuning"]},{"term":"Fine-Tuning","abbr":null,"category":"AI/ML","definition":"Adapting a pre-trained model to a downstream task by training on task-specific data. Fine-tuning is sample-efficient and leverages pre-trained knowledge.","related":["Transfer Learning","Pre-trained Model","Supervised Learning"]},{"term":"Pre-trained Model","abbr":null,"category":"AI/ML","definition":"A model trained on large-scale data that serves as a starting point for downstream tasks. Pre-trained models enable transfer learning and reduce data requirements.","related":["Transfer Learning","Fine-Tuning","Foundation Model"]},{"term":"Foundation Model","abbr":null,"category":"AI/ML","definition":"A large-scale model trained on broad data that can be adapted to many downstream tasks. Foundation models exhibit emergent capabilities across domains.","related":["Large Language Model","Pre-trained Model","Transfer Learning"]},{"term":"Prompt Template","abbr":null,"category":"AI/ML","definition":"A structured format for prompts with placeholders for variable inputs. Prompt templates enable consistent and reusable prompting.","related":["Prompt Engineering","Few-Shot Learning"]},{"term":"Instruction Tuning","abbr":null,"category":"AI/ML","definition":"A fine-tuning approach that trains models to follow natural language instructions. Instruction-tuned models exhibit strong generalization to new tasks.","related":["Fine-Tuning","Language Model","Supervised Learning"]},{"term":"Reinforcement Learning from Human Feedback","abbr":"RLHF","category":"AI/ML","definition":"A technique combining reinforcement learning with human preferences to align language models with human values. RLHF improves model safety and quality.","related":["Reinforcement Learning","Language Model","Human Feedback"]},{"term":"Constitutional AI","abbr":"CAI","category":"AI/ML","definition":"An approach that uses a set of principles (constitution) to guide model behavior during training. Constitutional AI reduces need for human feedback.","related":["RLHF","Language Model","Alignment"]},{"term":"Model Alignment","abbr":null,"category":"AI/ML","definition":"The process of ensuring AI models behave in accordance with human values and intentions. Alignment is critical for safe and beneficial AI.","related":["RLHF","Constitutional AI","Safety"]},{"term":"Memorization","abbr":null,"category":"AI/ML","definition":"A phenomenon where models learn training data exactly rather than generalizing. Memorization is problematic for privacy and generalization.","related":["Overfitting","Generalization","Differential Privacy"]},{"term":"Hallucination","abbr":null,"category":"AI/ML","definition":"A phenomenon where language models generate plausible but false information. Hallucination is a major challenge for reliable language models.","related":["Language Model","Factuality","Grounding"]},{"term":"Retrieval Augmented Generation","abbr":"RAG","category":"AI/ML","definition":"A technique that augments language models with retrieved relevant documents. RAG reduces hallucinations and improves factuality.","related":["Language Model","Information Retrieval","Question Answering"]},{"term":"Semantic Scholar","abbr":null,"category":"AI/ML","definition":"An AI-powered research tool for discovering scientific papers. Semantic Scholar uses embeddings for semantic search.","related":["Information Retrieval","Semantic Search"]},{"term":"Grounding","abbr":null,"category":"AI/ML","definition":"Connecting language model outputs to external knowledge and reality. Grounding improves factuality and reliability of language models.","related":["Retrieval Augmented Generation","Knowledge Integration"]},{"term":"Fact Verification","abbr":null,"category":"AI/ML","definition":"A task that verifies whether factual claims are true. Fact verification uses evidence retrieval and reasoning.","related":["Natural Language Processing","Information Retrieval"]},{"term":"Paraphrase Generation","abbr":null,"category":"AI/ML","definition":"An NLP task that generates alternative expressions of the same meaning. Paraphrasing is useful for data augmentation and diversity.","related":["Natural Language Processing","Text Generation"]},{"term":"Controlled Text Generation","abbr":null,"category":"AI/ML","definition":"A technique for generating text with specific attributes or properties. Controlled generation enables customization of model outputs.","related":["Text Generation","Language Model"]},{"term":"Prompt-Based Learning","abbr":null,"category":"AI/ML","definition":"A learning paradigm where tasks are reformulated as prompting language models. Prompt-based learning enables few-shot adaptation.","related":["Prompt Engineering","Few-Shot Learning","Language Model"]},{"term":"Cloze Task","abbr":null,"category":"AI/ML","definition":"A task where models fill in masked tokens in a sequence. Cloze tasks are used for pre-training language models.","related":["Language Model","Masked Language Modeling"]},{"term":"Masked Language Modeling","abbr":"MLM","category":"AI/ML","definition":"A pre-training objective where models predict masked tokens based on context. MLM is the foundation for BERT and other models.","related":["Pre-training","Language Model","BERT"]},{"term":"Next Sentence Prediction","abbr":"NSP","category":"AI/ML","definition":"A pre-training objective where models predict whether sentences are consecutive. NSP helps models understand discourse structure.","related":["Pre-training","Language Model","BERT"]},{"term":"Causal Language Modeling","abbr":null,"category":"AI/ML","definition":"A pre-training objective where models predict the next token given previous context. Causal modeling is foundational for autoregressive language models.","related":["Language Model","Autoregressive Model","GPT"]},{"term":"Autoregressive Model","abbr":null,"category":"AI/ML","definition":"A generative model that predicts each token conditioned on previously generated tokens. Autoregressive models are used for text generation.","related":["Language Model","Sequence Generation","GPT"]},{"term":"Denoising Autoencoder","abbr":null,"category":"AI/ML","definition":"An autoencoder trained to reconstruct inputs from corrupted versions. Denoising autoencoders learn robust representations.","related":["Autoencoder","Self-Supervised Learning"]},{"term":"Variational Inference","abbr":null,"category":"AI/ML","definition":"A method for approximate Bayesian inference using variational distributions. Variational inference enables efficient learning of complex models.","related":["Bayesian Inference","Variational Autoencoder"]},{"term":"DALL-E","abbr":null,"category":"AI/ML","definition":"A text-to-image generation model from OpenAI using contrastive learning. DALL-E generates diverse and creative images from text descriptions.","related":["Text-to-Image Generation","Vision-Language Model","Diffusion Model"]},{"term":"Text-to-Image Generation","abbr":null,"category":"AI/ML","definition":"A task that generates images from text descriptions using deep learning. Text-to-image models combine vision and language understanding.","related":["Image Generation","Vision-Language Model"]},{"term":"Image-to-Text Generation","abbr":null,"category":"AI/ML","definition":"A task that generates text descriptions from images. Image-to-text includes image captioning and visual question answering.","related":["Image Captioning","Vision-Language Model"]},{"term":"Cross-Lingual Model","abbr":null,"category":"AI/ML","definition":"A language model trained on multiple languages enabling cross-lingual transfer. Cross-lingual models support multilingual applications.","related":["Language Model","Transfer Learning","Multilingual NLP"]},{"term":"Code Model","abbr":null,"category":"AI/ML","definition":"A language model trained on source code for code generation and understanding. Code models enable AI-assisted programming.","related":["Language Model","Code Generation"]},{"term":"Code Generation","abbr":null,"category":"AI/ML","definition":"Automatically generating source code from specifications or prompts. Code generation models assist developers in writing code.","related":["Code Model","Program Synthesis"]},{"term":"Program Synthesis","abbr":null,"category":"AI/ML","definition":"Automatically generating programs from specifications or examples. Program synthesis uses neural and symbolic methods.","related":["Code Generation","Language Model"]},{"term":"Spiking Neural Network","abbr":"SNN","category":"AI/ML","definition":"A neural network model mimicking biological neurons that communicate via spikes. Spiking networks are energy-efficient and suitable for neuromorphic hardware.","related":["Neural Network","Biologically-Inspired AI","Neuromorphic Computing"]},{"term":"Neuromorphic Computing","abbr":null,"category":"AI/ML","definition":"Computing architecture inspired by biological neural systems. Neuromorphic systems are energy-efficient and suitable for edge AI.","related":["Spiking Neural Network","Brain-Inspired AI"]},{"term":"Biologically-Inspired AI","abbr":null,"category":"AI/ML","definition":"AI systems designed to mimic aspects of biological intelligence. Bio-inspired approaches include genetic algorithms and neural networks.","related":["Evolutionary Algorithm","Spiking Neural Network"]},{"term":"Hebbian Learning","abbr":null,"category":"AI/ML","definition":"A learning rule where synaptic strength increases when neurons fire together. Hebbian learning is foundational to neuroscience-inspired models.","related":["Neural Network","Synaptic Plasticity"]},{"term":"Attention Deficit","abbr":null,"category":"AI/ML","definition":"A technique where attention mechanisms selectively focus on important information. Used to improve model efficiency and interpretability.","related":["Attention Mechanism","Interpretability"]},{"term":"Edge AI","abbr":null,"category":"AI/ML","definition":"Running machine learning models on edge devices (phones, IoT) rather than cloud servers. Edge AI enables offline operation and privacy.","related":["Model Compression","Inference","Mobile ML"]},{"term":"Mobile ML","abbr":null,"category":"AI/ML","definition":"Machine learning optimization for mobile platforms with constraints on compute and memory. Mobile ML requires model compression and efficient inference.","related":["Edge AI","Model Compression"]},{"term":"TensorFlow Lite","abbr":null,"category":"AI/ML","definition":"A lightweight machine learning framework for mobile and embedded devices. TensorFlow Lite enables efficient inference on resource-constrained devices.","related":["Edge AI","Mobile ML","TensorFlow"]},{"term":"ONNX","abbr":null,"category":"AI/ML","definition":"Open Neural Network Exchange — a standard format for representing neural networks. ONNX enables model interoperability across frameworks.","related":["Model Format","Inference","Deployment"]},{"term":"CoreML","abbr":null,"category":"AI/ML","definition":"Apple's machine learning framework for iOS, macOS and other Apple platforms. CoreML enables on-device machine learning on Apple devices.","related":["Mobile ML","Edge AI"]},{"term":"MediaPipe","abbr":null,"category":"AI/ML","definition":"A cross-platform framework for building perception pipelines on mobile and desktop. MediaPipe provides pre-built models for hand, face and pose detection.","related":["Edge AI","Computer Vision","Mobile ML"]},{"term":"TensorFlow.js","abbr":null,"category":"AI/ML","definition":"A JavaScript library for machine learning in the browser and Node.js. TensorFlow.js enables client-side machine learning.","related":["Machine Learning Framework","Web AI"]},{"term":"WebGL","abbr":null,"category":"AI/ML","definition":"A JavaScript API for GPU-accelerated graphics that enables efficient neural network inference in browsers. WebGL powers TensorFlow.js.","related":["GPU Acceleration","Web AI"]},{"term":"Federated Inference","abbr":null,"category":"AI/ML","definition":"Making predictions using distributed models trained via federated learning. Federated inference preserves privacy.","related":["Federated Learning","Privacy-Preserving ML"]},{"term":"Differential Privacy","abbr":"DP","category":"AI/ML","definition":"A mathematical framework for quantifying and limiting privacy loss in data analysis. Differential privacy enables privacy-preserving machine learning.","related":["Privacy","Federated Learning"]},{"term":"Homomorphic Encryption","abbr":null,"category":"AI/ML","definition":"An encryption scheme enabling computation on encrypted data. Homomorphic encryption enables privacy-preserving inference.","related":["Privacy","Encryption","Cryptography"]},{"term":"Secure Multiparty Computation","abbr":"MPC","category":"AI/ML","definition":"A cryptographic protocol enabling multiple parties to compute on private data. MPC preserves privacy in distributed machine learning.","related":["Privacy","Cryptography","Federated Learning"]},{"term":"Privacy Budget","abbr":null,"category":"AI/ML","definition":"In differential privacy, the total allowable privacy loss. Privacy budget controls the tradeoff between privacy and utility.","related":["Differential Privacy","Privacy"]},{"term":"Data Poisoning","abbr":null,"category":"AI/ML","definition":"An adversarial attack that corrupts training data to degrade model performance. Data poisoning is a threat to machine learning systems.","related":["Adversarial Attack","Robustness"]},{"term":"Membership Inference","abbr":null,"category":"AI/ML","definition":"An attack that determines if a sample was in a model's training data. Membership inference is a privacy threat.","related":["Privacy","Adversarial Attack"]},{"term":"Model Inversion","abbr":null,"category":"AI/ML","definition":"An attack that reconstructs training data from model outputs. Model inversion threatens privacy of training data.","related":["Privacy","Adversarial Attack"]},{"term":"Adversarial Attack","abbr":null,"category":"AI/ML","definition":"An attack that causes a model to make incorrect predictions through carefully crafted inputs. Adversarial attacks reveal model vulnerabilities.","related":["Adversarial Robustness","Security","Perturbation"]},{"term":"Adversarial Example","abbr":null,"category":"AI/ML","definition":"An input designed to fool a machine learning model through small perturbations. Adversarial examples are imperceptible to humans.","related":["Adversarial Attack","Perturbation"]},{"term":"Adversarial Training","abbr":null,"category":"AI/ML","definition":"A training method that includes adversarial examples to improve robustness. Adversarial training makes models resistant to attacks.","related":["Adversarial Robustness","Robustness"]},{"term":"Adversarial Robustness","abbr":null,"category":"AI/ML","definition":"The resistance of machine learning models to adversarial attacks. Adversarial robustness is critical for secure AI systems.","related":["Adversarial Attack","Adversarial Training"]},{"term":"Perturbation","abbr":null,"category":"AI/ML","definition":"Small changes to input data used in adversarial attacks or robustness analysis. Perturbations measure model sensitivity.","related":["Adversarial Attack","Gradient"]},{"term":"FGSM Attack","abbr":null,"category":"AI/ML","definition":"Fast Gradient Sign Method — a simple adversarial attack using gradient direction. FGSM is efficient but less effective than stronger attacks.","related":["Adversarial Attack","Gradient-Based Attack"]},{"term":"Certified Robustness","abbr":null,"category":"AI/ML","definition":"Provable guarantees that models are robust within a certain perturbation radius. Certified robustness enables safety-critical applications.","related":["Adversarial Robustness","Verification"]},{"term":"Domain Adaptation","abbr":null,"category":"AI/ML","definition":"A learning approach adapting models trained on source domains to target domains. Domain adaptation handles distribution shift.","related":["Transfer Learning","Distribution Shift","Domain Gap"]},{"term":"Domain Gap","abbr":null,"category":"AI/ML","definition":"The difference in distributions between source and target domains. Large domain gaps degrade model performance.","related":["Domain Adaptation","Distribution Shift"]},{"term":"Source-Free Domain Adaptation","abbr":null,"category":"AI/ML","definition":"Domain adaptation using only target data without access to source data. Source-free adaptation is practical for privacy and efficiency.","related":["Domain Adaptation","Transfer Learning"]},{"term":"Unsupervised Domain Adaptation","abbr":null,"category":"AI/ML","definition":"Domain adaptation without labeled target data. Unsupervised adaptation is challenging and practical.","related":["Domain Adaptation","Unsupervised Learning"]},{"term":"Zero-Shot Domain Adaptation","abbr":null,"category":"AI/ML","definition":"Adapting to unseen target domains using semantic information without target data. Zero-shot adaptation leverages semantic knowledge.","related":["Domain Adaptation","Zero-Shot Learning"]},{"term":"Distribution Shift","abbr":null,"category":"AI/ML","definition":"A change in the distribution of data between training and deployment. Distribution shift causes model performance degradation.","related":["Domain Adaptation","Covariate Shift","Label Shift"]},{"term":"Covariate Shift","abbr":null,"category":"AI/ML","definition":"A type of distribution shift where P(X) changes but P(Y|X) remains constant. Covariate shift is common in practice.","related":["Distribution Shift","Domain Adaptation"]},{"term":"Label Shift","abbr":null,"category":"AI/ML","definition":"A type of distribution shift where P(Y) changes but P(X|Y) remains constant. Label shift occurs in imbalanced datasets.","related":["Distribution Shift","Class Imbalance"]},{"term":"Out-of-Distribution Detection","abbr":"OOD Detection","category":"AI/ML","definition":"Detecting when inputs are from outside the training distribution. OOD detection is crucial for safe deployment.","related":["Anomaly Detection","Distribution Shift"]},{"term":"Novelty Detection","abbr":null,"category":"AI/ML","definition":"Detecting novel or previously unseen patterns in data. Novelty detection is related to anomaly and outlier detection.","related":["Anomaly Detection","Out-of-Distribution Detection"]},{"term":"Causal Inference","abbr":null,"category":"AI/ML","definition":"The inference of cause-and-effect relationships from data. Causal inference goes beyond correlation to establish causation.","related":["Causal Model","Potential Outcomes","Confounding"]},{"term":"Causal Model","abbr":null,"category":"AI/ML","definition":"A probabilistic model representing causal relationships between variables. Causal models enable reasoning about interventions.","related":["Causal Inference","Graphical Model","Directed Acyclic Graph"]},{"term":"Potential Outcomes","abbr":null,"category":"AI/ML","definition":"A framework for causal inference treating treatment effects as random variables. Potential outcomes enable estimation of causal effects.","related":["Causal Inference","Treatment Effect"]},{"term":"Confounding","abbr":null,"category":"AI/ML","definition":"A situation where a variable affects both treatment and outcome, creating spurious associations. Confounding is a major challenge in causal inference.","related":["Causal Inference","Bias"]},{"term":"Backdoor Criterion","abbr":null,"category":"AI/ML","definition":"A graphical criterion for identifying confounding variables in causal models. Backdoor criterion enables correct causal identification.","related":["Causal Inference","Confounding","Graphical Model"]},{"term":"Frontdoor Criterion","abbr":null,"category":"AI/ML","definition":"A graphical criterion for identifying causal effects when there are hidden confounders. Frontdoor criterion extends backdoor methods.","related":["Causal Inference","Confounding"]},{"term":"Directed Acyclic Graph","abbr":"DAG","category":"AI/ML","definition":"A graphical representation of causal structures using directed edges. DAGs enable visual reasoning about causality.","related":["Causal Model","Graphical Model"]},{"term":"Graphical Model","abbr":null,"category":"AI/ML","definition":"A probabilistic model using graphs to represent dependencies between variables. Graphical models enable efficient inference.","related":["Bayesian Network","Markov Random Field"]},{"term":"Markov Random Field","abbr":"MRF","category":"AI/ML","definition":"An undirected graphical model representing conditional independencies. MRFs are useful for modeling spatial and structural dependencies.","related":["Graphical Model","Probabilistic Model"]},{"term":"Treatment Effect","abbr":null,"category":"AI/ML","definition":"The causal impact of a treatment on an outcome. Treatment effects are central to causal inference.","related":["Causal Inference","Potential Outcomes"]},{"term":"Heterogeneous Treatment Effect","abbr":"HTE","category":"AI/ML","definition":"Treatment effects that vary across subgroups or individuals. HTE enables personalized interventions.","related":["Treatment Effect","Causal Forest"]},{"term":"Causal Forest","abbr":null,"category":"AI/ML","definition":"A random forest variant for estimating heterogeneous treatment effects. Causal forests enable personalized prediction.","related":["Random Forest","Heterogeneous Treatment Effect"]},{"term":"Medical Image Analysis","abbr":null,"category":"AI/ML","definition":"Application of computer vision to medical images for diagnosis and treatment. Medical imaging combines deep learning with domain knowledge.","related":["Computer Vision","Semantic Segmentation","Disease Detection"]},{"term":"Disease Detection","abbr":null,"category":"AI/ML","definition":"Using machine learning to identify diseases from medical data. Disease detection improves diagnosis speed and accuracy.","related":["Medical Image Analysis","Classification"]},{"term":"Patient Stratification","abbr":null,"category":"AI/ML","definition":"Dividing patients into subgroups based on characteristics for personalized treatment. Stratification enables targeted interventions.","related":["Clustering","Precision Medicine"]},{"term":"Precision Medicine","abbr":null,"category":"AI/ML","definition":"Tailoring medical treatment to individual characteristics. Precision medicine uses machine learning for personalization.","related":["Patient Stratification","Personalization"]},{"term":"Drug Discovery","abbr":null,"category":"AI/ML","definition":"Using machine learning to accelerate identification of drug candidates. AI speeds up and reduces costs of drug discovery.","related":["Molecular Modeling","Graph Neural Network"]},{"term":"Protein Structure Prediction","abbr":null,"category":"AI/ML","definition":"Predicting 3D protein structures from amino acid sequences. AlphaFold revolutionized structure prediction.","related":["Sequence Modeling","Deep Learning"]},{"term":"AlphaFold","abbr":null,"category":"AI/ML","definition":"An AI system from DeepMind that predicts protein structures with unprecedented accuracy. AlphaFold was a major breakthrough in biology.","related":["Protein Structure Prediction","Deep Learning"]},{"term":"Genomics","abbr":null,"category":"AI/ML","definition":"Application of machine learning to genome analysis and genetic data. Genomics enables personalized medicine and disease understanding.","related":["Sequence Modeling","Classification"]},{"term":"Electronic Health Records","abbr":"EHR","category":"AI/ML","definition":"Digital records of patient health information used for prediction and analysis. EHR data enables learning of patient outcomes.","related":["Healthcare AI","Sequential Data"]},{"term":"Algorithmic Trading","abbr":null,"category":"AI/ML","definition":"Using machine learning models to make automated trading decisions. Algorithmic trading exploits patterns in market data.","related":["Time Series Prediction","Reinforcement Learning"]},{"term":"Credit Scoring","abbr":null,"category":"AI/ML","definition":"Predicting creditworthiness using machine learning on financial data. Credit scoring determines loan approval and terms.","related":["Classification","Risk Assessment"]},{"term":"Fraud Detection","abbr":null,"category":"AI/ML","definition":"Using machine learning to identify fraudulent transactions or activities. Fraud detection protects financial institutions.","related":["Anomaly Detection","Classification"]},{"term":"Risk Assessment","abbr":null,"category":"AI/ML","definition":"Quantifying and predicting financial risk using machine learning. Risk assessment informs investment and lending decisions.","related":["Prediction","Classification"]},{"term":"Portfolio Optimization","abbr":null,"category":"AI/ML","definition":"Using optimization algorithms to allocate assets in investment portfolios. Portfolio optimization balances risk and return.","related":["Optimization","Risk Management"]},{"term":"Model-Based RL","abbr":null,"category":"AI/ML","definition":"Reinforcement learning that learns an explicit model of the environment dynamics. Model-based RL enables planning.","related":["Reinforcement Learning","Model Learning"]},{"term":"Model-Free RL","abbr":null,"category":"AI/ML","definition":"Reinforcement learning that directly learns policies without modeling environment dynamics. Model-free RL is simpler but less sample-efficient.","related":["Reinforcement Learning","Policy Gradient"]},{"term":"On-Policy Learning","abbr":null,"category":"AI/ML","definition":"Reinforcement learning where the agent learns from data generated by the current policy. On-policy learning is safer but less sample-efficient.","related":["Reinforcement Learning","Policy Gradient"]},{"term":"Off-Policy Learning","abbr":null,"category":"AI/ML","definition":"Reinforcement learning where the agent learns from data generated by other policies. Off-policy learning is sample-efficient.","related":["Reinforcement Learning","Q-Learning"]},{"term":"Experience Replay","abbr":null,"category":"AI/ML","definition":"A technique storing and replaying past experiences to decorrelate samples. Experience replay stabilizes learning in deep RL.","related":["Reinforcement Learning","Deep Q-Network"]},{"term":"Deep Q-Network","abbr":"DQN","category":"AI/ML","definition":"A deep reinforcement learning algorithm using Q-learning with neural networks. DQN achieved superhuman performance on Atari games.","related":["Q-Learning","Deep Reinforcement Learning"]},{"term":"Deep Reinforcement Learning","abbr":"Deep RL","category":"AI/ML","definition":"Reinforcement learning using deep neural networks. Deep RL enables learning from high-dimensional observations like images.","related":["Reinforcement Learning","Deep Learning"]},{"term":"AlphaGo","abbr":null,"category":"AI/ML","definition":"An AI system from DeepMind that defeated human champions in the game Go. AlphaGo demonstrated the power of deep RL.","related":["Deep Reinforcement Learning","Monte Carlo Tree Search"]},{"term":"Monte Carlo Tree Search","abbr":"MCTS","category":"AI/ML","definition":"A tree search algorithm using random simulations to estimate move values. MCTS is effective in games and planning.","related":["Planning","Search Algorithm"]},{"term":"Imitation Learning","abbr":null,"category":"AI/ML","definition":"Learning to mimic expert behavior from demonstrations. Imitation learning bootstraps learning from human guidance.","related":["Reinforcement Learning","Supervised Learning"]},{"term":"Inverse Reinforcement Learning","abbr":"IRL","category":"AI/ML","definition":"Inferring the reward function from expert demonstrations. IRL enables learning objectives from human behavior.","related":["Reinforcement Learning","Imitation Learning"]},{"term":"Multi-Agent Reinforcement Learning","abbr":"MARL","category":"AI/ML","definition":"Reinforcement learning with multiple interacting agents. MARL addresses coordination and competition.","related":["Reinforcement Learning","Game Theory"]},{"term":"Curiosity-Driven Learning","abbr":null,"category":"AI/ML","definition":"A reinforcement learning approach where agents explore to maximize intrinsic curiosity reward. Curiosity drives exploration in sparse reward environments.","related":["Reinforcement Learning","Exploration"]},{"term":"Intrinsic Motivation","abbr":null,"category":"AI/ML","definition":"In RL, motivation driven by internal goals rather than external rewards. Intrinsic motivation enables exploration.","related":["Curiosity-Driven Learning","Reinforcement Learning"]},{"term":"Attention Visualization","abbr":null,"category":"AI/ML","definition":"Visualizing which parts of input the attention mechanism focuses on. Attention visualization improves model interpretability.","related":["Attention Mechanism","Interpretability","Visualization"]},{"term":"Saliency Map","abbr":null,"category":"AI/ML","definition":"A visualization showing which input features most influence model predictions. Saliency maps aid model interpretation.","related":["Interpretability","Gradient","Visualization"]},{"term":"Gradient-Based Attribution","abbr":null,"category":"AI/ML","definition":"Computing feature importance using gradients of predictions with respect to inputs. Gradient-based methods are efficient and differentiable.","related":["Interpretability","Feature Importance","SHAP"]},{"term":"Influence Function","abbr":null,"category":"AI/ML","definition":"A method for tracing predictions to influential training examples. Influence functions enable understanding of model decisions.","related":["Interpretability","Training Data"]},{"term":"Concept Activation Vectors","abbr":"TCAV","category":"AI/ML","definition":"A method for interpreting neural networks using human-defined concepts. TCAV bridges human concepts and neural representations.","related":["Interpretability","Concept Learning"]},{"term":"Prototype Learning","abbr":null,"category":"AI/ML","definition":"Learning prototypical examples that explain model predictions. Prototype-based models are interpretable.","related":["Interpretability","Case-Based Reasoning"]},{"term":"Case-Based Reasoning","abbr":null,"category":"AI/ML","definition":"A reasoning approach that solves problems by retrieving and adapting similar past cases. Case-based reasoning is interpretable.","related":["Prototype Learning","Memory-Based Learning"]},{"term":"Counterfactual Explanation","abbr":null,"category":"AI/ML","definition":"Explaining model predictions by describing minimal changes needed to change the outcome. Counterfactual explanations are intuitive.","related":["Interpretability","Explainability"]},{"term":"Example-Based Explanation","abbr":null,"category":"AI/ML","definition":"Explaining model decisions by showing similar training examples. Example-based methods are intuitive and interpretable.","related":["Interpretability","Case-Based Reasoning"]},{"term":"Attention Attribution","abbr":null,"category":"AI/ML","definition":"Using attention weights to attribute predictions to input elements. Attention attribution provides interpretability.","related":["Attention Mechanism","Interpretability"]},{"term":"Fairness Metric","abbr":null,"category":"AI/ML","definition":"Quantifying model fairness across demographic groups. Fairness metrics guide bias mitigation.","related":["Fairness","Bias"]},{"term":"Fairness","abbr":null,"category":"AI/ML","definition":"Ensuring machine learning systems treat different groups equitably. Fairness is critical for responsible AI.","related":["Bias","Discrimination","Ethical AI"]},{"term":"Bias Mitigation","abbr":null,"category":"AI/ML","definition":"Techniques for reducing bias in machine learning models. Bias mitigation improves fairness.","related":["Fairness","Bias","Pre-Processing"]},{"term":"Pre-Processing Bias Mitigation","abbr":null,"category":"AI/ML","definition":"Addressing bias by modifying training data before model training. Pre-processing approaches are model-agnostic.","related":["Bias Mitigation","Data Preprocessing"]},{"term":"In-Processing Bias Mitigation","abbr":null,"category":"AI/ML","definition":"Addressing bias during model training through loss modifications or constraints. In-processing methods are algorithm-specific.","related":["Bias Mitigation","Fairness"]},{"term":"Post-Processing Bias Mitigation","abbr":null,"category":"AI/ML","definition":"Addressing bias by adjusting predictions after model inference. Post-processing is model-agnostic.","related":["Bias Mitigation","Fairness"]},{"term":"Demographic Parity","abbr":null,"category":"AI/ML","definition":"A fairness criterion requiring equal selection rates across demographic groups. Demographic parity is a fairness metric.","related":["Fairness","Equality"]},{"term":"Equalized Odds","abbr":null,"category":"AI/ML","definition":"A fairness criterion requiring equal true positive and false positive rates across groups. Equalized odds balance error across groups.","related":["Fairness","Equality of Opportunity"]},{"term":"Calibration","abbr":null,"category":"AI/ML","definition":"Ensuring predicted probabilities match actual frequencies. Calibrated models provide reliable confidence estimates.","related":["Probability Estimation","Model Evaluation"]},{"term":"Uncertainty Quantification","abbr":null,"category":"AI/ML","definition":"Quantifying confidence or uncertainty in model predictions. Uncertainty estimates are crucial for safe deployment.","related":["Calibration","Bayesian Deep Learning","Confidence"]},{"term":"Bayesian Deep Learning","abbr":null,"category":"AI/ML","definition":"Combining deep learning with Bayesian inference for uncertainty quantification. Bayesian deep learning enables principled uncertainty.","related":["Deep Learning","Bayesian Inference","Uncertainty Quantification"]},{"term":"Monte Carlo Dropout","abbr":null,"category":"AI/ML","definition":"Using dropout at inference time to estimate uncertainty through ensemble predictions. Monte Carlo dropout is a practical uncertainty method.","related":["Dropout","Uncertainty Quantification","Ensemble Learning"]},{"term":"Epistemic Uncertainty","abbr":null,"category":"AI/ML","definition":"Uncertainty due to lack of knowledge, reducible with more data. Epistemic uncertainty reflects model ignorance.","related":["Uncertainty Quantification","Aleatoric Uncertainty"]},{"term":"Aleatoric Uncertainty","abbr":null,"category":"AI/ML","definition":"Irreducible uncertainty due to inherent randomness in data. Aleatoric uncertainty cannot be reduced with more data.","related":["Uncertainty Quantification","Epistemic Uncertainty"]},{"term":"Triplet Loss","abbr":null,"category":"AI/ML","definition":"A loss function that minimizes distance between anchor and positive samples while maximizing distance to negatives. Triplet loss is used for metric learning and face recognition.","related":["Loss Function","Metric Learning","Distance Metric"]},{"term":"Contrastive Loss","abbr":null,"category":"AI/ML","definition":"A loss function that brings similar samples closer and pushes dissimilar samples apart. Contrastive loss is foundational for contrastive learning.","related":["Loss Function","Contrastive Learning","Similarity"]},{"term":"Hinge Loss","abbr":null,"category":"AI/ML","definition":"A loss function commonly used for SVM and margin-based learning. Hinge loss penalizes predictions that are not confident enough.","related":["Loss Function","Support Vector Machine"]},{"term":"Huber Loss","abbr":null,"category":"AI/ML","definition":"A robust loss function that is quadratic for small errors and linear for large errors. Huber loss is less sensitive to outliers than MSE.","related":["Loss Function","Robustness","Regression"]},{"term":"Focal Loss","abbr":null,"category":"AI/ML","definition":"A loss function designed to address class imbalance by focusing on hard-to-classify examples. Focal loss reduces weight on easy examples.","related":["Loss Function","Class Imbalance","Object Detection"]},{"term":"Kullback-Leibler Divergence","abbr":"KL Divergence","category":"AI/ML","definition":"A measure of how one probability distribution differs from another. KL divergence is used in information theory and probabilistic models.","related":["Probability Distribution","Information Theory"]},{"term":"Wasserstein Distance","abbr":null,"category":"AI/ML","definition":"A distance metric between probability distributions measuring minimum cost of transporting probability mass. Wasserstein distance is used in GANs.","related":["Distance Metric","Probability Distribution","GAN"]},{"term":"Earth Mover Distance","abbr":null,"category":"AI/ML","definition":"Another name for Wasserstein distance, measuring how much mass needs to move to transform one distribution to another.","related":["Wasserstein Distance","Distance Metric"]},{"term":"Jensen-Shannon Divergence","abbr":null,"category":"AI/ML","definition":"A symmetric divergence measure between probability distributions based on KL divergence. Jensen-Shannon is more stable than KL.","related":["KL Divergence","Probability Distribution"]},{"term":"Categorical Cross-Entropy","abbr":null,"category":"AI/ML","definition":"A loss function for multi-class classification that measures difference between predicted and true class probabilities.","related":["Cross-Entropy Loss","Multi-Class Classification"]},{"term":"Binary Cross-Entropy","abbr":null,"category":"AI/ML","definition":"A loss function for binary classification measuring difference between predicted and true binary probabilities.","related":["Cross-Entropy Loss","Binary Classification"]},{"term":"Sparse Categorical Cross-Entropy","abbr":null,"category":"AI/ML","definition":"A variant of categorical cross-entropy for integer-encoded labels avoiding one-hot encoding. Sparse variant saves memory.","related":["Categorical Cross-Entropy","Cross-Entropy Loss"]},{"term":"Negative Log-Likelihood","abbr":"NLL","category":"AI/ML","definition":"A loss function based on negative log probability of true labels. NLL is equivalent to cross-entropy for classification.","related":["Loss Function","Likelihood","Classification"]},{"term":"Swish Activation","abbr":null,"category":"AI/ML","definition":"A smooth, non-monotonic activation function defined as x * sigmoid(x). Swish often outperforms ReLU.","related":["Activation Function","Neural Network"]},{"term":"GELU Activation","abbr":null,"category":"AI/ML","definition":"Gaussian Error Linear Unit — an activation function approximating ReLU with Gaussian CDF. GELU is used in BERT and modern transformers.","related":["Activation Function","Transformer"]},{"term":"Mish Activation","abbr":null,"category":"AI/ML","definition":"A smooth activation function with self-regularization properties. Mish has shown improvements in some deep learning tasks.","related":["Activation Function","Neural Network"]},{"term":"ELU Activation","abbr":null,"category":"AI/ML","definition":"Exponential Linear Unit — an activation allowing negative outputs for better gradient flow. ELU addresses dying ReLU problem.","related":["Activation Function","ReLU"]},{"term":"SELU Activation","abbr":null,"category":"AI/ML","definition":"Scaled ELU — an activation enabling self-normalizing neural networks. SELU maintains mean zero and unit variance.","related":["ELU Activation","Self-Normalizing Neural Networks"]},{"term":"Leaky ReLU","abbr":null,"category":"AI/ML","definition":"A ReLU variant allowing small negative gradients for inactive neurons. Leaky ReLU prevents dying ReLU problem.","related":["ReLU Activation","Activation Function"]},{"term":"Parametric ReLU","abbr":"PReLU","category":"AI/ML","definition":"A ReLU variant where the slope for negative inputs is learned. PReLU adapts activation to the data.","related":["ReLU Activation","Leaky ReLU"]},{"term":"Hardtanh Activation","abbr":null,"category":"AI/ML","definition":"A piecewise linear approximation of tanh with constant gradients in linear regions. Hardtanh is computationally efficient.","related":["Activation Function","Tanh"]},{"term":"Hard Sigmoid","abbr":null,"category":"AI/ML","definition":"A piecewise linear approximation of sigmoid activation. Hard sigmoid is efficient for inference.","related":["Sigmoid Activation","Activation Function"]},{"term":"Log-Softmax","abbr":null,"category":"AI/ML","definition":"A numerically stable combination of log and softmax. Log-softmax prevents numerical overflow.","related":["Softmax Activation","Numerical Stability"]},{"term":"He Initialization","abbr":null,"category":"AI/ML","definition":"A weight initialization scheme accounting for ReLU non-linearity. He initialization maintains variance across layers.","related":["Weight Initialization","ReLU Activation"]},{"term":"Glorot Initialization","abbr":null,"category":"AI/ML","definition":"Another name for Xavier initialization using uniform distribution. Glorot initialization balances variance.","related":["Xavier Initialization","Weight Initialization"]},{"term":"Kaiming Initialization","abbr":null,"category":"AI/ML","definition":"Another name for He initialization from Kaiming He's paper. Kaiming initialization improves deep network training.","related":["He Initialization","Weight Initialization"]},{"term":"Lecun Initialization","abbr":null,"category":"AI/ML","definition":"A weight initialization scheme for tanh and sigmoid activations. Lecun maintains gradient flow.","related":["Weight Initialization","Xavier Initialization"]},{"term":"Orthogonal Initialization","abbr":null,"category":"AI/ML","definition":"Initializing weights as orthogonal matrices improving gradient flow. Orthogonal initialization is beneficial for RNNs.","related":["Weight Initialization","Recurrent Neural Network"]},{"term":"Sparse Initialization","abbr":null,"category":"AI/ML","definition":"Weight initialization resulting in sparse connection patterns. Sparse initialization encourages sparsity.","related":["Weight Initialization","Sparse Model"]},{"term":"DropConnect","abbr":null,"category":"AI/ML","definition":"A regularization technique dropping connections between neurons during training. DropConnect is similar to dropout but drops weights.","related":["Dropout","Regularization"]},{"term":"Stochastic Depth","abbr":null,"category":"AI/ML","definition":"A regularization technique randomly skipping layers during training. Stochastic depth reduces training time and improves generalization.","related":["Dropout","Regularization","Deep Learning"]},{"term":"Mixup","abbr":null,"category":"AI/ML","definition":"A data augmentation technique mixing pairs of training examples linearly. Mixup improves generalization and robustness.","related":["Data Augmentation","Regularization"]},{"term":"Cutmix","abbr":null,"category":"AI/ML","definition":"A data augmentation technique removing and mixing patches between images. Cutmix improves model robustness.","related":["Data Augmentation","Mixup"]},{"term":"Cutout","abbr":null,"category":"AI/ML","definition":"A data augmentation technique removing random patches from images. Cutout acts as regularization.","related":["Data Augmentation","Regularization"]},{"term":"RandAugment","abbr":null,"category":"AI/ML","definition":"An automated data augmentation selecting random augmentations with magnitude. RandAugment simplifies augmentation tuning.","related":["Data Augmentation","AutoML"]},{"term":"AutoAugment","abbr":null,"category":"AI/ML","definition":"An automated data augmentation using reinforcement learning to find optimal augmentations. AutoAugment discovers effective augmentation policies.","related":["Data Augmentation","Reinforcement Learning"]},{"term":"Ghost Batch Normalization","abbr":null,"category":"AI/ML","definition":"A variant of batch normalization that uses smaller effective batch sizes. Ghost BN maintains diversity.","related":["Batch Normalization","Normalization"]},{"term":"Group Normalization","abbr":null,"category":"AI/ML","definition":"A normalization technique dividing channels into groups and normalizing. Group norm works with small batch sizes.","related":["Batch Normalization","Normalization"]},{"term":"Instance Normalization","abbr":null,"category":"AI/ML","definition":"A normalization technique normalizing each instance independently. Instance norm is used in style transfer.","related":["Batch Normalization","Normalization"]},{"term":"Spectral Normalization","abbr":null,"category":"AI/ML","definition":"A normalization technique constraining spectral norm of weight matrices. Spectral normalization stabilizes GAN training.","related":["Normalization","GAN"]},{"term":"Weight Standardization","abbr":null,"category":"AI/ML","definition":"A normalization technique standardizing weight matrices. Weight standardization improves training stability.","related":["Normalization","Regularization"]},{"term":"Lane Detection","abbr":null,"category":"AI/ML","definition":"A computer vision task identifying road lanes. Lane detection is crucial for autonomous driving.","related":["Computer Vision","Autonomous Driving","Semantic Segmentation"]},{"term":"Road Sign Recognition","abbr":null,"category":"AI/ML","definition":"Classifying and detecting traffic signs from images. Road sign recognition aids autonomous systems.","related":["Computer Vision","Classification","Object Detection"]},{"term":"Pedestrian Detection","abbr":null,"category":"AI/ML","definition":"Detecting and localizing pedestrians in images or videos. Pedestrian detection is essential for autonomous driving.","related":["Object Detection","Computer Vision"]},{"term":"Vehicle Detection","abbr":null,"category":"AI/ML","definition":"Detecting cars and vehicles in images. Vehicle detection is fundamental for autonomous systems.","related":["Object Detection","Computer Vision"]},{"term":"Traffic Scene Understanding","abbr":null,"category":"AI/ML","definition":"Understanding complete traffic scenes including all elements. Scene understanding is needed for autonomous driving.","related":["Scene Understanding","Computer Vision"]},{"term":"Salient Object Detection","abbr":null,"category":"AI/ML","definition":"Detecting visually salient regions in images. Salient detection aids attention and visual understanding.","related":["Object Detection","Segmentation"]},{"term":"Edge Detection","abbr":null,"category":"AI/ML","definition":"Identifying sharp changes in intensity in images (edges). Edge detection is foundational for computer vision.","related":["Computer Vision","Image Processing"]},{"term":"Contour Detection","abbr":null,"category":"AI/ML","definition":"Finding boundaries of objects in images. Contour detection aids object recognition.","related":["Edge Detection","Computer Vision"]},{"term":"Corner Detection","abbr":null,"category":"AI/ML","definition":"Identifying corner features in images. Corner detection is used for image matching and tracking.","related":["Feature Detection","Computer Vision"]},{"term":"Feature Matching","abbr":null,"category":"AI/ML","definition":"Finding correspondences between features in images. Feature matching enables image alignment and 3D reconstruction.","related":["Feature Detection","Computer Vision"]},{"term":"Image Registration","abbr":null,"category":"AI/ML","definition":"Aligning multiple images spatially. Image registration is used in medical imaging and remote sensing.","related":["Computer Vision","Image Alignment"]},{"term":"Image Stitching","abbr":null,"category":"AI/ML","definition":"Combining multiple images into a panorama. Image stitching requires registration and blending.","related":["Image Registration","Computer Vision"]},{"term":"Document Analysis","abbr":null,"category":"AI/ML","definition":"Understanding document structure and content from images. Document analysis includes layout analysis and text extraction.","related":["Computer Vision","OCR"]},{"term":"Handwriting Recognition","abbr":null,"category":"AI/ML","definition":"Recognizing handwritten text from images. Handwriting recognition requires character segmentation and classification.","related":["Computer Vision","OCR"]},{"term":"Scene Text Recognition","abbr":null,"category":"AI/ML","definition":"Recognizing text in natural scene images. Scene text recognition is challenging due to variations.","related":["OCR","Computer Vision"]},{"term":"Text Detection","abbr":null,"category":"AI/ML","definition":"Localizing text regions in images. Text detection precedes recognition.","related":["Scene Text Recognition","Object Detection"]},{"term":"Document Skew Correction","abbr":null,"category":"AI/ML","definition":"Correcting rotated or skewed document images. Skew correction improves OCR accuracy.","related":["Document Analysis","Image Processing"]},{"term":"License Plate Recognition","abbr":null,"category":"AI/ML","definition":"Reading vehicle license plates from images. License plate recognition aids traffic monitoring.","related":["OCR","Computer Vision"]},{"term":"Dependency Parsing","abbr":null,"category":"AI/ML","definition":"Identifying grammatical dependencies between words. Dependency parsing reveals sentence structure.","related":["Natural Language Processing","Parsing","Syntax Analysis"]},{"term":"Constituency Parsing","abbr":null,"category":"AI/ML","definition":"Building parse trees showing phrase structure of sentences. Constituency parsing analyzes hierarchical structure.","related":["Dependency Parsing","Natural Language Processing"]},{"term":"Part-of-Speech Tagging","abbr":"POS Tagging","category":"AI/ML","definition":"Labeling words with their grammatical roles. POS tagging is fundamental for NLP.","related":["Natural Language Processing","Sequence Labeling"]},{"term":"Chunking","abbr":null,"category":"AI/ML","definition":"Grouping words into phrases (chunks). Chunking is a shallow parsing technique.","related":["Natural Language Processing","Parsing"]},{"term":"Coreference Resolution","abbr":null,"category":"AI/ML","definition":"Identifying which pronouns or noun phrases refer to same entity. Coreference resolution aids understanding.","related":["Natural Language Processing","Entity Linking"]},{"term":"Relation Extraction","abbr":null,"category":"AI/ML","definition":"Extracting relationships between entities from text. Relation extraction enables knowledge graph construction.","related":["Information Extraction","Natural Language Processing"]},{"term":"Event Extraction","abbr":null,"category":"AI/ML","definition":"Extracting events and their arguments from text. Event extraction enables event understanding.","related":["Information Extraction","Natural Language Processing"]},{"term":"Aspect-Based Sentiment Analysis","abbr":null,"category":"AI/ML","definition":"Analyzing sentiment toward specific aspects of entities. Aspect-based analysis is fine-grained.","related":["Sentiment Analysis","Natural Language Processing"]},{"term":"Emotion Detection","abbr":null,"category":"AI/ML","definition":"Detecting emotions expressed in text. Emotion detection is related to sentiment analysis.","related":["Sentiment Analysis","Natural Language Processing"]},{"term":"Intent Detection","abbr":null,"category":"AI/ML","definition":"Identifying user intent from text. Intent detection is crucial for conversational AI.","related":["Natural Language Processing","Classification"]},{"term":"Slot Filling","abbr":null,"category":"AI/ML","definition":"Extracting specific information (slots) from text. Slot filling is used in dialogue systems.","related":["Information Extraction","Natural Language Processing"]},{"term":"Paraphrase Detection","abbr":null,"category":"AI/ML","definition":"Determining if two sentences express the same meaning. Paraphrase detection uses semantic similarity.","related":["Semantic Similarity","Natural Language Processing"]},{"term":"Textual Entailment","abbr":"RTE","category":"AI/ML","definition":"Determining if one sentence logically entails another. Textual entailment is a fundamental NLP task.","related":["Natural Language Processing","Inference"]},{"term":"Natural Language Inference","abbr":"NLI","category":"AI/ML","definition":"Determining entailment relationships between premises and hypotheses. NLI tasks test logical understanding.","related":["Textual Entailment","Natural Language Processing"]},{"term":"Dialogue State Tracking","abbr":null,"category":"AI/ML","definition":"Tracking dialogue context and user intents across turns. State tracking enables multi-turn conversations.","related":["Dialogue Systems","Natural Language Processing"]},{"term":"Response Generation","abbr":null,"category":"AI/ML","definition":"Generating natural language responses to inputs. Response generation is core to chatbots.","related":["Natural Language Processing","Text Generation"]},{"term":"Language Understanding","abbr":"LU","category":"AI/ML","definition":"Extracting meaning from language. Language understanding combines multiple NLP tasks.","related":["Natural Language Processing"]},{"term":"Language Generation","abbr":"LG","category":"AI/ML","definition":"Producing natural language from representations. Language generation is inverse of understanding.","related":["Natural Language Processing"]},{"term":"Bidirectional Encoder","abbr":null,"category":"AI/ML","definition":"An encoder reading sequences in both directions. Bidirectional encoders capture context from both sides.","related":["Encoder","BERT"]},{"term":"Unidirectional Decoder","abbr":null,"category":"AI/ML","definition":"A decoder generating sequences left-to-right with causal masking. Unidirectional decoders enable autoregressive generation.","related":["Decoder","Autoregressive Model"]},{"term":"Encoder-Decoder Model","abbr":null,"category":"AI/ML","definition":"A model with encoder processing input and decoder generating output. Encoder-decoder enables sequence-to-sequence tasks.","related":["Encoder","Decoder","Sequence-to-Sequence"]},{"term":"T5 Model","abbr":null,"category":"AI/ML","definition":"Text-to-Text Transfer Transformer treating all NLP tasks as text-to-text. T5 unifies language understanding and generation.","related":["Transformer","Encoder-Decoder Model"]},{"term":"BART Model","abbr":null,"category":"AI/ML","definition":"Bidirectional Autoregressive Transformers combining BERT and GPT. BART is effective for sequence-to-sequence tasks.","related":["BERT","GPT","Encoder-Decoder Model"]},{"term":"RoBERTa","abbr":null,"category":"AI/ML","definition":"Robustly optimized BERT pre-training — an improved BERT with better pre-training. RoBERTa achieves state-of-the-art on many tasks.","related":["BERT","Language Model"]},{"term":"ELECTRA","abbr":null,"category":"AI/ML","definition":"A language model using discriminative pre-training. ELECTRA is efficient and effective.","related":["Language Model","Pre-training"]},{"term":"ALBERT","abbr":null,"category":"AI/ML","definition":"A Lite BERT reducing parameters through factorization. ALBERT is parameter-efficient.","related":["BERT","Parameter Efficiency"]},{"term":"DistilBERT","abbr":null,"category":"AI/ML","definition":"A distilled version of BERT with 40% fewer parameters. DistilBERT runs faster while retaining performance.","related":["BERT","Knowledge Distillation","Model Compression"]},{"term":"ERNIE","abbr":null,"category":"AI/ML","definition":"Enhanced Representation through Knowledge — a language model enhanced with knowledge. ERNIE improves knowledge-intensive tasks.","related":["Language Model","Knowledge Integration"]},{"term":"XLNET","abbr":null,"category":"AI/ML","definition":"An autoregressive language model with two-stream self-attention. XLNet avoids BERT's masked token problem.","related":["Language Model","Autoregressive Model"]},{"term":"Megatron-LM","abbr":null,"category":"AI/ML","definition":"A framework for distributed training of large language models. Megatron enables efficient scaling.","related":["Distributed Training","Large Language Model"]},{"term":"DeepSpeed","abbr":null,"category":"AI/ML","definition":"A deep learning library enabling training of massive models efficiently. DeepSpeed optimizes distributed training.","related":["Distributed Training","Model Optimization"]},{"term":"DeiT","abbr":null,"category":"AI/ML","definition":"Data-Efficient Image Transformers using distillation. DeiT achieves ViT performance with fewer parameters.","related":["Vision Transformer","Knowledge Distillation"]},{"term":"Swin Transformer","abbr":null,"category":"AI/ML","definition":"A vision transformer with shifted windows for efficiency. Swin achieves hierarchical feature representation.","related":["Vision Transformer","Transformer"]},{"term":"BEIT","abbr":null,"category":"AI/ML","definition":"BERT Image Embeddings using masked image modeling. BEIT applies BERT pre-training to vision.","related":["Vision Transformer","Masked Language Modeling"]},{"term":"MAE","abbr":null,"category":"AI/ML","definition":"Masked Autoencoders for image self-supervised learning. MAE learns visual representations effectively.","related":["Vision Transformer","Self-Supervised Learning","Autoencoder"]},{"term":"UniCom","abbr":null,"category":"AI/ML","definition":"Universal Computer Vision Model treating vision tasks uniformly. UniCom unifies vision task processing.","related":["Vision Transformer","Universal Model"]},{"term":"Depthwise Separable Convolution","abbr":null,"category":"AI/ML","definition":"A convolution splitting into depthwise and pointwise components. Depthwise-separable reduces computation.","related":["Convolution","Model Compression"]},{"term":"Dilated Convolution","abbr":null,"category":"AI/ML","definition":"A convolution with gaps between kernel elements increasing receptive field. Dilated convolution captures larger context.","related":["Convolution","Receptive Field"]},{"term":"Grouped Convolution","abbr":null,"category":"AI/ML","definition":"A convolution separating channels into groups. Grouped convolution reduces computation.","related":["Convolution","Model Efficiency"]},{"term":"Transposed Convolution","abbr":null,"category":"AI/ML","definition":"An upsampling operation learned through convolution. Transposed convolution is used in generative models.","related":["Convolution","Upsampling","Generative Model"]},{"term":"Deconvolution","abbr":null,"category":"AI/ML","definition":"Another term for transposed convolution used for upsampling. Deconvolution learned to invert convolution.","related":["Transposed Convolution","Upsampling"]},{"term":"Standard Convolution","abbr":null,"category":"AI/ML","definition":"The basic convolution operation with full kernels. Standard convolution is computationally expensive.","related":["Convolution","Convolutional Neural Network"]},{"term":"Point-Wise Convolution","abbr":null,"category":"AI/ML","definition":"A 1x1 convolution changing channel dimensions. Pointwise convolution is computationally efficient.","related":["Convolution","Model Efficiency"]},{"term":"Receptive Field","abbr":null,"category":"AI/ML","definition":"The region of input that influences an output neuron. Larger receptive field captures more context.","related":["Convolution","Dilated Convolution"]},{"term":"Max Pooling","abbr":null,"category":"AI/ML","definition":"Selecting maximum values in pooling regions. Max pooling is aggressive downsampling.","related":["Pooling","Convolutional Neural Network"]},{"term":"Average Pooling","abbr":null,"category":"AI/ML","definition":"Computing average values in pooling regions. Average pooling is gentler than max pooling.","related":["Pooling","Convolutional Neural Network"]},{"term":"Stochastic Pooling","abbr":null,"category":"AI/ML","definition":"Randomly selecting activations for pooling with probability. Stochastic pooling provides regularization.","related":["Pooling","Regularization"]},{"term":"Adaptive Average Pooling","abbr":null,"category":"AI/ML","definition":"Average pooling adapting to produce fixed output size. Adaptive pooling enables variable input sizes.","related":["Average Pooling","Pooling"]},{"term":"Adaptive Max Pooling","abbr":null,"category":"AI/ML","definition":"Max pooling adapting to produce fixed output size. Adaptive pooling handles variable inputs.","related":["Max Pooling","Pooling"]},{"term":"Global Average Pooling","abbr":null,"category":"AI/ML","definition":"Averaging entire feature map to single value. Global average pooling reduces computation.","related":["Average Pooling","Model Compression"]},{"term":"Global Max Pooling","abbr":null,"category":"AI/ML","definition":"Taking maximum across entire feature map. Global max pooling extracts most salient features.","related":["Max Pooling","Pooling"]},{"term":"Oversampling","abbr":null,"category":"AI/ML","definition":"Duplicating minority class samples to balance datasets. Oversampling can cause overfitting.","related":["Class Imbalance","Sampling","Data Preprocessing"]},{"term":"Undersampling","abbr":null,"category":"AI/ML","definition":"Removing majority class samples to balance datasets. Undersampling loses information.","related":["Class Imbalance","Sampling"]},{"term":"SMOTE","abbr":null,"category":"AI/ML","definition":"Synthetic Minority Oversampling Technique creating synthetic minority samples. SMOTE balances without duplication.","related":["Oversampling","Class Imbalance"]},{"term":"ADASYN","abbr":null,"category":"AI/ML","definition":"Adaptive Synthetic Sampling generating samples adaptively. ADASYN focuses on harder minority examples.","related":["SMOTE","Class Imbalance"]},{"term":"Stratified Sampling","abbr":null,"category":"AI/ML","definition":"Sampling maintaining class distribution in subsets. Stratified sampling preserves balance.","related":["Sampling","Cross-Validation"]},{"term":"Stratified K-Fold","abbr":null,"category":"AI/ML","definition":"K-fold cross-validation preserving class distribution in each fold. Stratified K-fold is important for imbalanced data.","related":["Cross-Validation","Stratified Sampling"]},{"term":"Importance Sampling","abbr":null,"category":"AI/ML","definition":"Sampling from different distributions to estimate expectations. Importance sampling is used in variational inference.","related":["Sampling","Variational Inference"]},{"term":"Rejection Sampling","abbr":null,"category":"AI/ML","definition":"Sampling from complex distributions by accepting/rejecting proposals. Rejection sampling is simple but inefficient.","related":["Sampling","Probabilistic Model"]},{"term":"Gibbs Sampling","abbr":null,"category":"AI/ML","definition":"Sampling from multivariate distributions by sampling conditionals. Gibbs sampling is a MCMC method.","related":["MCMC","Sampling"]},{"term":"Metropolis-Hastings","abbr":null,"category":"AI/ML","definition":"An MCMC algorithm using proposal distributions and acceptance ratios. Metropolis-Hastings is general and powerful.","related":["MCMC","Sampling"]},{"term":"Eigenvalue Decomposition","abbr":null,"category":"AI/ML","definition":"Decomposing matrices into eigenvalues and eigenvectors. Eigendecomposition reveals matrix structure.","related":["Linear Algebra","Matrix Factorization"]},{"term":"Cholesky Decomposition","abbr":null,"category":"AI/ML","definition":"Decomposing positive definite matrices into triangular factors. Cholesky is efficient for solving linear systems.","related":["Matrix Decomposition","Linear Algebra"]},{"term":"QR Decomposition","abbr":null,"category":"AI/ML","definition":"Decomposing matrices into orthogonal and triangular factors. QR is used for solving least squares problems.","related":["Matrix Decomposition","Linear Algebra"]},{"term":"Tensor Decomposition","abbr":null,"category":"AI/ML","definition":"Decomposing multi-dimensional tensors. Tensor decomposition generalizes matrix factorization.","related":["Matrix Factorization","Dimensionality Reduction"]},{"term":"Tucker Decomposition","abbr":null,"category":"AI/ML","definition":"A tensor decomposition generalizing SVD to multiple dimensions. Tucker decomposition preserves structure.","related":["Tensor Decomposition"]},{"term":"CP Decomposition","abbr":null,"category":"AI/ML","definition":"CANDECOMP/PARAFAC decomposition factorizing tensors as sums of rank-1 tensors. CP is interpretable.","related":["Tensor Decomposition"]},{"term":"Kronecker Product","abbr":null,"category":"AI/ML","definition":"A matrix operation combining two matrices. Kronecker product is used in multi-task learning.","related":["Matrix Operations","Linear Algebra"]},{"term":"Trace","abbr":null,"category":"AI/ML","definition":"The sum of diagonal elements of a matrix. Trace is used in loss functions and analysis.","related":["Matrix Operations"]},{"term":"Frobenius Norm","abbr":null,"category":"AI/ML","definition":"The Euclidean norm of a matrix treating it as vector. Frobenius norm measures matrix size.","related":["Matrix Operations","Norm"]},{"term":"Spectral Norm","abbr":null,"category":"AI/ML","definition":"The largest singular value of a matrix. Spectral norm bounds matrix-vector products.","related":["Matrix Operations","Singular Value"]},{"term":"Adadelta","abbr":null,"category":"AI/ML","definition":"An optimizer accumulating squared gradients like RMSprop but without learning rate. Adadelta adapts learning rate per dimension.","related":["Optimizer","Gradient Descent"]},{"term":"Adagrad","abbr":null,"category":"AI/ML","definition":"An optimizer with adaptive per-parameter learning rates. Adagrad penalizes frequently updated parameters.","related":["Optimizer","Gradient Descent"]},{"term":"RMSprop","abbr":null,"category":"AI/ML","definition":"Root Mean Square Propagation — an optimizer using exponential moving average of squared gradients. RMSprop adapts learning rate.","related":["Optimizer","Adam Optimizer"]},{"term":"Nadam","abbr":null,"category":"AI/ML","definition":"Nesterov-accelerated Adaptive Moment Estimation combining Nesterov and Adam. Nadam often converges faster.","related":["Adam Optimizer","Optimizer"]},{"term":"AdamW","abbr":null,"category":"AI/ML","definition":"Adam with decoupled weight decay fixing weight decay in Adam. AdamW improves generalization.","related":["Adam Optimizer","Weight Decay"]},{"term":"LAMB","abbr":null,"category":"AI/ML","definition":"Layer-wise Adaptive Moments optimizer for Batch training. LAMB enables large batch sizes.","related":["Optimizer","Distributed Training"]},{"term":"LARS","abbr":null,"category":"AI/ML","definition":"Layer-wise Adaptive Rate Scaling adjusting learning rates per layer. LARS enables large-batch training.","related":["Optimizer","Learning Rate"]},{"term":"RAdam","abbr":null,"category":"AI/ML","definition":"Rectified Adam with variance rectification in early training. RAdam addresses Adam's variance problem.","related":["Adam Optimizer","Optimizer"]},{"term":"MADGRAD","abbr":null,"category":"AI/ML","definition":"An optimizer using gradient moments and variance. MADGRAD is effective for deep learning.","related":["Optimizer","Gradient Descent"]},{"term":"Lookahead","abbr":null,"category":"AI/ML","definition":"A meta-optimizer that maintains fast and slow weights. Lookahead improves convergence.","related":["Optimizer","Meta-Learning"]},{"term":"Data Parallelism","abbr":null,"category":"AI/ML","definition":"Distributing training data across devices computing gradients independently. Data parallelism is simple but communication-heavy.","related":["Distributed Training","Model Parallelism"]},{"term":"Model Parallelism","abbr":null,"category":"AI/ML","definition":"Splitting model across devices enabling training of larger models. Model parallelism reduces memory per device.","related":["Distributed Training","Data Parallelism"]},{"term":"Pipeline Parallelism","abbr":null,"category":"AI/ML","definition":"Distributing model layers across devices and pipelining batches. Pipeline parallelism improves utilization.","related":["Model Parallelism","Distributed Training"]},{"term":"Ring AllReduce","abbr":null,"category":"AI/ML","definition":"An efficient collective communication pattern for distributed training. Ring AllReduce reduces communication overhead.","related":["Distributed Training","Communication"]},{"term":"Gradient Accumulation","abbr":null,"category":"AI/ML","definition":"Accumulating gradients over multiple batches before update. Gradient accumulation enables larger effective batch sizes.","related":["Optimization","Training"]},{"term":"Mixed Precision Training","abbr":null,"category":"AI/ML","definition":"Using lower precision (float16) for speed and memory with float32 for stability. Mixed precision accelerates training.","related":["Distributed Training","Quantization"]},{"term":"Automatic Mixed Precision","abbr":"AMP","category":"AI/ML","definition":"Automatically using mixed precision during training. AMP is convenient for efficient training.","related":["Mixed Precision Training","Optimization"]},{"term":"Gradient Checkpointing","abbr":null,"category":"AI/ML","definition":"Trading computation for memory by recomputing activations. Gradient checkpointing enables training with limited memory.","related":["Memory Efficiency","Training"]},{"term":"ZeRO","abbr":null,"category":"AI/ML","definition":"Zero Redundancy Optimizer partitioning parameters, gradients and optimizers. ZeRO drastically reduces memory.","related":["Memory Efficiency","Distributed Training"]},{"term":"Pascal VOC","abbr":null,"category":"AI/ML","definition":"Pascal Visual Object Classes dataset with object detection and segmentation annotations. Pascal VOC was influential for object detection.","related":["Benchmark Dataset","Object Detection"]},{"term":"MS COCO","abbr":null,"category":"AI/ML","definition":"Microsoft Common Objects in Context dataset. MS COCO is the standard for object detection.","related":["COCO Dataset","Benchmark Dataset"]},{"term":"CityScapes","abbr":null,"category":"AI/ML","definition":"A dataset for urban scene understanding with semantic segmentation labels. Cityscape is used for autonomous driving research.","related":["Semantic Segmentation","Benchmark Dataset"]},{"term":"ADE20K","abbr":null,"category":"AI/ML","definition":"A large-scale scene parsing dataset with semantic segmentation. ADE20K has diverse scenes and objects.","related":["Semantic Segmentation","Benchmark Dataset"]},{"term":"Places","abbr":null,"category":"AI/ML","definition":"A large-scale scene understanding dataset with 365 place categories. Places enables scene classification.","related":["Image Classification","Benchmark Dataset"]},{"term":"Kinetics","abbr":null,"category":"AI/ML","definition":"A large-scale video action dataset with millions of videos. Kinetics is standard for action recognition.","related":["Action Recognition","Benchmark Dataset"]},{"term":"UCF101","abbr":null,"category":"AI/ML","definition":"A dataset of 101 action categories in videos. UCF101 is a popular action recognition benchmark.","related":["Action Recognition","Benchmark Dataset"]},{"term":"ActivityNet","abbr":null,"category":"AI/ML","definition":"A large-scale video understanding dataset with temporal annotations. ActivityNet includes action localization.","related":["Video Understanding","Benchmark Dataset"]},{"term":"VCR","abbr":null,"category":"AI/ML","definition":"Visual Commonsense Reasoning dataset for reasoning about images. VCR tests visual understanding.","related":["Visual Question Answering","Benchmark Dataset"]},{"term":"WebVision","abbr":null,"category":"AI/ML","definition":"A web-scale weakly-supervised dataset for image classification. WebVision tests learning from noisy labels.","related":["Image Classification","Benchmark Dataset"]},{"term":"Open Images","abbr":null,"category":"AI/ML","definition":"A large-scale dataset with diverse images and annotations. Open Images includes detection, segmentation and more.","related":["Benchmark Dataset","Computer Vision"]},{"term":"WikiText","abbr":null,"category":"AI/ML","definition":"A language modeling dataset from Wikipedia. WikiText is used for evaluating language models.","related":["Language Modeling","Benchmark Dataset"]},{"term":"GLUE","abbr":null,"category":"AI/ML","definition":"General Language Understanding Evaluation benchmark. GLUE evaluates language understanding models.","related":["Language Understanding","Benchmark Dataset"]},{"term":"SuperGLUE","abbr":null,"category":"AI/ML","definition":"A harder version of GLUE with more challenging tasks. SuperGLUE tests advanced understanding.","related":["GLUE","Benchmark Dataset"]},{"term":"MMLU","abbr":null,"category":"AI/ML","definition":"Massive Multitask Language Understanding evaluating knowledge. MMLU tests broad knowledge across domains.","related":["Benchmark Dataset","Knowledge"]},{"term":"Integer Quantization","abbr":null,"category":"AI/ML","definition":"Quantizing to integer representations (typically int8). Integer quantization enables efficient inference.","related":["Quantization","Model Compression"]},{"term":"Post-Training Quantization","abbr":null,"category":"AI/ML","definition":"Quantizing models after training without retraining. Post-training quantization is fast but less accurate.","related":["Quantization"]},{"term":"Quantization-Aware Training","abbr":"QAT","category":"AI/ML","definition":"Training with quantization simulated to adapt to lower precision. QAT maintains accuracy better.","related":["Quantization","Training"]},{"term":"Symmetric Quantization","abbr":null,"category":"AI/ML","definition":"Quantizing with symmetric ranges around zero. Symmetric quantization is simpler but less efficient.","related":["Quantization"]},{"term":"Asymmetric Quantization","abbr":null,"category":"AI/ML","definition":"Quantizing with asymmetric ranges maximizing precision. Asymmetric quantization is more efficient.","related":["Quantization"]},{"term":"Per-Channel Quantization","abbr":null,"category":"AI/ML","definition":"Quantizing each channel independently. Per-channel quantization preserves fine-grained information.","related":["Quantization"]},{"term":"Per-Layer Quantization","abbr":null,"category":"AI/ML","definition":"Quantizing entire layers uniformly. Per-layer quantization is simpler but coarser.","related":["Quantization"]},{"term":"Magnitude Pruning","abbr":null,"category":"AI/ML","definition":"Removing weights with small magnitudes. Magnitude pruning is simple and effective.","related":["Pruning","Model Compression"]},{"term":"Structured Pruning","abbr":null,"category":"AI/ML","definition":"Pruning entire channels or filters for hardware efficiency. Structured pruning maintains speedups.","related":["Pruning","Model Compression"]},{"term":"Unstructured Pruning","abbr":null,"category":"AI/ML","definition":"Pruning individual weights for compression. Unstructured pruning reduces size but not speed.","related":["Pruning","Model Compression"]},{"term":"Lottery Ticket Hypothesis","abbr":null,"category":"AI/ML","definition":"A hypothesis that pruned subnetworks can match full network performance. Lottery tickets suggest networks are overparameterized.","related":["Pruning","Model Compression"]},{"term":"Voting Ensemble","abbr":null,"category":"AI/ML","definition":"Combining predictions through voting (majority or weighted). Voting is simple ensemble method.","related":["Ensemble Learning"]},{"term":"Averaging Ensemble","abbr":null,"category":"AI/ML","definition":"Averaging predictions from multiple models. Averaging works well for regression.","related":["Ensemble Learning"]},{"term":"Stacking","abbr":null,"category":"AI/ML","definition":"Training a meta-learner on predictions of base learners. Stacking leverages complementary models.","related":["Ensemble Learning"]},{"term":"Blending","abbr":null,"category":"AI/ML","definition":"A simplified stacking using holdout set instead of cross-validation. Blending is faster than stacking.","related":["Stacking","Ensemble Learning"]},{"term":"Snapshot Ensemble","abbr":null,"category":"AI/ML","definition":"Saving models at different learning rate cycles. Snapshot ensemble uses multiple local minima.","related":["Ensemble Learning","Learning Rate Scheduling"]},{"term":"Multi-Loss Ensembling","abbr":null,"category":"AI/ML","definition":"Training models with different loss functions and ensembling. Multi-loss provides diverse predictions.","related":["Ensemble Learning","Loss Function"]},{"term":"Recommendation Engine","abbr":null,"category":"AI/ML","definition":"A system recommending items to users. Recommendation engines are crucial for platforms.","related":["Recommendation System","Collaborative Filtering"]},{"term":"Click-Through Rate Prediction","abbr":"CTR Prediction","category":"AI/ML","definition":"Predicting probability users click ads. CTR prediction is important for advertising.","related":["Classification","Prediction"]},{"term":"Churn Prediction","abbr":null,"category":"AI/ML","definition":"Predicting which customers will leave. Churn prediction enables retention strategies.","related":["Prediction","Business Analytics"]},{"term":"Next-Item Prediction","abbr":null,"category":"AI/ML","definition":"Predicting next item user will interact with. Next-item prediction is fundamental for recommendations.","related":["Recommendation System","Sequence Prediction"]},{"term":"User Segmentation","abbr":null,"category":"AI/ML","definition":"Dividing users into groups for targeting. User segmentation enables personalization.","related":["Clustering","Business Analytics"]},{"term":"Customer Lifetime Value","abbr":"CLV","category":"AI/ML","definition":"Predicting total revenue from a customer. CLV prediction guides marketing investment.","related":["Prediction","Business Analytics"]},{"term":"Propensity Modeling","abbr":null,"category":"AI/ML","definition":"Predicting likelihood customers perform actions. Propensity models guide targeting.","related":["Prediction","Classification"]},{"term":"Attribution Modeling","abbr":null,"category":"AI/ML","definition":"Assigning credit to marketing touchpoints. Attribution models guide budget allocation.","related":["Causal Inference","Business Analytics"]},{"term":"Demand Forecasting","abbr":null,"category":"AI/ML","definition":"Predicting future demand for products. Demand forecasting optimizes inventory.","related":["Time Series Prediction","Forecasting"]},{"term":"Supply Chain Optimization","abbr":null,"category":"AI/ML","definition":"Optimizing logistics and supply chains. Supply chain optimization reduces costs.","related":["Optimization","Prediction"]},{"term":"FastText","abbr":null,"category":"AI/ML","definition":"An extension of Word2Vec handling out-of-vocabulary words. FastText learns character n-gram embeddings.","related":["Embedding","Word2Vec"]},{"term":"Sentence Embeddings","abbr":null,"category":"AI/ML","definition":"Dense vectors representing entire sentences. Sentence embeddings enable semantic comparison.","related":["Embedding","Natural Language Processing"]},{"term":"Document Embeddings","abbr":null,"category":"AI/ML","definition":"Dense vectors representing documents. Document embeddings enable document classification and clustering.","related":["Embedding","Doc2Vec"]},{"term":"Doc2Vec","abbr":null,"category":"AI/ML","definition":"An extension of Word2Vec to documents. Doc2Vec learns fixed-size document vectors.","related":["Word2Vec","Document Embeddings"]},{"term":"TransE","abbr":null,"category":"AI/ML","definition":"Translation-based knowledge graph embedding. TransE models relations as translations.","related":["Knowledge Graph Embedding"]},{"term":"Contextual Embeddings","abbr":null,"category":"AI/ML","definition":"Embeddings that vary based on context (unlike static embeddings). Contextual embeddings capture polysemy.","related":["Embedding","BERT","ELMo"]},{"term":"ELMo","abbr":null,"category":"AI/ML","definition":"Embeddings from Language Models using bidirectional LSTMs. ELMo learns contextualized representations.","related":["Contextual Embeddings","Language Model"]},{"term":"Static Embeddings","abbr":null,"category":"AI/ML","definition":"Fixed embeddings for each word regardless of context. Static embeddings are simple but limited.","related":["Embedding","Word2Vec"]},{"term":"Subword Embeddings","abbr":null,"category":"AI/ML","definition":"Embeddings at subword level (characters or BPE). Subword embeddings handle rare words.","related":["Embedding","Tokenization"]},{"term":"Cross-Lingual Embeddings","abbr":null,"category":"AI/ML","definition":"Embeddings spanning multiple languages in shared space. Cross-lingual embeddings enable multilingual tasks.","related":["Embedding","Machine Translation"]},{"term":"Bilingual Embeddings","abbr":null,"category":"AI/ML","definition":"Embeddings bridging two languages. Bilingual embeddings enable translation and transfer.","related":["Cross-Lingual Embeddings"]},{"term":"Residual Connections","abbr":null,"category":"AI/ML","definition":"Skip connections allowing information to bypass layers. Residual connections improve gradient flow.","related":["ResNet","Deep Learning"]},{"term":"Attention Head","abbr":null,"category":"AI/ML","definition":"A single attention mechanism in multi-head attention. Attention heads capture different representation aspects.","related":["Multi-Head Attention","Attention Mechanism"]},{"term":"Query-Key-Value","abbr":"QKV","category":"AI/ML","definition":"The three components of attention mechanism. QKV enables flexible attention computation.","related":["Attention Mechanism","Self-Attention"]},{"term":"Positional Encoding","abbr":null,"category":"AI/ML","definition":"Adding position information to embeddings in transformers. Positional encodings preserve order.","related":["Transformer","Embedding"]},{"term":"Absolute Positional Encoding","abbr":null,"category":"AI/ML","definition":"Encoding absolute positions in sequences. Absolute encoding is traditional but has length issues.","related":["Positional Encoding","Transformer"]},{"term":"Relative Positional Encoding","abbr":null,"category":"AI/ML","definition":"Encoding relative distances between positions. Relative encoding improves length generalization.","related":["Positional Encoding","Transformer"]},{"term":"Token Embedding","abbr":null,"category":"AI/ML","definition":"Converting tokens to dense vectors. Token embeddings are foundation for language models.","related":["Embedding","Tokenization"]},{"term":"Feed-Forward Network","abbr":null,"category":"AI/ML","definition":"Fully connected layers in transformer blocks. Feed-forward networks enable non-linearity.","related":["Transformer","Neural Network"]},{"term":"Sequence Masking","abbr":null,"category":"AI/ML","definition":"Preventing attention to future tokens (causal masking). Sequence masking enables autoregressive generation.","related":["Attention Mechanism","Autoregressive Model"]},{"term":"Causal Masking","abbr":null,"category":"AI/ML","definition":"Masking future positions in attention. Causal masking enforces left-to-right generation.","related":["Sequence Masking","Autoregressive Model"]},{"term":"Padding Masking","abbr":null,"category":"AI/ML","definition":"Masking padding tokens in attention. Padding masking prevents attending to padding.","related":["Sequence Masking","Attention Mechanism"]},{"term":"Layer Drop","abbr":null,"category":"AI/ML","definition":"Randomly dropping transformer layers during training. Layer drop is a regularization technique.","related":["Dropout","Regularization"]},{"term":"Encoder Stacking","abbr":null,"category":"AI/ML","definition":"Stacking multiple encoder layers. Encoder stacking increases model capacity.","related":["Transformer","Deep Learning"]},{"term":"Decoder Stacking","abbr":null,"category":"AI/ML","definition":"Stacking multiple decoder layers. Decoder stacking enables complex generation.","related":["Decoder","Transformer"]},{"term":"Double Descent","abbr":null,"category":"AI/ML","definition":"A phenomenon where test error decreases then increases with model complexity. Double descent challenges bias-variance tradeoff.","related":["Overfitting","Generalization"]},{"term":"Neural Collapse","abbr":null,"category":"AI/ML","definition":"A phenomenon where learned representations converge to structured geometry. Neural collapse enables generalization.","related":["Representation Learning","Deep Learning"]},{"term":"Feature Learning","abbr":null,"category":"AI/ML","definition":"Automatic discovery of useful features during training. Feature learning is fundamental to deep learning.","related":["Representation Learning","Deep Learning"]},{"term":"Grokking","abbr":null,"category":"AI/ML","definition":"A phenomenon where models suddenly generalize after long training. Grokking reveals phase transitions in learning.","related":["Generalization","Training"]},{"term":"Mode Connectivity","abbr":null,"category":"AI/ML","definition":"The existence of paths between high-performing solutions in loss landscape. Mode connectivity enables model merging.","related":["Loss Landscape","Optimization"]},{"term":"Loss Landscape","abbr":null,"category":"AI/ML","definition":"The visualization of loss function as function of parameters. Loss landscape reveals optimization geometry.","related":["Optimization","Convergence"]},{"term":"Lottery Ticket","abbr":null,"category":"AI/ML","definition":"A sparse subnetwork matching full network performance. Lottery tickets demonstrate overparameterization.","related":["Pruning","Sparse Model"]},{"term":"Critical Learning Period","abbr":null,"category":"AI/ML","definition":"A period where corrupting data training particularly hurts. Critical periods reveal learning dynamics.","related":["Training","Learning Theory"]},{"term":"Power Law Scaling","abbr":null,"category":"AI/ML","definition":"Loss decreasing as power law with more data/compute. Power laws guide resource allocation.","related":["Scaling Laws","Generalization"]},{"term":"Scaling Laws","abbr":null,"category":"AI/ML","definition":"Predictable relationships between model size, data and performance. Scaling laws guide model design.","related":["Power Law Scaling","Large Language Model"]},{"term":"Zero-Shot Evaluation","abbr":null,"category":"AI/ML","definition":"Evaluating models on tasks without any task-specific training. Zero-shot evaluation tests transfer.","related":["Zero-Shot Learning","Evaluation"]},{"term":"Few-Shot Evaluation","abbr":null,"category":"AI/ML","definition":"Evaluating models with minimal task examples. Few-shot evaluation tests rapid adaptation.","related":["Few-Shot Learning","Evaluation"]},{"term":"In-Domain Evaluation","abbr":null,"category":"AI/ML","definition":"Testing on data from same distribution as training. In-domain evaluation measures fit to training distribution.","related":["Evaluation Metrics","Generalization"]},{"term":"Out-of-Domain Evaluation","abbr":null,"category":"AI/ML","definition":"Testing on different distribution than training. OOD evaluation measures robustness.","related":["Domain Adaptation","Evaluation"]},{"term":"Adversarial Evaluation","abbr":null,"category":"AI/ML","definition":"Testing with adversarially constructed examples. Adversarial evaluation reveals weaknesses.","related":["Adversarial Attack","Robustness"]},{"term":"Human Evaluation","abbr":null,"category":"AI/ML","definition":"Having humans rate model outputs. Human evaluation assesses quality beyond metrics.","related":["Evaluation Metrics"]},{"term":"Automatic Evaluation","abbr":null,"category":"AI/ML","definition":"Using metrics to automatically score model outputs. Automatic evaluation is scalable.","related":["Evaluation Metrics"]},{"term":"Crowdsourcing Evaluation","abbr":null,"category":"AI/ML","definition":"Using crowdworkers for large-scale evaluation. Crowdsourcing scales human evaluation.","related":["Human Evaluation"]},{"term":"Activation Analysis","abbr":null,"category":"AI/ML","definition":"Analyzing neuron activations to understand learned representations. Activation analysis aids debugging.","related":["Interpretability","Debugging"]},{"term":"Weight Analysis","abbr":null,"category":"AI/ML","definition":"Analyzing learned weights to understand model behavior. Weight analysis reveals learned patterns.","related":["Interpretability"]},{"term":"Gradient Analysis","abbr":null,"category":"AI/ML","definition":"Analyzing gradients during training. Gradient analysis reveals optimization issues.","related":["Backpropagation","Debugging"]},{"term":"Confusion Matrix Analysis","abbr":null,"category":"AI/ML","definition":"Detailed analysis of classification errors. Confusion matrix analysis identifies error patterns.","related":["Confusion Matrix","Error Analysis"]},{"term":"Error Analysis","abbr":null,"category":"AI/ML","definition":"Analyzing types and patterns of model errors. Error analysis guides improvements.","related":["Debugging","Model Evaluation"]},{"term":"Ablation Study","abbr":null,"category":"AI/ML","definition":"Removing components to measure their contribution. Ablation studies reveal important components.","related":["Evaluation","Debugging"]},{"term":"Sensitivity Analysis","abbr":null,"category":"AI/ML","definition":"Measuring how output changes with input variations. Sensitivity analysis reveals robustness.","related":["Robustness","Evaluation"]},{"term":"Hyperparameter Importance","abbr":null,"category":"AI/ML","definition":"Ranking hyperparameters by their impact on performance. Hyperparameter importance guides tuning.","related":["Hyperparameter Tuning","AutoML"]},{"term":"Feature Importance Ranking","abbr":null,"category":"AI/ML","definition":"Ranking features by their contribution to predictions. Feature importance ranks reveal influential features.","related":["Feature Importance","Interpretability"]},{"term":"Learning Curves","abbr":null,"category":"AI/ML","definition":"Plots of performance vs training set size. Learning curves diagnose overfitting vs underfitting.","related":["Overfitting","Underfitting"]},{"term":"Bottleneck Layer","abbr":null,"category":"AI/ML","definition":"A layer with fewer units reducing dimensionality. Bottleneck layers compress information.","related":["Neural Network","Dimensionality Reduction"]},{"term":"Squeeze-and-Excitation Block","abbr":null,"category":"AI/ML","definition":"A module adaptively recalibrating channel feature maps. SE blocks improve feature relevance.","related":["Attention Mechanism","Neural Network"]},{"term":"Inception Module","abbr":null,"category":"AI/ML","definition":"A network component with parallel paths of different sizes. Inception modules capture multi-scale features.","related":["Convolutional Neural Network","GoogLeNet"]},{"term":"Residual Block","abbr":null,"category":"AI/ML","definition":"A block with skip connection enabling deep networks. Residual blocks solve vanishing gradient.","related":["ResNet","Deep Learning"]},{"term":"Dense Block","abbr":null,"category":"AI/ML","definition":"A block where each layer connects to all preceding layers. Dense blocks encourage feature reuse.","related":["DenseNet","Neural Network"]},{"term":"Fire Module","abbr":null,"category":"AI/ML","definition":"A small module in SqueezeNet with squeeze and expand. Fire modules reduce parameters.","related":["SqueezeNet","Model Compression"]},{"term":"Depthwise Separable Block","abbr":null,"category":"AI/ML","definition":"A block combining depthwise and pointwise convolutions. Depthwise-separable blocks are efficient.","related":["MobileNet","Efficient Architecture"]},{"term":"Inverted Residual Block","abbr":null,"category":"AI/ML","definition":"A residual block with wide intermediate layers. Inverted blocks are used in MobileNetV2.","related":["MobileNet","Residual Block"]},{"term":"Transformer Block","abbr":null,"category":"AI/ML","definition":"A block with self-attention and feed-forward layers. Transformer blocks are units of transformers.","related":["Transformer","Self-Attention"]},{"term":"LSTM Cell","abbr":null,"category":"AI/ML","definition":"The fundamental unit of LSTM networks. LSTM cells enable learning long-term dependencies.","related":["LSTM","Recurrent Neural Network"]},{"term":"Curriculum Learning","abbr":null,"category":"AI/ML","definition":"Training on easier examples first then harder ones. Curriculum learning accelerates convergence.","related":["Training","Sample Ordering"]},{"term":"Hard Example Mining","abbr":null,"category":"AI/ML","definition":"Focusing training on difficult examples. Hard mining improves learning.","related":["Training","Sample Selection"]},{"term":"Active Learning","abbr":null,"category":"AI/ML","definition":"Selecting most informative unlabeled examples for labeling. Active learning reduces annotation cost.","related":["Semi-Supervised Learning","Sampling"]},{"term":"Continual Learning","abbr":null,"category":"AI/ML","definition":"Learning from sequential tasks without forgetting previous ones. Continual learning prevents catastrophic forgetting.","related":["Lifelong Learning","Transfer Learning"]},{"term":"Lifelong Learning","abbr":null,"category":"AI/ML","definition":"Learning continuously from new experiences. Lifelong learning mimics human learning.","related":["Continual Learning","Transfer Learning"]},{"term":"Meta-Learning Training","abbr":null,"category":"AI/ML","definition":"Training to learn how to learn quickly. Meta-training enables few-shot adaptation.","related":["Meta-Learning","Transfer Learning"]},{"term":"Multi-Task Learning Training","abbr":null,"category":"AI/ML","definition":"Training on multiple related tasks simultaneously. Multi-task training improves generalization.","related":["Transfer Learning","Regularization"]},{"term":"Self-Training","abbr":null,"category":"AI/ML","definition":"Using model predictions on unlabeled data as labels. Self-training leverages unlabeled data.","related":["Semi-Supervised Learning","Pseudo-Labeling"]},{"term":"Pseudo-Labeling","abbr":null,"category":"AI/ML","definition":"Assigning predicted labels to unlabeled data. Pseudo-labels boost semi-supervised learning.","related":["Self-Training","Semi-Supervised Learning"]},{"term":"Teacher-Student Training","abbr":null,"category":"AI/ML","definition":"Having student model learn from teacher model. Teacher-student enables knowledge transfer.","related":["Knowledge Distillation","Transfer Learning"]},{"term":"Machine Reading Comprehension","abbr":"MRC","category":"AI/ML","definition":"A task where systems answer questions about text passages. MRC tests comprehension abilities.","related":["Question Answering","Natural Language Processing"]},{"term":"Natural Language Inference Task","abbr":null,"category":"AI/ML","definition":"Tasks testing logical reasoning over text. NLI tasks evaluate reasoning capabilities.","related":["Textual Entailment","Natural Language Processing"]},{"term":"Semantic Textual Similarity Task","abbr":"STS","category":"AI/ML","definition":"A task evaluating semantic similarity between sentence pairs. STS measures understanding.","related":["Semantic Similarity","Natural Language Processing"]},{"term":"Visual Question Answering Task","abbr":null,"category":"AI/ML","definition":"Answering free-form questions about images. VQA tests vision-language understanding.","related":["Visual Question Answering","Multimodal Learning"]},{"term":"Image-Text Matching","abbr":null,"category":"AI/ML","definition":"Matching images with descriptions or captions. Image-text matching tests multimodal alignment.","related":["Vision-Language Model","Multimodal Learning"]},{"term":"Video Understanding","abbr":null,"category":"AI/ML","definition":"Comprehensive understanding of video content. Video understanding combines spatial and temporal.","related":["Action Recognition","Computer Vision"]},{"term":"Temporal Action Localization","abbr":null,"category":"AI/ML","definition":"Finding when actions occur in videos. Temporal localization enables action understanding.","related":["Action Recognition","Video Understanding"]},{"term":"Phrase Localization","abbr":null,"category":"AI/ML","definition":"Localizing objects matching text descriptions. Phrase localization tests grounding.","related":["Vision-Language Model","Object Detection"]},{"term":"Compositional Reasoning","abbr":null,"category":"AI/ML","definition":"Reasoning about novel combinations of known concepts. Compositional reasoning tests generalization.","related":["Visual Reasoning","Compositionality"]},{"term":"Commonsense Reasoning","abbr":null,"category":"AI/ML","definition":"Reasoning requiring world knowledge and common sense. Commonsense reasoning is challenging.","related":["Reasoning","Knowledge"]},{"term":"Physics-Informed Neural Networks","abbr":"PINN","category":"AI/ML","definition":"Neural networks trained with physics constraints. PINNs solve differential equations.","related":["Deep Learning","Scientific Computing"]},{"term":"Scientific Machine Learning","abbr":null,"category":"AI/ML","definition":"Applying machine learning to scientific problems. Scientific ML accelerates discovery.","related":["Deep Learning","Scientific Computing"]},{"term":"Molecular Modeling","abbr":null,"category":"AI/ML","definition":"Using machine learning for molecular properties and interactions. Molecular ML aids drug discovery.","related":["Graph Neural Network","Drug Discovery"]},{"term":"Protein Folding Prediction","abbr":null,"category":"AI/ML","definition":"Predicting 3D structure of proteins. Protein folding is solved by AlphaFold.","related":["Sequence Modeling","Protein Structure Prediction"]},{"term":"Molecular Property Prediction","abbr":null,"category":"AI/ML","definition":"Predicting chemical properties of molecules. Property prediction guides drug design.","related":["Molecular Modeling","Regression"]},{"term":"Quantum Machine Learning","abbr":null,"category":"AI/ML","definition":"Using quantum computers for machine learning. Quantum ML is an emerging field.","related":["Machine Learning","Quantum Computing"]},{"term":"Climate Modeling with AI","abbr":null,"category":"AI/ML","definition":"Using machine learning for climate simulation. AI speeds up climate models.","related":["Deep Learning","Scientific Computing"]},{"term":"Materials Discovery","abbr":null,"category":"AI/ML","definition":"Using machine learning to discover new materials. ML accelerates materials science.","related":["Graph Neural Network","Property Prediction"]},{"term":"Kernel Density Estimation","abbr":null,"category":"AI/ML","definition":"Estimating probability density from samples. Kernel estimation is non-parametric.","related":["Density Estimation","Non-Parametric Methods"]},{"term":"Mixture Model","abbr":null,"category":"AI/ML","definition":"A probabilistic model of mixture of distributions. Mixture models enable flexible modeling.","related":["Probabilistic Model","Gaussian Mixture Model"]},{"term":"Dirichlet Distribution","abbr":null,"category":"AI/ML","definition":"A distribution over probability distributions. Dirichlet is used in topic models.","related":["Probabilistic Model","Topic Modeling"]},{"term":"Latent Factor Model","abbr":null,"category":"AI/ML","definition":"A model using latent factors to explain observations. Latent factors enable dimensionality reduction.","related":["Factor Analysis","Dimensionality Reduction"]},{"term":"Factor Analysis","abbr":null,"category":"AI/ML","definition":"Assuming data comes from latent factors plus noise. Factor analysis is probabilistic PCA.","related":["PCA","Dimensionality Reduction"]},{"term":"Independent Component Analysis","abbr":"ICA","category":"AI/ML","definition":"Separating mixed signals into independent components. ICA is used for blind source separation.","related":["Dimensionality Reduction","Signal Processing"]},{"term":"Manifold Learning","abbr":null,"category":"AI/ML","definition":"Assuming high-dimensional data lies on lower-dimensional manifold. Manifold learning enables meaningful dimensionality reduction.","related":["Dimensionality Reduction","Non-Linear Methods"]},{"term":"Isomap","abbr":null,"category":"AI/ML","definition":"Isometric feature mapping preserving geodesic distances. Isomap discovers manifolds.","related":["Manifold Learning","Dimensionality Reduction"]},{"term":"Locally Linear Embedding","abbr":"LLE","category":"AI/ML","definition":"A manifold learning technique preserving local neighborhoods. LLE recovers manifold structure.","related":["Manifold Learning","Dimensionality Reduction"]},{"term":"Spectral Clustering","abbr":null,"category":"AI/ML","definition":"A clustering approach using spectral decomposition of similarity matrix. Spectral clustering finds non-convex clusters.","related":["Clustering","Spectral Methods"]},{"term":"Affinity Propagation","abbr":null,"category":"AI/ML","definition":"A clustering algorithm finding exemplars through message passing. Affinity propagation is unsupervised exemplar selection.","related":["Clustering","Graph-Based Methods"]},{"term":"Mean Shift Clustering","abbr":null,"category":"AI/ML","definition":"A clustering approach finding modes of density. Mean shift discovers natural clusters.","related":["Clustering","Density-Based Methods"]},{"term":"Agglomerative Clustering","abbr":null,"category":"AI/ML","definition":"Bottom-up hierarchical clustering merging closest clusters. Agglomerative clustering builds dendrograms.","related":["Hierarchical Clustering","Clustering"]},{"term":"Divisive Clustering","abbr":null,"category":"AI/ML","definition":"Top-down hierarchical clustering recursively splitting. Divisive clustering is less common.","related":["Hierarchical Clustering","Clustering"]},{"term":"Silhouette Score","abbr":null,"category":"AI/ML","definition":"A metric measuring cluster cohesion and separation. Silhouette score guides cluster number selection.","related":["Clustering Evaluation","Clustering"]},{"term":"Davies-Bouldin Index","abbr":null,"category":"AI/ML","definition":"A metric comparing within-cluster and between-cluster distances. Davies-Bouldin evaluates clustering quality.","related":["Clustering Evaluation","Clustering"]},{"term":"Calinski-Harabasz Index","abbr":null,"category":"AI/ML","definition":"A metric computing ratio of between-cluster to within-cluster variance. Calinski-Harabasz evaluates separation.","related":["Clustering Evaluation","Clustering"]},{"term":"Dunn Index","abbr":null,"category":"AI/ML","definition":"A metric measuring minimum inter-cluster distance to maximum intra-cluster distance. Dunn index evaluates cluster quality.","related":["Clustering Evaluation","Clustering"]},{"term":"Adjusted Rand Index","abbr":"ARI","category":"AI/ML","definition":"A similarity measure between clusterings correcting for chance. ARI compares clustering solutions.","related":["Clustering Evaluation","Clustering"]},{"term":"Cloud Computing","abbr":null,"category":"Cloud Providers","definition":"The on-demand delivery of computing resources — servers, storage, databases, networking and software — over the internet with pay-as-you-go pricing.","related":["IaaS","PaaS","SaaS","Public Cloud"]},{"term":"IaaS","abbr":"IaaS","category":"Cloud Providers","definition":"Infrastructure as a Service — cloud delivery of fundamental compute, storage and networking resources that customers manage and build on (e.g., EC2).","related":["PaaS","SaaS","Virtual Machine"]},{"term":"PaaS","abbr":"PaaS","category":"Cloud Providers","definition":"Platform as a Service — a cloud model providing a managed platform (runtime, middleware, tooling) so developers deploy apps without managing infrastructure.","related":["IaaS","SaaS","Serverless"]},{"term":"SaaS","abbr":"SaaS","category":"Cloud Providers","definition":"Software as a Service — fully managed applications delivered over the internet on subscription, with the provider handling all infrastructure and maintenance.","related":["PaaS","IaaS","Multitenancy"]},{"term":"Public Cloud","abbr":null,"category":"Cloud Providers","definition":"Cloud infrastructure owned and operated by a third-party provider (AWS, Azure, GCP) and shared among many customers over the internet.","related":["Private Cloud","Hybrid Cloud","Cloud Computing"]},{"term":"Private Cloud","abbr":null,"category":"Cloud Providers","definition":"Cloud infrastructure dedicated to a single organization, hosted on-premises or by a provider, offering more control and isolation.","related":["Public Cloud","Hybrid Cloud"]},{"term":"Hybrid Cloud","abbr":null,"category":"Cloud Providers","definition":"An environment combining public and private cloud (and/or on-prem) with orchestration between them, balancing flexibility, control and cost.","related":["Public Cloud","Private Cloud","Multicloud"]},{"term":"Multicloud","abbr":null,"category":"Cloud Providers","definition":"Using services from more than one cloud provider, to avoid lock-in, optimize cost/performance, or meet regulatory needs.","related":["Hybrid Cloud","Public Cloud","Cloud Agnostic"]},{"term":"Region","abbr":null,"category":"Cloud Providers","definition":"A geographic area where a cloud provider clusters data centers; choosing regions affects latency, cost, compliance and availability.","related":["Availability Zone","Edge Computing","Latency"]},{"term":"Availability Zone","abbr":"AZ","category":"Cloud Providers","definition":"An isolated location within a cloud region with independent power and networking; deploying across AZs improves fault tolerance.","related":["Region","High Availability","Failover"]},{"term":"Elasticity","abbr":null,"category":"Cloud Providers","definition":"The ability to automatically scale resources up and down to match demand, a defining benefit of cloud over fixed capacity.","related":["Auto-Scaling","Scalability","Pay-As-You-Go"]},{"term":"Pay-As-You-Go","abbr":null,"category":"Cloud Providers","definition":"A pricing model where customers pay only for the resources they actually consume, aligning cost with usage.","related":["Elasticity","FinOps","Reserved Instance"]},{"term":"FinOps","abbr":null,"category":"Cloud Providers","definition":"A practice combining finance and operations to manage and optimize cloud spending through visibility, accountability and continuous cost optimization.","related":["Cost Optimization","Pay-As-You-Go","Showback"]},{"term":"Cost Optimization","abbr":null,"category":"Cloud Providers","definition":"Reducing cloud spend without sacrificing performance, via right-sizing, reserved capacity, autoscaling and eliminating waste.","related":["FinOps","Right-Sizing","Reserved Instance"]},{"term":"Right-Sizing","abbr":null,"category":"Cloud Providers","definition":"Matching resource allocation (instance type, size) to actual workload needs to avoid paying for unused capacity.","related":["Cost Optimization","Vertical Pod Autoscaler","Capacity Planning"]},{"term":"Reserved Instance","abbr":"RI","category":"Cloud Providers","definition":"A pricing commitment that reserves cloud capacity for a term (1–3 years) at a discount versus on-demand, lowering cost for steady workloads.","related":["Pay-As-You-Go","Spot Instance","Cost Optimization"]},{"term":"Spot Instance","abbr":null,"category":"Cloud Providers","definition":"Discounted, interruptible cloud compute capacity that the provider can reclaim with short notice, ideal for fault-tolerant, flexible workloads.","related":["Reserved Instance","Cost Optimization","Auto-Scaling"]},{"term":"Virtual Machine","abbr":"VM","category":"Cloud Providers","definition":"A software emulation of a physical computer that runs its own OS on shared hardware via a hypervisor, the building block of IaaS.","related":["Hypervisor","IaaS","Bare Metal Machine","Container"]},{"term":"Hypervisor","abbr":null,"category":"Cloud Providers","definition":"Software that creates and runs virtual machines by abstracting and allocating physical hardware among multiple guest operating systems.","related":["Virtual Machine","Virtualization","Bare Metal Machine"]},{"term":"Virtualization","abbr":null,"category":"Cloud Providers","definition":"Creating virtual versions of computing resources (servers, storage, networks) to increase utilization, isolation and flexibility.","related":["Hypervisor","Virtual Machine","Containerization"]},{"term":"Bare Metal Machine","abbr":null,"category":"Cloud Providers","definition":"A physical server dedicated to a single tenant without a hypervisor layer, offering maximum performance and control.","related":["Virtual Machine","Hypervisor"]},{"term":"Amazon EC2","abbr":"EC2","category":"Cloud Providers","definition":"Amazon Elastic Compute Cloud — AWS's core IaaS offering resizable virtual machine instances on demand.","related":["IaaS","Virtual Machine","Auto Scaling Group"]},{"term":"AWS Lambda","abbr":null,"category":"Cloud Providers","definition":"AWS's serverless function-as-a-service that runs code in response to events, scaling automatically and billing per invocation and duration.","related":["Serverless","Function as a Service","Cold Start"]},{"term":"Amazon S3","abbr":"S3","category":"Cloud Providers","definition":"Amazon Simple Storage Service — a highly durable, scalable object-storage service widely used for data lakes, backups and static assets.","related":["Object Storage","Data Lake","Storage Bucket"]},{"term":"Storage Bucket","abbr":null,"category":"Cloud Providers","definition":"A top-level container for objects in cloud object storage (e.g., S3 or GCS), with its own name, permissions and configuration.","related":["Amazon S3","Object Storage"]},{"term":"Amazon RDS","abbr":"RDS","category":"Cloud Providers","definition":"Amazon Relational Database Service — a managed service that runs relational databases (PostgreSQL, MySQL, etc.) with automated backups, patching and scaling.","related":["Relational Database","Managed Service","Read Replica"]},{"term":"Amazon EKS","abbr":"EKS","category":"Cloud Providers","definition":"Amazon Elastic Kubernetes Service — AWS's managed Kubernetes control plane, removing the burden of operating Kubernetes masters.","related":["Kubernetes","Managed Service","GKE","AKS"]},{"term":"GKE","abbr":"GKE","category":"Cloud Providers","definition":"Google Kubernetes Engine — Google Cloud's managed Kubernetes service, known for deep integration and autopilot operation modes.","related":["Kubernetes","Amazon EKS","AKS"]},{"term":"AKS","abbr":"AKS","category":"Cloud Providers","definition":"Azure Kubernetes Service — Microsoft Azure's managed Kubernetes offering.","related":["Kubernetes","Amazon EKS","GKE"]},{"term":"Amazon CloudWatch","abbr":null,"category":"Cloud Providers","definition":"AWS's native monitoring and observability service for metrics, logs, alarms and dashboards across AWS resources and applications.","related":["Infrastructure Monitoring","Cloud Monitoring","Alerting"]},{"term":"AWS CloudTrail","abbr":null,"category":"Cloud Providers","definition":"An AWS service that records account activity and API calls as audit events for governance, compliance and security investigation.","related":["Audit Log","Compliance","Forensics"]},{"term":"VPC","abbr":"VPC","category":"Cloud Providers","definition":"Virtual Private Cloud — a logically isolated virtual network within a cloud where you control subnets, routing and security.","related":["Subnet","CIDR","Security Group","NAT"]},{"term":"Security Group","abbr":null,"category":"Cloud Providers","definition":"A virtual firewall in cloud networking that controls inbound and outbound traffic to resources such as VM instances, by rules on ports and sources.","related":["Firewall","VPC","Network Policy"]},{"term":"Auto Scaling Group","abbr":"ASG","category":"Cloud Providers","definition":"An AWS construct that maintains a desired number of instances and scales them in/out based on policies and health checks.","related":["Auto-Scaling","Elasticity","Amazon EC2"]},{"term":"Managed Service","abbr":null,"category":"Cloud Providers","definition":"A cloud offering where the provider operates the underlying infrastructure and much of the software lifecycle, reducing operational burden for the customer.","related":["PaaS","SaaS","Shared Responsibility Model"]},{"term":"Shared Responsibility Model","abbr":null,"category":"Cloud Providers","definition":"The division of security duties between cloud provider (security of the cloud) and customer (security in the cloud), varying by service type.","related":["Managed Service","Compliance","Security Posture"]},{"term":"KMS","abbr":"KMS","category":"Cloud Providers","definition":"Key Management Service — a managed cloud service for creating and controlling cryptographic keys used to encrypt data.","related":["Key Management","Encryption at Rest","Secrets Management"]},{"term":"CloudFormation","abbr":null,"category":"Cloud Providers","definition":"AWS's native infrastructure-as-code service that provisions and manages stacks of AWS resources from declarative templates.","related":["Infrastructure as Code","Terraform","Provisioning"]},{"term":"Cloud Agnostic","abbr":null,"category":"Cloud Providers","definition":"Designing software so it can run on any cloud provider without significant changes, typically by avoiding proprietary services or abstracting them.","related":["Multicloud","Portability","Vendor Lock-In"]},{"term":"Vendor Lock-In","abbr":null,"category":"Cloud Providers","definition":"Dependence on a particular vendor's proprietary technology that makes switching costly or difficult, a key driver of open standards adoption.","related":["Cloud Agnostic","OpenTelemetry","Multicloud"]},{"term":"Disaster Recovery","abbr":"DR","category":"Reliability","definition":"The strategy and tooling for restoring systems and data after a major outage or disaster, measured by RTO and RPO targets.","related":["RTO","RPO","Backup","Failover"]},{"term":"RTO","abbr":"RTO","category":"Reliability","definition":"Recovery Time Objective — the maximum acceptable time to restore a service after a disruption, a key disaster-recovery target.","related":["RPO","Disaster Recovery","MTTR"]},{"term":"RPO","abbr":"RPO","category":"Reliability","definition":"Recovery Point Objective — the maximum acceptable amount of data loss measured in time, defining how frequently backups must occur.","related":["RTO","Disaster Recovery","Backup"]},{"term":"Backup","abbr":null,"category":"Reliability","definition":"A copy of data stored separately so it can be restored after loss, corruption or attack; tested restores are essential for true protection.","related":["Disaster Recovery","RPO","Cold Storage"]},{"term":"High Availability","abbr":"HA","category":"Reliability","definition":"Designing systems to remain operational with minimal downtime through redundancy, failover and removal of single points of failure.","related":["Availability","Failover","Redundancy","Availability Zone"]},{"term":"Redundancy","abbr":null,"category":"Reliability","definition":"Duplicating critical components so that the failure of one does not bring down the system, a foundation of high availability.","related":["High Availability","Failover","Single Point of Failure"]},{"term":"Single Point of Failure","abbr":"SPOF","category":"Reliability","definition":"A component whose failure alone would cause the entire system to fail; eliminating SPOFs is central to resilient design.","related":["Redundancy","High Availability","Blast Radius"]},{"term":"Showback","abbr":null,"category":"Cloud Providers","definition":"Reporting cloud costs back to teams for visibility without direct billing, a step toward accountability; chargeback bills them directly.","related":["FinOps","Chargeback","Cost Optimization"]},{"term":"Chargeback","abbr":null,"category":"Cloud Providers","definition":"Allocating and billing actual cloud costs to the teams or departments that incurred them, driving cost accountability.","related":["Showback","FinOps"]},{"term":"Serverless Container","abbr":null,"category":"Cloud Providers","definition":"Running containers without managing servers or clusters, where the provider handles capacity (e.g., AWS Fargate, Cloud Run).","related":["Serverless","Container","Managed Service"]},{"term":"Infrastructure Drift","abbr":null,"category":"Cloud Providers","definition":"When deployed cloud infrastructure no longer matches its IaC definitions due to manual changes, detected by drift-detection tooling.","related":["Configuration Drift","Infrastructure as Code","Terraform"]},{"term":"Cloud Native","abbr":null,"category":"Cloud Native","definition":"An approach to building and running applications that fully exploits the cloud model — using containers, microservices, dynamic orchestration and declarative automation to deliver scalable, resilient, frequently updated systems.","related":["Microservices","Containers","Kubernetes","CNCF"]},{"term":"CNCF","abbr":"CNCF","category":"Cloud Native","definition":"The Cloud Native Computing Foundation — a Linux Foundation project that hosts and governs key open-source cloud-native technologies such as Kubernetes, Prometheus, Envoy and OpenTelemetry.","related":["Cloud Native","Kubernetes","OpenTelemetry"]},{"term":"Microservices Architecture","abbr":null,"category":"Cloud Native","definition":"A design style that structures an application as a collection of small, independently deployable services, each owning a single business capability and communicating over the network.","related":["Monolithic Apps","Service","API","Distributed System"]},{"term":"Monolithic Apps","abbr":null,"category":"Cloud Native","definition":"Applications built as a single, tightly coupled unit where all functionality is deployed together. Simpler to start with but harder to scale and evolve than microservices.","related":["Microservices Architecture","Tightly Coupled Architecture"]},{"term":"Twelve-Factor App","abbr":"12-Factor","category":"Cloud Native","definition":"A methodology of twelve best practices for building software-as-a-service apps that are portable, scalable and suitable for modern cloud platforms — covering config, dependencies, logs, processes and more.","related":["Cloud Native","Stateless Apps","Configuration as Code"]},{"term":"Containerization","abbr":null,"category":"Containers","definition":"Packaging an application together with its dependencies into a container image so it runs consistently across environments, isolated from other workloads but sharing the host OS kernel.","related":["Container","Container Image","Docker"]},{"term":"Container Image","abbr":null,"category":"Containers","definition":"An immutable, layered file bundle containing an application and everything needed to run it. Images are built from a Dockerfile and instantiated as running containers.","related":["Container","Container Registry","Dockerfile","Layer"]},{"term":"Container Registry","abbr":null,"category":"Containers","definition":"A storage and distribution system for container images, such as Docker Hub, Amazon ECR or Harbor, from which orchestrators pull images to run.","related":["Container Image","Docker","Artifact Repository"]},{"term":"Docker","abbr":null,"category":"Containers","definition":"A popular platform and toolset for building, sharing and running containers, which standardized container images and made containerization mainstream.","related":["Containerization","Container Image","Dockerfile","OCI"]},{"term":"Dockerfile","abbr":null,"category":"Containers","definition":"A text file of instructions that defines how to build a container image — base image, dependencies, files to copy, and the command to run.","related":["Container Image","Docker","Build"]},{"term":"OCI","abbr":"OCI","category":"Containers","definition":"The Open Container Initiative — open standards for container image format and runtime, ensuring interoperability between container tools and registries.","related":["Container Image","containerd","Docker"]},{"term":"containerd","abbr":null,"category":"Containers","definition":"An industry-standard, lightweight container runtime that manages the complete container lifecycle — image transfer, execution, storage and networking. Used by Kubernetes via the CRI.","related":["Container Runtime","CRI","OCI","runc"]},{"term":"Container Runtime","abbr":null,"category":"Containers","definition":"The low-level software responsible for running containers on a node — pulling images, creating isolation (namespaces and cgroups) and starting processes. Examples include containerd and CRI-O.","related":["containerd","CRI","runc","cgroup"]},{"term":"runc","abbr":null,"category":"Containers","definition":"A lightweight, OCI-compliant command-line tool for spawning and running containers, used under the hood by higher-level runtimes like containerd.","related":["Container Runtime","OCI","containerd"]},{"term":"cgroup","abbr":"cgroup","category":"Containers","definition":"A Linux control group — a kernel feature that limits, accounts for and isolates the resource usage (CPU, memory, I/O) of a group of processes, underpinning container resource limits.","related":["Namespace","Container Runtime","Resource Limits"]},{"term":"Namespace (Linux)","abbr":null,"category":"Containers","definition":"A Linux kernel feature that isolates and virtualizes system resources (process IDs, network, mounts) for a set of processes, providing the isolation that makes containers possible.","related":["cgroup","Container Runtime"]},{"term":"Sidecar Container","abbr":null,"category":"Containers","definition":"A helper container deployed alongside a main application container in the same pod to provide supporting features such as logging, proxying or service-mesh data-plane functions.","related":["Pod","Service Mesh","Service Proxy","Init Container"]},{"term":"Init Container","abbr":null,"category":"Containers","definition":"A specialized container that runs to completion before the main app containers in a pod start, used for setup tasks like waiting on dependencies or preparing data.","related":["Pod","Sidecar Container"]},{"term":"Image Pull Policy","abbr":null,"category":"Containers","definition":"A setting that controls when an orchestrator fetches a container image from the registry — Always, IfNotPresent or Never — balancing freshness against startup speed.","related":["Container Image","Container Registry"]},{"term":"Layer (Image)","abbr":null,"category":"Containers","definition":"One of the stacked, cached filesystem changes that compose a container image. Shared layers are reused across images to save space and speed up builds and pulls.","related":["Container Image","Dockerfile"]},{"term":"Container Orchestration","abbr":null,"category":"Cloud Native","definition":"Automated management of containerized workloads across a cluster — scheduling, scaling, networking, health-checking and self-healing — most commonly performed by Kubernetes.","related":["Kubernetes","Cluster","Scheduler"]},{"term":"Service Mesh","abbr":null,"category":"Service Mesh","definition":"A dedicated infrastructure layer that manages service-to-service communication — traffic routing, load balancing, mTLS, retries and observability — transparently via proxies, without changing application code.","related":["Service Proxy","Envoy","Istio","Sidecar Container","mTLS"]},{"term":"Service Proxy","abbr":null,"category":"Service Mesh","definition":"A network proxy that intercepts and manages traffic to and from a service, providing routing, load balancing, security and telemetry. The data-plane building block of a service mesh.","related":["Service Mesh","Envoy","Sidecar Container"]},{"term":"Envoy","abbr":null,"category":"Service Mesh","definition":"A high-performance, CNCF-graduated L7 proxy designed for cloud-native applications, widely used as the data plane in service meshes and API gateways.","related":["Service Proxy","Service Mesh","Istio","API Gateway"]},{"term":"Istio","abbr":null,"category":"Service Mesh","definition":"A popular open-source service mesh that layers traffic management, security (mTLS) and observability onto Kubernetes workloads using Envoy sidecar proxies.","related":["Service Mesh","Envoy","Kubernetes","mTLS"]},{"term":"Linkerd","abbr":null,"category":"Service Mesh","definition":"A lightweight, CNCF service mesh for Kubernetes focused on simplicity, security and low overhead, providing mTLS, metrics and reliability features out of the box.","related":["Service Mesh","mTLS","Kubernetes"]},{"term":"Data Plane","abbr":null,"category":"Service Mesh","definition":"The set of proxies that actually carry and act on application traffic in a service mesh, applying routing, security and telemetry as configured by the control plane.","related":["Control Plane","Service Proxy","Service Mesh"]},{"term":"Control Plane","abbr":null,"category":"Service Mesh","definition":"The management layer that configures and coordinates the data plane — distributing routing rules, certificates and policy to proxies. Also a general term for a system's management tier.","related":["Data Plane","Service Mesh"]},{"term":"mTLS","abbr":"mTLS","category":"Service Mesh","definition":"Mutual Transport Layer Security — TLS in which both client and server authenticate each other with certificates, commonly used by service meshes to encrypt and verify service-to-service traffic.","related":["TLS","Service Mesh","Zero Trust Architecture"]},{"term":"GitOps","abbr":null,"category":"DevOps & CI/CD","definition":"An operational model that uses Git as the single source of truth for declarative infrastructure and applications, with automated agents continuously reconciling the live system to match the repository.","related":["Infrastructure as Code","Continuous Delivery","Argo CD","Reconciliation"]},{"term":"Argo CD","abbr":null,"category":"DevOps & CI/CD","definition":"A declarative GitOps continuous-delivery tool for Kubernetes that automatically syncs cluster state to manifests stored in Git and reports drift.","related":["GitOps","Kubernetes","Continuous Delivery"]},{"term":"Flux","abbr":null,"category":"DevOps & CI/CD","definition":"A CNCF GitOps toolkit for Kubernetes that keeps clusters in sync with configuration stored in Git, automating deployments and updates.","related":["GitOps","Kubernetes","Argo CD"]},{"term":"Reconciliation","abbr":null,"category":"Cloud Native","definition":"The continuous control-loop process of comparing a system's actual state to its declared desired state and taking action to converge them — the core mechanism behind Kubernetes controllers and GitOps.","related":["Desired State","Controller","GitOps","Operator"]},{"term":"Desired State","abbr":null,"category":"Cloud Native","definition":"The declarative specification of how a system should look, which controllers continuously work to achieve. Contrast with the observed actual state.","related":["Reconciliation","Declarative Configuration","Controller"]},{"term":"Declarative Configuration","abbr":null,"category":"Cloud Native","definition":"Describing the desired end state of a system (what you want) rather than the steps to get there (how), letting automation figure out the actions. Central to Kubernetes and IaC.","related":["Desired State","Infrastructure as Code","Imperative Configuration"]},{"term":"Infrastructure as Code","abbr":"IaC","category":"DevOps & CI/CD","definition":"Managing and provisioning infrastructure through machine-readable definition files rather than manual processes, enabling versioning, review and repeatable automated deployments.","related":["Terraform","Declarative Configuration","GitOps","Configuration as Code"]},{"term":"Terraform","abbr":null,"category":"DevOps & CI/CD","definition":"A widely used open-source infrastructure-as-code tool that provisions and manages cloud and on-prem resources declaratively across many providers using a state file.","related":["Infrastructure as Code","Provisioning","State File"]},{"term":"Configuration as Code","abbr":"CaC","category":"DevOps & CI/CD","definition":"Defining application and system configuration in version-controlled files rather than ad-hoc manual settings, making config auditable, reviewable and reproducible.","related":["Infrastructure as Code","GitOps"]},{"term":"Policy as Code","abbr":"PaC","category":"Security & SIEM","definition":"Expressing governance, security and compliance rules as machine-readable code that can be automatically enforced and tested, for example with Open Policy Agent.","related":["OPA","Compliance","Infrastructure as Code"]},{"term":"OPA","abbr":"OPA","category":"Security & SIEM","definition":"Open Policy Agent — a CNCF general-purpose policy engine that evaluates declarative rules (written in Rego) to make authorization and admission decisions across the stack.","related":["Policy as Code","Admission Controller"]},{"term":"Immutable Infrastructure","abbr":null,"category":"Cloud Native","definition":"An approach where servers and components are never modified after deployment; changes are made by replacing them with new versions, improving consistency and reducing configuration drift.","related":["Configuration Drift","Container Image","Infrastructure as Code"]},{"term":"Configuration Drift","abbr":null,"category":"DevOps & CI/CD","definition":"The gradual divergence of a system's actual configuration from its intended baseline due to manual or unmanaged changes, a key risk that GitOps and IaC aim to eliminate.","related":["Immutable Infrastructure","GitOps","Reconciliation"]},{"term":"Function as a Service","abbr":"FaaS","category":"Cloud Native","definition":"A serverless compute model where individual functions run in response to events, scaling to zero when idle. AWS Lambda and Google Cloud Functions are examples.","related":["Serverless","AWS Lambda","Cold Start","Event-Driven Architecture"]},{"term":"Platform Engineering","abbr":null,"category":"DevOps & CI/CD","definition":"The discipline of building internal developer platforms — self-service tooling, golden paths and automation — that reduce cognitive load and let teams ship software faster and safely.","related":["Internal Developer Platform","DevOps","Golden Path"]},{"term":"Internal Developer Platform","abbr":"IDP","category":"DevOps & CI/CD","definition":"A curated, self-service layer of tools and workflows that abstracts infrastructure complexity so developers can deploy and operate services without deep platform expertise.","related":["Platform Engineering","Golden Path"]},{"term":"Stateless Apps","abbr":null,"category":"Cloud Native","definition":"Applications that retain no client session data between requests, storing any state externally. Statelessness makes horizontal scaling and recovery straightforward.","related":["Stateful Apps","Horizontal Scaling","Twelve-Factor App"]},{"term":"Stateful Apps","abbr":null,"category":"Cloud Native","definition":"Applications that maintain persistent state across requests or restarts, such as databases, requiring stable storage and identity, handled in Kubernetes by StatefulSets.","related":["Stateless Apps","StatefulSet","Persistent Volume"]},{"term":"Loosely Coupled Architecture","abbr":null,"category":"Architecture","definition":"A design where components depend on one another minimally, communicating through stable interfaces, so each can change, scale or fail independently.","related":["Tightly Coupled Architecture","Microservices Architecture","Event-Driven Architecture"]},{"term":"Tightly Coupled Architecture","abbr":null,"category":"Architecture","definition":"A design where components are highly interdependent, so a change or failure in one strongly affects others. Common in monoliths and harder to evolve.","related":["Loosely Coupled Architecture","Monolithic Apps"]},{"term":"Event-Driven Architecture","abbr":"EDA","category":"Architecture","definition":"An architectural style where components communicate by producing and reacting to events asynchronously, enabling loose coupling, scalability and real-time responsiveness.","related":["Event Streaming","Message Queue","Pub/Sub","Kafka"]},{"term":"Edge Computing","abbr":null,"category":"Cloud Native","definition":"Processing data near where it is generated — at the network edge rather than a central cloud — to reduce latency and bandwidth for use cases like IoT and CDNs.","related":["CDN","Latency","IoT"]},{"term":"WebAssembly","abbr":"Wasm","category":"Cloud Native","definition":"A portable, sandboxed binary instruction format that runs near-native code in browsers and increasingly on servers and edge platforms, offering fast, language-agnostic execution.","related":["Edge Computing","Runtime"]},{"term":"Multitenancy","abbr":null,"category":"Cloud Native","definition":"An architecture where a single instance of software serves multiple isolated customers (tenants), sharing infrastructure while keeping each tenant's data and configuration separate.","related":["Isolation","Namespace (Linux)","SaaS"]},{"term":"Self Healing","abbr":null,"category":"Cloud Native","definition":"A system's built-in ability to detect and automatically recover from failures — restarting crashed containers, rescheduling pods or replacing unhealthy instances — without human action.","related":["Reconciliation","Liveness Probe","Auto-Remediation"]},{"term":"Shift Left","abbr":null,"category":"DevOps & CI/CD","definition":"Moving testing, security and observability earlier in the software lifecycle so issues are caught during development rather than in production.","related":["DevSecOps","Continuous Integration","Shift Right"]},{"term":"DevSecOps","abbr":null,"category":"Security & SIEM","definition":"Integrating security practices and automation throughout the DevOps lifecycle, making security a shared responsibility from code to production rather than a late-stage gate.","related":["DevOps","Shift Left","Policy as Code"]},{"term":"Zero Trust Architecture","abbr":"ZTA","category":"Security & SIEM","definition":"A security model that assumes no implicit trust based on network location and continuously verifies every user, device and request before granting least-privilege access.","related":["mTLS","Identity and Access Management","Least Privilege"]},{"term":"Service Discovery","abbr":null,"category":"Cloud Native","definition":"The automatic detection of services and their network locations within a dynamic environment, so clients can find healthy instances without hardcoded addresses.","related":["Service","DNS","Service Mesh","Load Balancing"]},{"term":"API Gateway","abbr":null,"category":"Networking","definition":"A server that sits in front of backend services as a single entry point, handling routing, authentication, rate limiting, and aggregation for client requests.","related":["API","Reverse Proxy","Rate Limiting","Envoy"]},{"term":"Security Chaos Engineering","abbr":null,"category":"Security & SIEM","definition":"Applying chaos-engineering principles to security — proactively testing detection and response controls by simulating attacks and failures.","related":["Chaos Engineering","DevSecOps","Threat Detection"]},{"term":"Portability","abbr":null,"category":"Cloud Native","definition":"The ability to move an application across environments — clouds, on-prem, or local — with minimal change, often achieved through containers and open standards.","related":["Containerization","Cloud Native","OCI"]},{"term":"Idempotence","abbr":null,"category":"Distributed Systems","definition":"A property where performing an operation multiple times produces the same result as performing it once, important for safe retries in distributed systems and APIs.","related":["Retry","At-Least-Once Delivery","Distributed System"]},{"term":"Runtime","abbr":null,"category":"Compute & Runtime","definition":"The environment in which a program executes, providing services like memory management, scheduling and libraries; also the period during which a program runs.","related":["JVM","Garbage Collection","Interpreter"]},{"term":"JVM","abbr":"JVM","category":"Compute & Runtime","definition":"Java Virtual Machine — the runtime that executes Java bytecode, providing portability, JIT compilation and garbage collection; a common APM instrumentation target.","related":["Bytecode","Garbage Collection","JIT Compilation","Heap"]},{"term":"Bytecode","abbr":null,"category":"Compute & Runtime","definition":"Portable intermediate instructions (e.g., Java or .NET) executed by a virtual machine rather than directly by hardware, enabling cross-platform execution and instrumentation.","related":["JVM","Bytecode Instrumentation","Interpreter"]},{"term":"Bytecode Instrumentation","abbr":null,"category":"APM","definition":"Modifying compiled bytecode at load time to inject telemetry without changing source code, the basis of many auto-instrumentation agents.","related":["Auto-Instrumentation","Bytecode","Agent"]},{"term":"JIT Compilation","abbr":null,"category":"Compute & Runtime","definition":"Just-In-Time compilation — translating bytecode to native machine code at runtime for speed, used by the JVM and other managed runtimes.","related":["JVM","Bytecode","Compiler"]},{"term":"Compiler","abbr":null,"category":"Compute & Runtime","definition":"A program that translates source code into a lower-level form (machine code or bytecode) ahead of execution.","related":["Interpreter","Bytecode","Build"]},{"term":"Interpreter","abbr":null,"category":"Compute & Runtime","definition":"A program that executes source code directly, statement by statement, without a separate compilation step.","related":["Compiler","Runtime","Bytecode"]},{"term":"Garbage Collection","abbr":"GC","category":"Compute & Runtime","definition":"Automatic reclamation of memory no longer in use by a program; GC pauses are a common source of latency spikes monitored by APM.","related":["Heap","Memory Leak","GC Pause","JVM"]},{"term":"GC Pause","abbr":null,"category":"Compute & Runtime","definition":"A period when application threads are stopped so the garbage collector can run, causing latency that observability tools track and correlate.","related":["Garbage Collection","Tail Latency","Profiling"]},{"term":"Heap","abbr":null,"category":"Compute & Runtime","definition":"The region of memory used for dynamic allocation during program execution; heap growth and exhaustion drive memory issues and GC activity.","related":["Stack","Garbage Collection","Memory Leak","OOMKilled"]},{"term":"Stack","abbr":null,"category":"Compute & Runtime","definition":"A region of memory holding function call frames and local variables, managed in last-in-first-out order; stack traces derive from it.","related":["Heap","Stack Trace","Thread"]},{"term":"Memory Leak","abbr":null,"category":"Compute & Runtime","definition":"A defect where a program fails to release memory it no longer needs, causing usage to grow over time until performance degrades or it crashes.","related":["Heap","Garbage Collection","Profiling"]},{"term":"Thread","abbr":null,"category":"Compute & Runtime","definition":"The smallest unit of execution within a process; multiple threads share memory and enable concurrency within a program.","related":["Process","Concurrency","Thread Pool"]},{"term":"Thread Pool","abbr":null,"category":"Compute & Runtime","definition":"A managed set of reusable threads that execute tasks, avoiding the cost of creating threads per task; pool saturation is a common bottleneck.","related":["Thread","Concurrency","Saturation"]},{"term":"Goroutine","abbr":null,"category":"Compute & Runtime","definition":"A lightweight, runtime-managed concurrent function in Go; goroutines are cheap, enabling massive concurrency, and are tracked in Go profiling.","related":["Concurrency","Thread","Profiling"]},{"term":"Event Loop","abbr":null,"category":"Compute & Runtime","definition":"A single-threaded loop (as in Node.js or browsers) that processes events and callbacks asynchronously; blocking it stalls all work.","related":["Asynchronous","Concurrency","Thread"]},{"term":"Asynchronous","abbr":null,"category":"Compute & Runtime","definition":"A programming model where operations run without blocking the caller, signaling completion later via callbacks, promises or events.","related":["Event Loop","Concurrency","Non-Blocking I/O"]},{"term":"Non-Blocking I/O","abbr":null,"category":"Compute & Runtime","definition":"I/O operations that return immediately and notify when complete, letting a thread handle many operations concurrently.","related":["Asynchronous","Event Loop"]},{"term":"Process","abbr":null,"category":"Compute & Runtime","definition":"An instance of a running program with its own memory space and resources; processes contain one or more threads.","related":["Thread","Namespace (Linux)","PID"]},{"term":"PID","abbr":"PID","category":"Compute & Runtime","definition":"Process Identifier — a unique number the OS assigns to each running process, used to manage and reference it.","related":["Process","Signal"]},{"term":"System Call","abbr":"syscall","category":"Compute & Runtime","definition":"A request from a program to the operating system kernel to perform a privileged operation like I/O or process control; traced by tools like strace and eBPF.","related":["Kernel","eBPF","File Descriptor"]},{"term":"Kernel","abbr":null,"category":"Compute & Runtime","definition":"The core of an operating system that manages hardware, memory, processes and system calls; the layer eBPF programs hook into.","related":["System Call","eBPF","cgroup"]},{"term":"File Descriptor","abbr":"FD","category":"Compute & Runtime","definition":"An OS handle representing an open file, socket or pipe; exhausting the file-descriptor limit is a common cause of failures under load.","related":["System Call","Socket","Resource Limits"]},{"term":"Load Average","abbr":null,"category":"Compute & Runtime","definition":"A Unix metric showing the average number of processes runnable or waiting over 1, 5 and 15 minutes, indicating system demand relative to CPU count.","related":["CPU Utilization","Saturation","USE Method"]},{"term":"CPU Utilization","abbr":null,"category":"Infrastructure","definition":"The percentage of CPU capacity in use over a period; sustained high utilization signals saturation and potential performance impact.","related":["Saturation","Load Average","Utilization"]},{"term":"Utilization","abbr":null,"category":"Metrics","definition":"The fraction of a resource's capacity that is in use; one of the USE method's three signals for resource analysis.","related":["Saturation","USE Method","CPU Utilization"]},{"term":"Page Fault","abbr":null,"category":"Compute & Runtime","definition":"An event when a program accesses memory not currently in physical RAM, requiring the OS to load it; excessive faults (thrashing) hurt performance.","related":["Swap","Heap","Memory Leak"]},{"term":"Swap","abbr":null,"category":"Compute & Runtime","definition":"Disk space used as overflow when physical memory is exhausted; heavy swapping drastically slows systems and signals memory pressure.","related":["Page Fault","Saturation","OOMKilled"]},{"term":"Signal","abbr":null,"category":"Compute & Runtime","definition":"An asynchronous notification sent to a process by the OS or another process (e.g., SIGTERM, SIGKILL) to trigger handling or termination.","related":["Process","Graceful Shutdown"]},{"term":"Graceful Shutdown","abbr":null,"category":"Compute & Runtime","definition":"Stopping a process in an orderly way — finishing in-flight work, releasing resources and deregistering — typically on receiving SIGTERM.","related":["Signal","Drain","Readiness Probe"]},{"term":"systemd","abbr":null,"category":"Compute & Runtime","definition":"A widely used Linux init system and service manager that starts, supervises and logs system services (units).","related":["Process","Daemon","journald"]},{"term":"Daemon","abbr":null,"category":"Compute & Runtime","definition":"A long-running background process that provides a service, typically started at boot and not attached to a terminal.","related":["systemd","Agent","Process"]},{"term":"Cron","abbr":null,"category":"Compute & Runtime","definition":"A Unix time-based job scheduler that runs commands on a defined schedule; the inspiration for Kubernetes CronJobs.","related":["CronJob","Scheduler","Batch Processing"]},{"term":"Throughput (Compute)","abbr":null,"category":"Compute & Runtime","definition":"The amount of work a system completes per unit time (requests, transactions, jobs), a primary capacity and performance measure.","related":["Throughput","Latency","Saturation"]},{"term":"Latency vs Throughput","abbr":null,"category":"Compute & Runtime","definition":"A core performance trade-off: latency is how long one operation takes, throughput is how many complete per unit time; optimizing one can hurt the other.","related":["Latency","Throughput","Bottleneck"]},{"term":"IOPS","abbr":"IOPS","category":"Infrastructure","definition":"Input/Output Operations Per Second — a storage performance measure of how many read/write operations a disk or volume can handle.","related":["Block Storage","Disk Latency","Throughput"]},{"term":"Disk Latency","abbr":null,"category":"Infrastructure","definition":"The time taken to complete a storage I/O request; high disk latency is a frequent cause of application slowdowns.","related":["IOPS","Saturation","Block Storage"]},{"term":"Cache (CPU/App)","abbr":null,"category":"Compute & Runtime","definition":"Fast storage that holds frequently accessed data closer to where it's needed (CPU caches, application caches) to reduce access time.","related":["Caching","Cache Hit Ratio","Redis"]},{"term":"Cold Start (Runtime)","abbr":null,"category":"Compute & Runtime","definition":"The latency of initializing a fresh execution environment (JVM warmup, serverless container init) before it serves requests at full speed.","related":["Cold Start","Serverless","JIT Compilation"]},{"term":"Profiler","abbr":null,"category":"APM","definition":"A tool that samples or instruments a program to measure where time and resources are spent, producing flame graphs and hot-spot reports.","related":["Profiling","Continuous Profiling","Flame Graph"]},{"term":"Tracepoint","abbr":null,"category":"Compute & Runtime","definition":"A predefined hook in the kernel or application where instrumentation can attach to observe events, used by eBPF and tracing tools.","related":["eBPF","System Call","Instrumentation"]},{"term":"Hot Path","abbr":null,"category":"Compute & Runtime","definition":"The most frequently executed code path in a program, where performance optimizations have the greatest impact.","related":["Profiling","Flame Graph","Bottleneck"]},{"term":"Memory Footprint","abbr":null,"category":"Compute & Runtime","definition":"The amount of memory a program uses while running; tracking it helps right-size containers and prevent OOM kills.","related":["Heap","Resource Limits","Right-Sizing"]},{"term":"Database","abbr":null,"category":"Databases","definition":"An organized, persistent collection of structured data managed by a database management system (DBMS), supporting storage, querying and transactions.","related":["Relational Database","NoSQL","Query","Schema"]},{"term":"Relational Database","abbr":"RDBMS","category":"Databases","definition":"A database that stores data in tables of rows and columns with defined relationships, queried with SQL and offering strong consistency and transactions.","related":["SQL","NoSQL","ACID","Normalization"]},{"term":"NoSQL","abbr":null,"category":"Databases","definition":"A category of non-relational databases (document, key-value, column-family, graph) designed for flexible schemas, horizontal scale and high throughput.","related":["Relational Database","Document Database","Key-Value Store","Eventual Consistency"]},{"term":"SQL","abbr":"SQL","category":"Databases","definition":"Structured Query Language — the standard language for defining, querying and manipulating data in relational databases.","related":["Relational Database","Query","Join"]},{"term":"Query","abbr":null,"category":"Databases","definition":"A request to retrieve or modify data in a database or telemetry store, expressed in a query language such as SQL, PromQL or a search syntax.","related":["SQL","PromQL","Query Optimization","Index (Database)"]},{"term":"Index (Database)","abbr":null,"category":"Databases","definition":"A data structure that speeds up lookups on one or more columns at the cost of extra storage and slower writes, central to query performance.","related":["Query","Query Optimization","B-Tree"]},{"term":"Query Optimization","abbr":null,"category":"Databases","definition":"The process by which a database chooses an efficient execution plan for a query; slow queries are a common application performance bottleneck.","related":["Query","Execution Plan","Database Monitoring"]},{"term":"Execution Plan","abbr":null,"category":"Databases","definition":"The step-by-step strategy a database uses to run a query (scans, joins, index use); examining it is key to diagnosing slow queries.","related":["Query Optimization","Database Monitoring","Slow Query"]},{"term":"Slow Query","abbr":null,"category":"Databases","definition":"A database query whose execution time exceeds a threshold, often surfaced in logs and APM as a target for optimization.","related":["Query Optimization","Database Monitoring","Latency"]},{"term":"ACID","abbr":"ACID","category":"Databases","definition":"Atomicity, Consistency, Isolation, Durability — the guarantees that make database transactions reliable even amid failures and concurrency.","related":["Transaction (DB)","BASE","Relational Database"]},{"term":"BASE","abbr":"BASE","category":"Databases","definition":"Basically Available, Soft state, Eventual consistency — a relaxed consistency model favored by many distributed NoSQL systems over strict ACID.","related":["Eventual Consistency","ACID","CAP Theorem"]},{"term":"Transaction (DB)","abbr":null,"category":"Databases","definition":"A unit of database work executed as a single, all-or-nothing operation, preserving consistency through commit or rollback.","related":["ACID","Rollback","Isolation Level"]},{"term":"Isolation Level","abbr":null,"category":"Databases","definition":"A setting that controls how visible concurrent transactions are to each other, trading consistency against performance (e.g., read committed, serializable).","related":["Transaction (DB)","ACID","Concurrency"]},{"term":"Sharding","abbr":null,"category":"Databases","definition":"Partitioning a database horizontally across multiple servers, each holding a subset of the data, to scale beyond a single machine's capacity.","related":["Partitioning","Replication","Horizontal Scaling"]},{"term":"Partitioning","abbr":null,"category":"Databases","definition":"Dividing data into segments (by range, hash or list) to improve manageability and performance; sharding is partitioning across machines.","related":["Sharding","Index (Database)"]},{"term":"Replication","abbr":null,"category":"Databases","definition":"Maintaining copies of data across multiple nodes for availability, durability and read scalability, using synchronous or asynchronous propagation.","related":["Sharding","Primary-Replica","Consistency"]},{"term":"Primary-Replica","abbr":null,"category":"Databases","definition":"A replication topology where one primary node accepts writes and propagates them to read-only replicas, improving read scale and availability.","related":["Replication","Failover","Read Replica"]},{"term":"Read Replica","abbr":null,"category":"Databases","definition":"A read-only copy of a database that serves read queries to offload the primary and scale read-heavy workloads.","related":["Primary-Replica","Replication"]},{"term":"Failover","abbr":null,"category":"Reliability","definition":"Automatically switching to a standby system or replica when the active one fails, minimizing downtime.","related":["High Availability","Replication","Disaster Recovery"]},{"term":"Denormalization","abbr":null,"category":"Databases","definition":"Intentionally duplicating data across tables to speed up reads at the cost of redundancy and write complexity, common in analytics and NoSQL.","related":["Normalization","NoSQL"]},{"term":"Schema","abbr":null,"category":"Databases","definition":"The formal structure that defines how data is organized — tables, fields, types and relationships in a database, or the shape of messages/events.","related":["Database","Schema Evolution","Data Model"]},{"term":"Schema Evolution","abbr":null,"category":"Data & Streaming","definition":"Managing changes to a data or message schema over time while keeping producers and consumers compatible, a key concern in streaming and APIs.","related":["Schema","Schema Registry","Backward Compatibility"]},{"term":"Document Database","abbr":null,"category":"Databases","definition":"A NoSQL database that stores data as flexible, self-describing documents (often JSON), such as MongoDB, suited to evolving schemas.","related":["NoSQL","MongoDB","Key-Value Store"]},{"term":"Key-Value Store","abbr":null,"category":"Databases","definition":"A simple, fast NoSQL database that stores data as keyed values, ideal for caching and session storage; Redis is a popular example.","related":["NoSQL","Redis","Caching"]},{"term":"Columnar Database","abbr":null,"category":"Databases","definition":"A database that stores data by column rather than row, enabling fast aggregation over large datasets; widely used for analytics and observability backends.","related":["Time Series Database","OLAP","Analytics"]},{"term":"Graph Database","abbr":null,"category":"Databases","definition":"A database that models data as nodes and edges, optimized for traversing relationships, used for social graphs, fraud detection and dependency analysis.","related":["NoSQL","Topology"]},{"term":"Time Series Database","abbr":"TSDB","category":"Databases","definition":"A database optimized for storing and querying timestamped data points, providing efficient ingestion, compression and time-range queries for metrics.","related":["Time Series","Prometheus","Metric","Downsampling"]},{"term":"OLAP","abbr":"OLAP","category":"Databases","definition":"Online Analytical Processing — systems optimized for complex analytical queries over large historical datasets, as opposed to transactional workloads.","related":["OLTP","Columnar Database","Data Warehouse"]},{"term":"OLTP","abbr":"OLTP","category":"Databases","definition":"Online Transaction Processing — systems optimized for many short, concurrent read/write transactions, such as order entry and banking.","related":["OLAP","Transaction (DB)","Relational Database"]},{"term":"Data Warehouse","abbr":null,"category":"Data & Streaming","definition":"A central repository of integrated, structured data optimized for analytics and reporting, fed by ETL/ELT from operational systems.","related":["Data Lake","ETL","OLAP"]},{"term":"Data Lake","abbr":null,"category":"Data & Streaming","definition":"A storage repository that holds vast amounts of raw data in native format until needed, supporting diverse analytics and machine learning.","related":["Data Warehouse","Data Lakehouse","Object Storage"]},{"term":"Data Lakehouse","abbr":null,"category":"Data & Streaming","definition":"An architecture that combines the low-cost, flexible storage of a data lake with the management and performance features of a data warehouse.","related":["Data Lake","Data Warehouse"]},{"term":"ETL","abbr":"ETL","category":"Data & Streaming","definition":"Extract, Transform, Load — a pipeline pattern that pulls data from sources, transforms it, and loads it into a target store for analysis.","related":["ELT","Data Pipeline","Data Warehouse"]},{"term":"ELT","abbr":"ELT","category":"Data & Streaming","definition":"Extract, Load, Transform — a variant of ETL that loads raw data first and transforms it inside the destination, leveraging modern warehouse compute.","related":["ETL","Data Warehouse"]},{"term":"Data Pipeline","abbr":null,"category":"Data & Streaming","definition":"A series of processing steps that move and transform data from sources to destinations, batch or streaming, underpinning analytics and observability.","related":["ETL","Stream Processing","Observability Pipeline"]},{"term":"Stream Processing","abbr":null,"category":"Data & Streaming","definition":"Continuously processing data records as they arrive in real time, rather than in scheduled batches, enabling low-latency analytics and reactions.","related":["Event Streaming","Kafka","Batch Processing"]},{"term":"Batch Processing","abbr":null,"category":"Data & Streaming","definition":"Processing data in large, scheduled groups rather than continuously, suited to high-volume jobs where latency is not critical.","related":["Stream Processing","Data Pipeline"]},{"term":"Event Streaming","abbr":null,"category":"Data & Streaming","definition":"Capturing and distributing continuous streams of events between producers and consumers in real time, often via platforms like Apache Kafka.","related":["Kafka","Event-Driven Architecture","Pub/Sub","Stream Processing"]},{"term":"Kafka","abbr":null,"category":"Data & Streaming","definition":"Apache Kafka — a distributed, durable, high-throughput event-streaming platform that stores streams of records in partitioned, replicated topics.","related":["Event Streaming","Topic","Partition","Consumer Group"]},{"term":"Topic","abbr":null,"category":"Data & Streaming","definition":"A named, append-only category or feed of messages in a streaming system to which producers write and from which consumers read.","related":["Kafka","Partition","Pub/Sub"]},{"term":"Partition (Streaming)","abbr":null,"category":"Data & Streaming","definition":"A subdivision of a Kafka topic that enables parallelism and ordering within the partition; consumers in a group divide partitions among themselves.","related":["Kafka","Topic","Consumer Group"]},{"term":"Consumer Group","abbr":null,"category":"Data & Streaming","definition":"A set of consumers that cooperatively read from a topic's partitions, each partition handled by one member, enabling scalable parallel consumption.","related":["Kafka","Partition (Streaming)","Offset"]},{"term":"Offset","abbr":null,"category":"Data & Streaming","definition":"A monotonic identifier marking a consumer's position in a partition, used to track which messages have been processed.","related":["Kafka","Consumer Group","At-Least-Once Delivery"]},{"term":"Message Queue","abbr":null,"category":"Data & Streaming","definition":"A component that buffers messages between producers and consumers, decoupling them and smoothing load; examples include RabbitMQ and SQS.","related":["Pub/Sub","Event-Driven Architecture","Backpressure"]},{"term":"Pub/Sub","abbr":null,"category":"Data & Streaming","definition":"A messaging pattern where publishers send messages to topics and subscribers receive them, decoupling senders from receivers.","related":["Message Queue","Event Streaming","Topic"]},{"term":"Dead Letter Queue","abbr":"DLQ","category":"Data & Streaming","definition":"A queue where messages that cannot be processed successfully are sent for later inspection, preventing them from blocking the main flow.","related":["Message Queue","Retry","Poison Message"]},{"term":"At-Least-Once Delivery","abbr":null,"category":"Data & Streaming","definition":"A messaging guarantee that every message is delivered one or more times, requiring consumers to be idempotent to handle duplicates.","related":["Exactly-Once Delivery","Idempotence","Offset"]},{"term":"Exactly-Once Delivery","abbr":null,"category":"Data & Streaming","definition":"A strong messaging guarantee that each message is processed once and only once, harder to achieve and often realized via idempotency and transactions.","related":["At-Least-Once Delivery","Idempotence"]},{"term":"Schema Registry","abbr":null,"category":"Data & Streaming","definition":"A central service that stores and validates the schemas of messages in a streaming system, enforcing compatibility as schemas evolve.","related":["Schema Evolution","Kafka","Serialization"]},{"term":"Serialization","abbr":null,"category":"Data & Streaming","definition":"Converting in-memory data structures into a format suitable for storage or transmission (e.g., JSON, Avro, Protocol Buffers), with deserialization reversing it.","related":["Protocol Buffers","Schema","JSON"]},{"term":"Object Storage","abbr":null,"category":"Databases","definition":"Storage that manages data as objects with metadata in a flat namespace (e.g., Amazon S3), offering massive scalability for unstructured data.","related":["Data Lake","Block Storage","Blob"]},{"term":"Block Storage","abbr":null,"category":"Databases","definition":"Storage that exposes raw volumes split into fixed-size blocks, attached to servers like disks; used by databases and file systems.","related":["Object Storage","Persistent Volume"]},{"term":"Redis","abbr":null,"category":"Databases","definition":"An in-memory key-value data store used for caching, session storage, queues and real-time analytics, prized for very low latency.","related":["Key-Value Store","Caching","In-Memory Database"]},{"term":"In-Memory Database","abbr":null,"category":"Databases","definition":"A database that keeps data primarily in RAM for extremely fast access, trading durability characteristics for speed; Redis and Memcached are examples.","related":["Redis","Caching"]},{"term":"CAP Theorem","abbr":null,"category":"Distributed Systems","definition":"A principle stating a distributed data store can guarantee at most two of Consistency, Availability and Partition tolerance simultaneously.","related":["Eventual Consistency","Distributed System","BASE"]},{"term":"Eventual Consistency","abbr":null,"category":"Distributed Systems","definition":"A consistency model where replicas may temporarily diverge but converge to the same value if no new updates occur, common in highly available systems.","related":["Strong Consistency","CAP Theorem","BASE"]},{"term":"Strong Consistency","abbr":null,"category":"Distributed Systems","definition":"A guarantee that all readers see the most recent write immediately, simplifying reasoning at the cost of availability or latency in distributed systems.","related":["Eventual Consistency","CAP Theorem","Linearizability"]},{"term":"Data Model","abbr":null,"category":"Databases","definition":"An abstract representation of how data elements relate and are organized within a system, guiding schema design and querying.","related":["Schema","Relational Database","Normalization"]},{"term":"Cardinality (Data)","abbr":null,"category":"Databases","definition":"The number of distinct values in a column or field; high cardinality affects index design in databases and storage cost in metrics systems.","related":["Cardinality","Index (Database)","Dimension"]},{"term":"Data Retention (DB)","abbr":null,"category":"Databases","definition":"Policies governing how long data is stored before archival or deletion, balancing query needs, compliance and storage cost.","related":["Retention","Downsampling","Cold Storage"]},{"term":"Cold Storage","abbr":null,"category":"Databases","definition":"Low-cost, slow-access storage for infrequently used or archival data, often used for old logs and metrics to cut costs.","related":["Data Retention (DB)","Retention","Object Storage"]},{"term":"DevOps","abbr":null,"category":"DevOps & CI/CD","definition":"A culture and set of practices that unite software development and IT operations to shorten the delivery lifecycle through automation, collaboration and continuous feedback.","related":["DevSecOps","Continuous Integration","Site Reliability Engineering"]},{"term":"Continuous Integration","abbr":"CI","category":"DevOps & CI/CD","definition":"The practice of frequently merging code changes into a shared repository, where each change is automatically built and tested to catch integration problems early.","related":["Continuous Delivery","Pipeline (CI/CD)","Build","Shift Left"]},{"term":"Continuous Delivery","abbr":"CD","category":"DevOps & CI/CD","definition":"Extending CI so that code is always in a releasable state and can be deployed to production at any time with a manual approval step.","related":["Continuous Integration","Continuous Deployment","Pipeline (CI/CD)"]},{"term":"Continuous Deployment","abbr":null,"category":"DevOps & CI/CD","definition":"An extension of continuous delivery where every change that passes automated tests is released to production automatically, with no manual gate.","related":["Continuous Delivery","Pipeline (CI/CD)","Feature Flag"]},{"term":"Pipeline (CI/CD)","abbr":null,"category":"DevOps & CI/CD","definition":"An automated sequence of stages — build, test, scan, deploy — that code changes flow through on their way to production, defined as code and triggered on commits.","related":["Continuous Integration","Build","Artifact"]},{"term":"Build","abbr":null,"category":"DevOps & CI/CD","definition":"The process of compiling source code and packaging it (and its dependencies) into a runnable artifact such as a binary, container image or archive.","related":["Artifact","Pipeline (CI/CD)","Container Image"]},{"term":"Artifact","abbr":null,"category":"DevOps & CI/CD","definition":"A versioned output of a build — such as a binary, package or container image — stored in a repository and promoted through environments.","related":["Artifact Repository","Build","Container Image"]},{"term":"Artifact Repository","abbr":null,"category":"DevOps & CI/CD","definition":"A storage system for build artifacts and dependencies (e.g., Artifactory, Nexus, container registries) that versions and serves them to pipelines and runtimes.","related":["Artifact","Container Registry","Package Manager"]},{"term":"Blue Green Deployment","abbr":null,"category":"DevOps & CI/CD","definition":"A release strategy that runs two identical environments (blue and green); traffic is switched to the new version all at once, enabling instant rollback by switching back.","related":["Canary Deployment","Rolling Update","Rollback"]},{"term":"Progressive Delivery","abbr":null,"category":"DevOps & CI/CD","definition":"An evolution of continuous delivery that gradually exposes changes (via canaries, feature flags and A/B tests) with automated analysis and rollback based on metrics.","related":["Canary Deployment","Feature Flag","Continuous Delivery"]},{"term":"Feature Flag","abbr":null,"category":"DevOps & CI/CD","definition":"A configuration switch that turns functionality on or off at runtime without deploying new code, enabling gradual rollouts, experiments and quick disabling of features.","related":["Progressive Delivery","Canary Deployment","A/B Testing"]},{"term":"Rollback","abbr":null,"category":"DevOps & CI/CD","definition":"Reverting a system to a previous known-good version after a faulty deployment, a key capability for limiting the impact of bad releases.","related":["Blue Green Deployment","Rolling Update","Deployment"]},{"term":"Pull Request","abbr":"PR","category":"DevOps & CI/CD","definition":"A proposed set of code changes submitted for review and merging into a branch, where teammates discuss, review and approve before integration.","related":["Code Review","Version Control","Continuous Integration"]},{"term":"Version Control","abbr":null,"category":"DevOps & CI/CD","definition":"A system (such as Git) that tracks changes to code over time, enabling collaboration, history, branching and the ability to revert.","related":["Git","Pull Request","Repository"]},{"term":"Git","abbr":null,"category":"DevOps & CI/CD","definition":"A distributed version-control system that tracks source-code changes, enabling branching, merging and collaboration across teams.","related":["Version Control","Repository","GitOps"]},{"term":"Repository","abbr":null,"category":"DevOps & CI/CD","definition":"A storage location for a project's code and its full version history, hosted on platforms like GitHub or GitLab.","related":["Version Control","Git","Pull Request"]},{"term":"Code Review","abbr":null,"category":"DevOps & CI/CD","definition":"The practice of having peers examine code changes before they merge, improving quality, sharing knowledge and catching defects early.","related":["Pull Request","Shift Left"]},{"term":"Package Manager","abbr":null,"category":"DevOps & CI/CD","definition":"A tool that automates installing, upgrading and resolving dependencies of software packages (e.g., npm, pip, Maven, Helm).","related":["Dependency","Artifact Repository","Helm"]},{"term":"Dependency","abbr":null,"category":"DevOps & CI/CD","definition":"An external library or component that software relies on to function; managing dependencies and their versions is critical for reproducible, secure builds.","related":["Package Manager","Software Supply Chain","SBOM"]},{"term":"Software Supply Chain","abbr":null,"category":"Security & SIEM","definition":"Everything involved in building and delivering software — code, dependencies, build systems and pipelines — whose integrity must be protected against tampering.","related":["SBOM","Dependency","DevSecOps","Provenance"]},{"term":"SBOM","abbr":"SBOM","category":"Security & SIEM","definition":"Software Bill of Materials — a formal, machine-readable inventory of all components and dependencies in a piece of software, used for security and license tracking.","related":["Software Supply Chain","Dependency","Vulnerability"]},{"term":"Provisioning","abbr":null,"category":"DevOps & CI/CD","definition":"The act of setting up and configuring the infrastructure (servers, networks, storage) needed to run applications, increasingly automated via IaC.","related":["Infrastructure as Code","Terraform","Configuration Management"]},{"term":"Configuration Management","abbr":null,"category":"DevOps & CI/CD","definition":"Maintaining systems in a desired, consistent state by automating the setup of software and settings, using tools like Ansible, Puppet or Chef.","related":["Infrastructure as Code","Configuration Drift","Provisioning"]},{"term":"Ansible","abbr":null,"category":"DevOps & CI/CD","definition":"An open-source automation tool for configuration management, application deployment and orchestration, using agentless, YAML-based playbooks.","related":["Configuration Management","Infrastructure as Code"]},{"term":"Idempotent Deployment","abbr":null,"category":"DevOps & CI/CD","definition":"A deployment that produces the same result no matter how many times it is applied, allowing safe re-runs — a core property of declarative IaC tooling.","related":["Idempotence","Declarative Configuration","Infrastructure as Code"]},{"term":"Environment","abbr":null,"category":"DevOps & CI/CD","definition":"A distinct, isolated context where software runs — such as development, staging or production — each with its own configuration and data.","related":["Staging","Production","Configuration as Code"]},{"term":"Staging","abbr":null,"category":"DevOps & CI/CD","definition":"A pre-production environment that mirrors production as closely as possible, used to validate releases before they go live.","related":["Environment","Production","Canary Deployment"]},{"term":"Production","abbr":null,"category":"DevOps & CI/CD","definition":"The live environment where software serves real users; problems here have direct business impact, making observability and safe-release practices essential.","related":["Environment","Staging","Observability"]},{"term":"Dogfooding","abbr":null,"category":"DevOps & CI/CD","definition":"The practice of using your own product internally before or alongside customers to catch issues and build empathy with users. Also called 'eating your own dog food'.","related":["Production","Feature Flag"]},{"term":"Value Stream","abbr":null,"category":"DevOps & CI/CD","definition":"The end-to-end sequence of activities required to deliver value to a customer; value-stream mapping reveals bottlenecks and waste in the delivery process.","related":["DevOps","DORA Metrics","Lead Time"]},{"term":"DORA Metrics","abbr":null,"category":"DevOps & CI/CD","definition":"Four key DevOps performance measures from the DORA research program: deployment frequency, lead time for changes, change failure rate, and time to restore service.","related":["Lead Time","Change Failure Rate","MTTR"]},{"term":"Lead Time","abbr":null,"category":"DevOps & CI/CD","definition":"The time from a code change being committed to it running in production; a DORA metric and indicator of delivery speed.","related":["DORA Metrics","Value Stream","Cycle Time"]},{"term":"Change Failure Rate","abbr":null,"category":"DevOps & CI/CD","definition":"The percentage of deployments that cause a failure in production requiring remediation; a DORA metric measuring release quality.","related":["DORA Metrics","Rollback","Deployment Frequency"]},{"term":"Deployment Frequency","abbr":null,"category":"DevOps & CI/CD","definition":"How often an organization successfully releases to production; a DORA metric where higher frequency correlates with stronger delivery performance.","related":["DORA Metrics","Continuous Deployment"]},{"term":"Runner","abbr":null,"category":"DevOps & CI/CD","definition":"A machine or process that executes CI/CD pipeline jobs, such as a GitHub Actions runner or GitLab runner.","related":["Pipeline (CI/CD)","Build","Continuous Integration"]},{"term":"Webhook","abbr":null,"category":"DevOps & CI/CD","definition":"A user-defined HTTP callback triggered by an event (e.g., a code push), used to integrate systems and kick off automation like CI pipelines.","related":["Event-Driven Architecture","API","Pipeline (CI/CD)"]},{"term":"Blameless Culture","abbr":null,"category":"Reliability","definition":"An organizational approach that treats incidents as learning opportunities rather than occasions to assign fault, encouraging honesty and systemic improvement.","related":["Postmortem","Site Reliability Engineering"]},{"term":"Distributed System","abbr":null,"category":"Distributed Systems","definition":"A system whose components run on multiple networked machines and coordinate by passing messages, appearing to users as a single coherent system.","related":["Microservices Architecture","CAP Theorem","Consensus","Fault Tolerance"]},{"term":"Consensus","abbr":null,"category":"Distributed Systems","definition":"The problem of getting multiple distributed nodes to agree on a single value or state despite failures, solved by algorithms like Raft and Paxos.","related":["Raft","Paxos","Quorum","etcd"]},{"term":"Raft","abbr":null,"category":"Distributed Systems","definition":"A consensus algorithm designed to be understandable, electing a leader that replicates a log to followers; used by etcd, Consul and others.","related":["Consensus","Paxos","Leader Election","etcd"]},{"term":"Paxos","abbr":null,"category":"Distributed Systems","definition":"A family of foundational consensus protocols for agreeing on values among unreliable distributed nodes, known for correctness but complexity.","related":["Consensus","Raft","Quorum"]},{"term":"Quorum","abbr":null,"category":"Distributed Systems","definition":"The minimum number of nodes that must agree for an operation to succeed in a distributed system, ensuring consistency despite some node failures.","related":["Consensus","Replication","Split-Brain"]},{"term":"Leader Election","abbr":null,"category":"Distributed Systems","definition":"The process by which distributed nodes select one node to coordinate work; if the leader fails, a new one is elected.","related":["Raft","Consensus","Failover"]},{"term":"Partition Tolerance","abbr":null,"category":"Distributed Systems","definition":"A system's ability to keep operating despite network partitions that split nodes into groups that cannot communicate; one pillar of the CAP theorem.","related":["CAP Theorem","Network Partition","Split-Brain"]},{"term":"Network Partition","abbr":null,"category":"Distributed Systems","definition":"A communication breakdown that divides a distributed system into isolated groups of nodes, forcing trade-offs between consistency and availability.","related":["Partition Tolerance","Split-Brain","CAP Theorem"]},{"term":"Split-Brain","abbr":null,"category":"Distributed Systems","definition":"A failure where a network partition leads multiple nodes to believe they are the leader, risking divergent state and data corruption.","related":["Network Partition","Quorum","Leader Election","Fencing"]},{"term":"Fencing","abbr":null,"category":"Distributed Systems","definition":"Mechanisms that prevent a previously isolated or stale node from corrupting shared state after recovery, such as fencing tokens.","related":["Split-Brain","Distributed Lock"]},{"term":"Distributed Lock","abbr":null,"category":"Distributed Systems","definition":"A lock spanning multiple nodes that ensures only one process accesses a resource at a time across a cluster, often backed by etcd, ZooKeeper or Redis.","related":["Consensus","Concurrency","Fencing"]},{"term":"Two-Phase Commit","abbr":"2PC","category":"Distributed Systems","definition":"A protocol for atomically committing a transaction across multiple nodes using a prepare phase and a commit phase, at the cost of blocking on failures.","related":["Saga","Transaction (DB)","Consensus"]},{"term":"Saga","abbr":null,"category":"Distributed Systems","definition":"A pattern for managing distributed transactions as a sequence of local transactions with compensating actions to undo on failure, avoiding 2PC.","related":["Two-Phase Commit","Eventual Consistency","Microservices Architecture"]},{"term":"Idempotency Key","abbr":null,"category":"Distributed Systems","definition":"A unique token a client sends so a server can detect and ignore duplicate requests, making retried operations safe.","related":["Idempotence","Retry","At-Least-Once Delivery"]},{"term":"Retry","abbr":null,"category":"Distributed Systems","definition":"Re-attempting a failed operation, ideally with backoff and idempotency, to overcome transient errors in distributed systems.","related":["Exponential Backoff","Idempotence","Retry Storm"]},{"term":"Exponential Backoff","abbr":null,"category":"Distributed Systems","definition":"A retry strategy that progressively increases the wait between attempts (often with jitter) to avoid overwhelming a struggling dependency.","related":["Retry","Jitter","Retry Storm"]},{"term":"Retry Storm","abbr":null,"category":"Reliability","definition":"A cascading overload caused by many clients retrying simultaneously against a failing service, often amplifying the original problem.","related":["Retry","Circuit Breaker","Cascading Failure"]},{"term":"Linearizability","abbr":null,"category":"Distributed Systems","definition":"The strongest single-object consistency guarantee, where operations appear to take effect instantaneously in a single global order matching real time.","related":["Strong Consistency","Consensus","Eventual Consistency"]},{"term":"Vector Clock","abbr":null,"category":"Distributed Systems","definition":"A data structure that tracks causal ordering of events across distributed nodes, used to detect concurrency and resolve conflicts.","related":["Clock Skew","Eventual Consistency","CRDT"]},{"term":"Clock Skew","abbr":null,"category":"Distributed Systems","definition":"The difference in time readings between machines' clocks, which complicates ordering events and correlating telemetry across hosts.","related":["NTP","Vector Clock","Distributed Tracing"]},{"term":"CRDT","abbr":"CRDT","category":"Distributed Systems","definition":"Conflict-free Replicated Data Type — a data structure that can be updated independently on multiple replicas and merged without conflicts, enabling eventual consistency.","related":["Eventual Consistency","Vector Clock"]},{"term":"Gossip Protocol","abbr":null,"category":"Distributed Systems","definition":"A decentralized communication method where nodes periodically exchange state with random peers, spreading information reliably across large clusters.","related":["Service Discovery","Eventual Consistency"]},{"term":"Fault Tolerance","abbr":null,"category":"Distributed Systems","definition":"The capacity of a system to continue operating correctly despite the failure of some of its components, through redundancy and graceful degradation.","related":["Resilience","Redundancy","Graceful Degradation"]},{"term":"Graceful Degradation","abbr":null,"category":"Distributed Systems","definition":"Designing a system to reduce functionality rather than fail completely when components are unavailable, preserving core service.","related":["Fault Tolerance","Load Shedding","Resilience"]},{"term":"Bulkhead","abbr":null,"category":"Distributed Systems","definition":"A resilience pattern that isolates resources into compartments so a failure in one does not exhaust resources and sink the whole system.","related":["Circuit Breaker","Blast Radius","Resilience"]},{"term":"Fan-Out","abbr":null,"category":"Distributed Systems","definition":"A pattern where one request triggers many downstream calls in parallel; large fan-out amplifies tail latency and load.","related":["Tail Latency","Fan-In","Backpressure"]},{"term":"Fan-In","abbr":null,"category":"Distributed Systems","definition":"A pattern where many sources converge into one component, which can become a bottleneck or single point of failure.","related":["Fan-Out","Bottleneck","Aggregation"]},{"term":"Concurrency","abbr":null,"category":"Distributed Systems","definition":"Multiple computations making progress at overlapping times; managing shared state safely under concurrency is a core systems challenge.","related":["Parallelism","Race Condition","Distributed Lock"]},{"term":"Parallelism","abbr":null,"category":"Distributed Systems","definition":"Executing multiple computations literally at the same time on multiple cores or machines to increase throughput.","related":["Concurrency","Horizontal Scaling"]},{"term":"Race Condition","abbr":null,"category":"Distributed Systems","definition":"A bug where the outcome depends on the unpredictable timing of concurrent operations accessing shared state.","related":["Concurrency","Distributed Lock","Idempotence"]},{"term":"Bottleneck","abbr":null,"category":"Distributed Systems","definition":"The component that limits the overall throughput or performance of a system; identifying and relieving it is central to performance work.","related":["Saturation","Fan-In","Capacity Planning"]},{"term":"NTP","abbr":"NTP","category":"Distributed Systems","definition":"Network Time Protocol — a protocol for synchronizing clocks across machines over a network, reducing clock skew important for ordered telemetry.","related":["Clock Skew","Timestamp"]},{"term":"Heartbeating","abbr":null,"category":"Distributed Systems","definition":"Nodes periodically signaling that they are alive so peers or coordinators can detect failures and react (e.g., trigger failover).","related":["Heartbeat","Failover","Leader Election"]},{"term":"Horizontal Scaling","abbr":null,"category":"Distributed Systems","definition":"Adding more machines/instances to handle increased load (scaling out), the cloud-native approach to scale, versus adding power to one machine.","related":["Vertical Scaling","Auto-Scaling","Stateless Apps"]},{"term":"Vertical Scaling","abbr":null,"category":"Distributed Systems","definition":"Increasing the capacity of a single machine (more CPU, memory) to handle load (scaling up), limited by hardware ceilings.","related":["Horizontal Scaling","Right-Sizing"]},{"term":"Scalability","abbr":null,"category":"Distributed Systems","definition":"A system's ability to handle growing load by adding resources, ideally with proportional cost and without redesign.","related":["Horizontal Scaling","Elasticity","Throughput"]},{"term":"Event Sourcing","abbr":null,"category":"Architecture","definition":"Persisting state as an immutable sequence of events rather than current values, enabling full history, replay and auditing.","related":["CQRS","Event-Driven Architecture","Event Streaming"]},{"term":"CQRS","abbr":"CQRS","category":"Architecture","definition":"Command Query Responsibility Segregation — separating the write model from the read model so each can be optimized independently.","related":["Event Sourcing","Architecture"]},{"term":"Service-Oriented Architecture","abbr":"SOA","category":"Architecture","definition":"An architectural style organizing software as reusable, loosely coupled services communicating over a network, a precursor to microservices.","related":["Microservices Architecture","API","ESB"]},{"term":"Strangler Fig Pattern","abbr":null,"category":"Architecture","definition":"Incrementally replacing a legacy system by routing functionality to new services over time until the old system can be retired.","related":["Microservices Architecture","Monolithic Apps","Migration"]},{"term":"Datadog","abbr":null,"category":"Standards & Tools","definition":"A SaaS observability and security platform unifying metrics, traces, logs, RUM, synthetics and more, known for broad integrations and its tagging model.","related":["Watchdog","Agent","Single Pane of Glass"]},{"term":"New Relic","abbr":null,"category":"Standards & Tools","definition":"An observability platform centered on a unified telemetry database (NRDB) and the NRQL query language, covering APM, infrastructure, logs and digital experience.","related":["NRQL","MELT","Apdex"]},{"term":"Dynatrace","abbr":null,"category":"Standards & Tools","definition":"An observability platform built on the OneAgent and Davis causal AI, providing automatic instrumentation, topology (Smartscape) and deterministic root cause analysis.","related":["OneAgent","Davis AI","PurePath","Smartscape"]},{"term":"Splunk","abbr":null,"category":"Standards & Tools","definition":"A platform for searching, analyzing and visualizing machine data, widely used for log analytics, SIEM and observability via Splunk Observability Cloud.","related":["Log Aggregation","SIEM","SPL"]},{"term":"SPL","abbr":"SPL","category":"Standards & Tools","definition":"Search Processing Language — Splunk's query language for searching, filtering and transforming machine data and logs.","related":["Splunk","Query","NRQL"]},{"term":"NRQL","abbr":"NRQL","category":"Standards & Tools","definition":"New Relic Query Language — a SQL-like language for querying telemetry stored in New Relic's database to build charts and alerts.","related":["New Relic","Query","PromQL"]},{"term":"AppDynamics","abbr":null,"category":"Standards & Tools","definition":"A Cisco APM platform centered on business transactions, baselining and health rules, tying application performance to business outcomes.","related":["Business Transaction","Health Rule","Dynamic Baseline"]},{"term":"Sumo Logic","abbr":null,"category":"Standards & Tools","definition":"A cloud-native machine-data analytics platform for logs, metrics and security, delivered as SaaS.","related":["Log Aggregation","SIEM","Observability"]},{"term":"Coralogix","abbr":null,"category":"Standards & Tools","definition":"An observability platform that processes logs, metrics and traces in-stream to reduce storage cost while preserving analytics.","related":["Telemetry Pipeline","Log Aggregation","Data Volume"]},{"term":"Honeycomb","abbr":null,"category":"Standards & Tools","definition":"An observability tool built for high-cardinality, event-based analysis and fast exploratory querying of traces and wide events.","related":["Cardinality","Distributed Tracing","Wide Event"]},{"term":"Chronosphere","abbr":null,"category":"Standards & Tools","definition":"A cloud-native observability platform focused on Prometheus-compatible metrics at scale with strong cost-control and telemetry-pipeline capabilities.","related":["Prometheus","Telemetry Pipeline","Long-Term Storage"]},{"term":"Grafana Cloud","abbr":null,"category":"Standards & Tools","definition":"Grafana Labs' managed observability stack (metrics with Mimir, logs with Loki, traces with Tempo, profiles with Pyroscope) plus Grafana dashboards.","related":["Grafana","Mimir","Loki","Tempo"]},{"term":"Azure Monitor","abbr":null,"category":"Standards & Tools","definition":"Microsoft Azure's native monitoring service for collecting and analyzing metrics and logs across Azure resources and applications.","related":["Application Insights","Cloud Monitoring","Amazon CloudWatch"]},{"term":"Application Insights","abbr":null,"category":"Standards & Tools","definition":"The application performance monitoring feature of Azure Monitor, providing distributed tracing, metrics and diagnostics for apps.","related":["Azure Monitor","Application Performance Monitoring","Distributed Tracing"]},{"term":"Google Cloud Operations","abbr":null,"category":"Standards & Tools","definition":"Google Cloud's observability suite (formerly Stackdriver) for monitoring, logging, tracing and profiling of GCP and hybrid workloads.","related":["Cloud Monitoring","Distributed Tracing","Amazon CloudWatch"]},{"term":"AWS X-Ray","abbr":null,"category":"Standards & Tools","definition":"An AWS service for distributed tracing that helps analyze and debug request flows across microservices and AWS resources.","related":["Distributed Tracing","Service Map","Amazon CloudWatch"]},{"term":"Wide Event","abbr":null,"category":"Tracing","definition":"A single, richly attributed event capturing many fields about a unit of work, enabling flexible high-cardinality analysis without predefining metrics.","related":["Honeycomb","Structured Logging","Cardinality"]},{"term":"Azure Functions","abbr":null,"category":"Cloud Providers","definition":"Microsoft Azure's serverless function-as-a-service for running event-driven code without managing infrastructure.","related":["Function as a Service","AWS Lambda","Serverless"]},{"term":"Cloud Run","abbr":null,"category":"Cloud Providers","definition":"Google Cloud's serverless platform for running containers that scale automatically, including to zero, billed per use.","related":["Serverless Container","AWS Fargate","Serverless"]},{"term":"AWS Fargate","abbr":null,"category":"Cloud Providers","definition":"A serverless compute engine for running containers on AWS ECS and EKS without provisioning or managing servers.","related":["Serverless Container","Amazon ECS","Amazon EKS"]},{"term":"Amazon ECS","abbr":"ECS","category":"Cloud Providers","definition":"Amazon Elastic Container Service — AWS's container orchestration service for running and scaling Docker containers.","related":["AWS Fargate","Amazon EKS","Container Orchestration"]},{"term":"Amazon ECR","abbr":"ECR","category":"Cloud Providers","definition":"Amazon Elastic Container Registry — AWS's managed container image registry for storing and distributing images.","related":["Container Registry","Amazon ECS","Container Image"]},{"term":"DynamoDB","abbr":null,"category":"Cloud Providers","definition":"Amazon's fully managed, serverless NoSQL key-value and document database offering single-digit-millisecond performance at scale.","related":["NoSQL","Key-Value Store","Managed Service"]},{"term":"Amazon Aurora","abbr":null,"category":"Cloud Providers","definition":"AWS's managed relational database compatible with MySQL and PostgreSQL, offering higher performance, scalability and availability.","related":["Amazon RDS","Relational Database","Read Replica"]},{"term":"Amazon SQS","abbr":"SQS","category":"Cloud Providers","definition":"Amazon Simple Queue Service — a fully managed message queue for decoupling and scaling distributed components.","related":["Message Queue","Amazon SNS","Dead Letter Queue"]},{"term":"Amazon SNS","abbr":"SNS","category":"Cloud Providers","definition":"Amazon Simple Notification Service — a managed pub/sub messaging service for fan-out delivery to subscribers and endpoints.","related":["Pub/Sub","Amazon SQS","Event-Driven Architecture"]},{"term":"Amazon Kinesis","abbr":null,"category":"Cloud Providers","definition":"AWS's managed platform for real-time streaming data ingestion and processing at scale.","related":["Event Streaming","Kafka","Stream Processing"]},{"term":"Amazon EventBridge","abbr":null,"category":"Cloud Providers","definition":"A serverless event bus on AWS that routes events between applications and services using rules.","related":["Event-Driven Architecture","Webhook","Pub/Sub"]},{"term":"AWS Step Functions","abbr":null,"category":"Cloud Providers","definition":"An AWS service for orchestrating multi-step serverless workflows as state machines with built-in error handling and retries.","related":["Serverless","Saga","Workflow"]},{"term":"Amazon CloudFront","abbr":null,"category":"Cloud Providers","definition":"AWS's content delivery network that caches and serves content from edge locations close to users.","related":["CDN","Edge Computing","Point of Presence"]},{"term":"Amazon Route 53","abbr":null,"category":"Cloud Providers","definition":"AWS's scalable DNS and domain-registration service with health checks and traffic-routing policies.","related":["DNS","Health Check","Anycast"]},{"term":"BigQuery","abbr":null,"category":"Cloud Providers","definition":"Google Cloud's serverless, highly scalable data warehouse for fast SQL analytics over very large datasets.","related":["Data Warehouse","OLAP","Columnar Database"]},{"term":"Azure Blob Storage","abbr":null,"category":"Cloud Providers","definition":"Microsoft Azure's object storage service for unstructured data such as files, backups and media.","related":["Object Storage","Amazon S3","Blob"]},{"term":"Cosmos DB","abbr":null,"category":"Cloud Providers","definition":"Azure's globally distributed, multi-model NoSQL database with tunable consistency and low-latency access.","related":["NoSQL","Eventual Consistency","Managed Service"]},{"term":"Apache Spark","abbr":null,"category":"Data & Streaming","definition":"A distributed engine for large-scale batch and stream data processing and analytics, popular in big-data and ML pipelines.","related":["Batch Processing","Stream Processing","Apache Flink"]},{"term":"Apache Flink","abbr":null,"category":"Data & Streaming","definition":"A distributed engine for stateful stream processing with low latency and strong consistency guarantees.","related":["Stream Processing","Apache Spark","Event Streaming"]},{"term":"Apache Airflow","abbr":null,"category":"Data & Streaming","definition":"An open-source platform to author, schedule and monitor data workflows as code, using directed acyclic graphs (DAGs).","related":["DAG","Data Pipeline","ETL"]},{"term":"DAG","abbr":"DAG","category":"Data & Streaming","definition":"Directed Acyclic Graph — a structure of tasks with dependencies and no cycles, used to model data and CI/CD workflows.","related":["Apache Airflow","Data Pipeline","Pipeline (CI/CD)"]},{"term":"dbt","abbr":null,"category":"Data & Streaming","definition":"A tool for transforming data in the warehouse using modular, version-controlled SQL, bringing software engineering practices to analytics.","related":["ELT","Data Warehouse","Data Pipeline"]},{"term":"Snowflake","abbr":null,"category":"Data & Streaming","definition":"A cloud data platform separating storage and compute for elastic, scalable analytics and data sharing.","related":["Data Warehouse","BigQuery","OLAP"]},{"term":"Databricks","abbr":null,"category":"Data & Streaming","definition":"A unified analytics and AI platform built on Apache Spark and the lakehouse architecture for data engineering and machine learning.","related":["Data Lakehouse","Apache Spark","MLOps"]},{"term":"Change Data Capture","abbr":"CDC","category":"Data & Streaming","definition":"A technique that captures and streams row-level changes from a database so downstream systems stay in sync in near real time.","related":["Event Streaming","Replication","Data Pipeline"]},{"term":"Data Observability","abbr":null,"category":"Data & Streaming","definition":"Monitoring the health of data and pipelines — freshness, volume, schema, distribution and lineage — to catch data quality issues before they cause harm.","related":["Data Quality","Data Lineage","Schema Drift"]},{"term":"Data Quality","abbr":null,"category":"Data & Streaming","definition":"The degree to which data is accurate, complete, consistent and timely for its intended use; poor data quality undermines analytics and ML.","related":["Data Observability","Data Contract","Data Freshness"]},{"term":"Data Lineage","abbr":null,"category":"Data & Streaming","definition":"The end-to-end record of data's origins, movements and transformations, used for trust, debugging and compliance.","related":["Data Observability","Data Catalog","Provenance"]},{"term":"Data Freshness","abbr":null,"category":"Data & Streaming","definition":"How up to date data is relative to expectations; stale data is a common data-quality and pipeline failure signal.","related":["Data Observability","Data Quality","Staleness"]},{"term":"Schema Drift","abbr":null,"category":"Data & Streaming","definition":"Unexpected changes to a data source's schema that can break downstream pipelines if not detected and handled.","related":["Schema Evolution","Data Observability","Configuration Drift"]},{"term":"Data Contract","abbr":null,"category":"Data & Streaming","definition":"An agreement between data producers and consumers specifying schema, semantics and quality guarantees, enforced to prevent breaking changes.","related":["Schema Registry","Data Quality","API"]},{"term":"Data Catalog","abbr":null,"category":"Data & Streaming","definition":"A searchable inventory of an organization's data assets with metadata, ownership and lineage, helping people find and trust data.","related":["Data Lineage","Service Catalog","Metadata"]},{"term":"Data Mesh","abbr":null,"category":"Architecture","definition":"A decentralized data architecture where domain teams own their data as products, with federated governance and self-serve infrastructure.","related":["Data Lakehouse","Data Contract","Microservices Architecture"]},{"term":"Materialized View","abbr":null,"category":"Databases","definition":"A precomputed, stored result of a query that speeds up reads at the cost of refresh overhead, used for analytics and recording-rule-like patterns.","related":["Query Optimization","Recording Rule","OLAP"]},{"term":"Provenance","abbr":null,"category":"Security & SIEM","definition":"Verifiable records of where an artifact or data came from and how it was produced, key to software supply-chain integrity and data trust.","related":["Software Supply Chain","Data Lineage","SBOM"]},{"term":"MLOps","abbr":null,"category":"AIOps","definition":"Practices and tooling for reliably deploying, monitoring and maintaining machine-learning models in production, applying DevOps principles to ML.","related":["Model Monitoring","ML Pipeline","Model Registry"]},{"term":"ML Pipeline","abbr":null,"category":"AIOps","definition":"An automated workflow covering data preparation, training, evaluation and deployment of machine-learning models.","related":["MLOps","Feature Store","DAG"]},{"term":"Model Registry","abbr":null,"category":"AIOps","definition":"A central store for versioned ML models with metadata, stage (staging/production) and lineage, supporting governance and rollback.","related":["MLOps","Model Monitoring","Artifact Repository"]},{"term":"Feature Store","abbr":null,"category":"AIOps","definition":"A system for managing, storing and serving curated features for training and inference consistently across models.","related":["ML Pipeline","MLOps","Training"]},{"term":"Training","abbr":null,"category":"AIOps","definition":"The process of fitting a machine-learning model to data so it learns patterns it can later apply to new inputs.","related":["Inference","Model Drift","ML Pipeline"]},{"term":"Inference Latency","abbr":null,"category":"AIOps","definition":"The time a model takes to return a prediction for an input, a critical performance metric for AI applications.","related":["Inference","Latency","Token Usage"]},{"term":"GPU Utilization","abbr":null,"category":"Infrastructure","definition":"The fraction of a GPU's compute capacity in use; a key signal for monitoring and right-sizing expensive AI/ML workloads.","related":["Utilization","Inference","Cost Optimization"]},{"term":"Vector Database","abbr":null,"category":"AIOps","definition":"A database optimized for storing and querying high-dimensional embeddings by similarity, foundational to retrieval-augmented generation.","related":["Embedding","RAG","NoSQL"]},{"term":"RAG","abbr":"RAG","category":"AIOps","definition":"Retrieval-Augmented Generation — augmenting an LLM's prompt with relevant external data retrieved at query time to improve accuracy and reduce hallucination.","related":["Vector Database","Embedding","Hallucination"]},{"term":"Context Window","abbr":null,"category":"AIOps","definition":"The maximum amount of text (measured in tokens) a language model can consider at once; exceeding it forces truncation or summarization.","related":["Token Usage","Prompt","LLM Observability"]},{"term":"AI Agent","abbr":null,"category":"AIOps","definition":"An autonomous system that uses an LLM to plan and take actions via tools to accomplish goals, requiring observability of its steps, costs and outcomes.","related":["LLM Observability","Guardrails","Token Usage"]},{"term":"Bias (ML)","abbr":null,"category":"AIOps","definition":"Systematic, unfair skew in a model's outputs arising from data or design, monitored and mitigated for fairness and reliability.","related":["Explainability","Model Monitoring","Data Quality"]},{"term":"SAST","abbr":"SAST","category":"Security & SIEM","definition":"Static Application Security Testing — analyzing source code or binaries for vulnerabilities without executing the program.","related":["DAST","Shift Left","Vulnerability"]},{"term":"DAST","abbr":"DAST","category":"Security & SIEM","definition":"Dynamic Application Security Testing — probing a running application from the outside for vulnerabilities.","related":["SAST","Penetration Testing","WAF"]},{"term":"Secret Scanning","abbr":null,"category":"Security & SIEM","definition":"Automatically detecting hardcoded credentials and keys in code and configuration before they leak.","related":["Secrets Management","Software Supply Chain","Redaction"]},{"term":"Privilege Escalation","abbr":null,"category":"Security & SIEM","definition":"An attacker gaining higher permissions than initially granted, a key step in many breaches that detection aims to catch.","related":["Least Privilege","Lateral Movement","Threat Detection"]},{"term":"Lateral Movement","abbr":null,"category":"Security & SIEM","definition":"An attacker moving through a network from an initial foothold to reach additional systems and data.","related":["Privilege Escalation","Kill Chain","Zero Trust Architecture"]},{"term":"Data Exfiltration","abbr":null,"category":"Security & SIEM","definition":"The unauthorized transfer of data out of an organization, a primary goal of many attacks and a focus of DLP and detection.","related":["Data Loss Prevention","Kill Chain","Egress"]},{"term":"SOC 2","abbr":null,"category":"Security & SIEM","definition":"A compliance framework and audit report on a service organization's controls for security, availability, confidentiality and privacy.","related":["Compliance","Audit Log","Security Posture"]},{"term":"GDPR","abbr":"GDPR","category":"Security & SIEM","definition":"The EU General Data Protection Regulation governing the processing and protection of personal data, with strict consent and rights requirements.","related":["PII","Compliance","Redaction"]},{"term":"PCI DSS","abbr":"PCI DSS","category":"Security & SIEM","definition":"Payment Card Industry Data Security Standard — security requirements for organizations that handle credit-card data.","related":["Compliance","Encryption at Rest","Audit Log"]},{"term":"Anti-Affinity","abbr":null,"category":"Kubernetes","definition":"Scheduling rules that keep pods apart (e.g., across nodes or zones) to improve fault tolerance and avoid co-locating replicas.","related":["Affinity","Topology Spread","High Availability"]},{"term":"Topology Spread","abbr":null,"category":"Kubernetes","definition":"Constraints that distribute pods evenly across failure domains like nodes and zones to improve resilience and balance.","related":["Anti-Affinity","Availability Zone","High Availability"]},{"term":"Priority Class","abbr":null,"category":"Kubernetes","definition":"A Kubernetes object that assigns scheduling priority to pods, influencing which pods are scheduled first and which are preempted under pressure.","related":["Eviction","QoS Class","Scheduler"]},{"term":"Ephemeral Container","abbr":null,"category":"Kubernetes","definition":"A temporary container added to a running pod for debugging, without restarting it or altering its spec.","related":["Pod","Init Container","kubectl"]},{"term":"Karpenter","abbr":null,"category":"Kubernetes","definition":"An open-source Kubernetes node-autoscaler that rapidly provisions right-sized nodes in response to pending pods, optimizing cost and speed.","related":["Cluster Autoscaler","Node","Auto-Scaling"]},{"term":"Finalizer","abbr":null,"category":"Kubernetes","definition":"A key on a Kubernetes object that blocks its deletion until associated cleanup logic completes, ensuring orderly resource teardown.","related":["Controller","Custom Resource","Reconciliation"]},{"term":"Game Day","abbr":null,"category":"Reliability","definition":"A planned exercise that simulates failures or incidents to test systems, tooling and team response, improving resilience and readiness.","related":["Chaos Engineering","Disaster Recovery","Runbook"]},{"term":"Error Budget Policy","abbr":null,"category":"Reliability","definition":"An agreed set of actions triggered when an error budget is at risk or exhausted, such as freezing feature work to focus on reliability.","related":["Error Budget","SLO","Burn Rate"]},{"term":"Capacity Headroom","abbr":null,"category":"Reliability","definition":"The spare capacity kept in reserve above expected load to absorb spikes and failures without degradation.","related":["Capacity Planning","Saturation","Auto-Scaling"]},{"term":"Fault Injection","abbr":null,"category":"Reliability","definition":"Deliberately introducing errors, latency or failures into a system to validate its resilience and recovery behavior.","related":["Chaos Engineering","Game Day","Resilience"]},{"term":"Workflow","abbr":null,"category":"DevOps & CI/CD","definition":"A defined, often automated sequence of steps or tasks to accomplish a process, such as a CI/CD pipeline or data orchestration.","related":["Pipeline (CI/CD)","DAG","AWS Step Functions"]},{"term":"JSON","abbr":"JSON","category":"Data Formats","definition":"JavaScript Object Notation — a lightweight, human-readable text format for structured data, ubiquitous in APIs, configuration and structured logging.","related":["YAML","XML","Structured Logging","Serialization"]},{"term":"YAML","abbr":"YAML","category":"Data Formats","definition":"A human-friendly data-serialization format using indentation, widely used for configuration files and Kubernetes manifests.","related":["JSON","Manifest","Configuration as Code"]},{"term":"XML","abbr":"XML","category":"Data Formats","definition":"Extensible Markup Language — a verbose, tag-based format for structured data and documents, used in SAML, SOAP and legacy systems.","related":["JSON","SAML"]},{"term":"CSV","abbr":"CSV","category":"Data Formats","definition":"Comma-Separated Values — a simple tabular text format where each line is a row and commas separate fields, common for data exchange.","related":["JSON","Data Pipeline"]},{"term":"Avro","abbr":null,"category":"Data Formats","definition":"A compact, schema-based binary serialization format common in data and streaming pipelines, with strong schema-evolution support.","related":["Serialization","Schema Registry","Parquet"]},{"term":"Parquet","abbr":null,"category":"Data Formats","definition":"A columnar storage file format optimized for analytical queries and compression, widely used in data lakes and warehouses.","related":["Columnar Database","Data Lake","Avro"]},{"term":"Markdown","abbr":null,"category":"Data Formats","definition":"A lightweight markup language for formatting plain text, widely used for documentation, READMEs and runbooks.","related":["Documentation","Runbook"]},{"term":"Base64","abbr":null,"category":"Data Formats","definition":"An encoding that represents binary data as ASCII text, used to embed binary content in text formats like JSON, URLs and Kubernetes Secrets.","related":["Encoding","Secret"]},{"term":"Encoding","abbr":null,"category":"Data Formats","definition":"Converting data from one representation to another (e.g., UTF-8 text, Base64, URL-encoding) for storage or transmission.","related":["Base64","Serialization","Character Set"]},{"term":"Compression","abbr":null,"category":"Data Formats","definition":"Reducing data size to save storage and bandwidth; observability backends heavily compress telemetry to control cost.","related":["Gzip","Downsampling","Data Volume"]},{"term":"Gzip","abbr":null,"category":"Data Formats","definition":"A common lossless compression format and algorithm used to shrink HTTP responses, logs and files.","related":["Compression","HTTP"]},{"term":"Checksum","abbr":null,"category":"Data Formats","definition":"A computed value used to verify data integrity; if data changes, its checksum changes, revealing corruption or tampering.","related":["Hash","Integrity","Provenance"]},{"term":"Hash","abbr":null,"category":"Data Formats","definition":"A fixed-size value produced from input data by a hash function; used for integrity checks, deduplication, indexing and (cryptographically) for security.","related":["Checksum","Hashing","Index (Database)"]},{"term":"Hashing","abbr":null,"category":"Security & SIEM","definition":"Applying a one-way function to data to produce a fixed-size digest, used for password storage, integrity verification and indicators of compromise.","related":["Hash","Encryption at Rest","Indicator of Compromise"]},{"term":"UUID","abbr":"UUID","category":"Data Formats","definition":"Universally Unique Identifier — a 128-bit value used to label entities (requests, resources, traces) with negligible collision risk.","related":["Trace ID","Idempotency Key"]},{"term":"Endpoint","abbr":null,"category":"Networking","definition":"A specific URL or address where an API or service can be accessed to perform an operation.","related":["API","REST","Uptime Check"]},{"term":"Payload","abbr":null,"category":"Networking","definition":"The actual data carried in a request, response or message, as distinct from headers and metadata.","related":["Packet","HTTP","Serialization"]},{"term":"HTTP Header","abbr":null,"category":"Networking","definition":"A key-value field in an HTTP request or response conveying metadata such as content type, authentication and trace context.","related":["HTTP","Context Propagation","Cookie"]},{"term":"Cookie","abbr":null,"category":"Networking","definition":"A small piece of data a server stores in a browser to maintain state such as sessions and preferences across requests.","related":["Session (Web)","HTTP Header","CSRF"]},{"term":"Session (Web)","abbr":null,"category":"Networking","definition":"Server-side state that links a series of requests to one user, typically tracked via a session cookie or token.","related":["Cookie","Token","Stateless Apps"]},{"term":"CORS","abbr":"CORS","category":"Networking","definition":"Cross-Origin Resource Sharing — a browser security mechanism controlling which origins may call an API, enforced via HTTP headers.","related":["HTTP Header","API","XSS"]},{"term":"CSRF","abbr":"CSRF","category":"Security & SIEM","definition":"Cross-Site Request Forgery — an attack that tricks a logged-in user's browser into making unwanted authenticated requests; mitigated with tokens.","related":["XSS","Cookie","Token"]},{"term":"XSS","abbr":"XSS","category":"Security & SIEM","definition":"Cross-Site Scripting — injecting malicious scripts into web pages viewed by other users; mitigated by output encoding and CSP.","related":["CSRF","SQL Injection","WAF"]},{"term":"SQL Injection","abbr":"SQLi","category":"Security & SIEM","definition":"An attack that inserts malicious SQL into inputs to manipulate a database; prevented with parameterized queries and input validation.","related":["XSS","WAF","OWASP"]},{"term":"OWASP","abbr":"OWASP","category":"Security & SIEM","definition":"Open Worldwide Application Security Project — a nonprofit known for the OWASP Top 10 list of the most critical web-application security risks.","related":["XSS","SQL Injection","Vulnerability"]},{"term":"JWT","abbr":"JWT","category":"Security & SIEM","definition":"JSON Web Token — a compact, signed token format carrying claims, commonly used for stateless authentication and authorization.","related":["Token","OAuth","Authentication"]},{"term":"Token","abbr":null,"category":"Security & SIEM","definition":"A credential representing authentication or authorization (e.g., access token, API key) presented to access protected resources.","related":["JWT","OAuth","API Key","Bearer Token"]},{"term":"Bearer Token","abbr":null,"category":"Security & SIEM","definition":"A token that grants access to whoever holds it, sent in the Authorization header; must be protected since possession equals access.","related":["Token","JWT","OAuth"]},{"term":"API Key","abbr":null,"category":"Security & SIEM","definition":"A secret identifier passed with API requests to authenticate and track the caller; simpler but less secure than OAuth tokens.","related":["Token","Authentication","Secrets Management"]},{"term":"Pagination","abbr":null,"category":"Networking","definition":"Splitting large result sets into pages returned across multiple requests (via offsets or cursors) to bound payload size and load.","related":["Cursor","API","Payload"]},{"term":"Cursor","abbr":null,"category":"Networking","definition":"A pointer used in cursor-based pagination to mark a position in a result set, enabling stable, efficient paging through large data.","related":["Pagination","Offset"]},{"term":"Timeout","abbr":null,"category":"Reliability","definition":"A limit on how long an operation may take before being aborted; well-tuned timeouts prevent resources from hanging on slow dependencies.","related":["Retry","Circuit Breaker","Latency Budget"]},{"term":"Latency Budget","abbr":null,"category":"Reliability","definition":"An allocation of allowable latency across the components of a request path, ensuring each stays within limits to meet an overall target.","related":["Latency","SLO","Timeout"]},{"term":"Polling","abbr":null,"category":"Networking","definition":"Repeatedly requesting a resource at intervals to check for changes; simple but can be inefficient compared with push or webhooks.","related":["Long Polling","Webhook","Server-Sent Events"]},{"term":"Long Polling","abbr":null,"category":"Networking","definition":"A technique where the server holds a request open until data is available or a timeout occurs, approximating real-time updates over HTTP.","related":["Polling","WebSocket","Server-Sent Events"]},{"term":"Server-Sent Events","abbr":"SSE","category":"Networking","definition":"A standard for servers to push a stream of updates to a browser over a single long-lived HTTP connection, one-directional.","related":["WebSocket","Long Polling","Event-Driven Architecture"]},{"term":"Filesystem","abbr":null,"category":"Infrastructure","definition":"The OS structure that organizes how data is stored and retrieved on a storage device, managing files, directories and metadata.","related":["inode","Block Storage","Mount"]},{"term":"inode","abbr":null,"category":"Infrastructure","definition":"A filesystem data structure storing metadata about a file (permissions, size, location); running out of inodes can cause failures even with free space.","related":["Filesystem","File Descriptor"]},{"term":"Mount","abbr":null,"category":"Infrastructure","definition":"Attaching a storage volume or filesystem to a directory in the OS so its contents become accessible.","related":["Filesystem","Persistent Volume","Volume"]},{"term":"Volume","abbr":null,"category":"Infrastructure","definition":"A storage unit attached to a host or container for persisting data; in Kubernetes, volumes outlive container restarts within a pod.","related":["Persistent Volume","Block Storage","Mount"]},{"term":"RAID","abbr":"RAID","category":"Infrastructure","definition":"Redundant Array of Independent Disks — combining multiple disks for redundancy, performance, or both, depending on the RAID level.","related":["Redundancy","Block Storage","IOPS"]},{"term":"SSD","abbr":"SSD","category":"Infrastructure","definition":"Solid-State Drive — fast flash-based storage with no moving parts, offering much lower latency and higher IOPS than spinning disks.","related":["IOPS","Disk Latency","NVMe"]},{"term":"NVMe","abbr":"NVMe","category":"Infrastructure","definition":"Non-Volatile Memory Express — a high-performance interface for accessing SSDs over PCIe, delivering very high throughput and low latency.","related":["SSD","IOPS","Disk Latency"]},{"term":"Snapshot (Storage)","abbr":null,"category":"Infrastructure","definition":"A point-in-time copy of a volume or filesystem used for backups and fast restoration.","related":["Backup","Volume","Persistent Volume"]},{"term":"Object","abbr":null,"category":"Databases","definition":"A unit of data in object storage consisting of the data itself, metadata and a unique identifier, stored in a flat namespace.","related":["Object Storage","Storage Bucket","Blob"]},{"term":"Blob","abbr":null,"category":"Databases","definition":"A Binary Large Object — unstructured binary data such as images or backups, stored in object or blob storage.","related":["Object","Object Storage"]},{"term":"OSI Model","abbr":null,"category":"Networking","definition":"A seven-layer conceptual framework (physical to application) describing how network communication functions are organized.","related":["Layer 4","Layer 7","TCP"]},{"term":"Layer 4","abbr":"L4","category":"Networking","definition":"The transport layer of the OSI model (TCP/UDP); L4 load balancers route by IP and port without inspecting application content.","related":["OSI Model","Layer 7","Network Load Balancer"]},{"term":"Layer 7","abbr":"L7","category":"Networking","definition":"The application layer of the OSI model (HTTP, gRPC); L7 proxies and load balancers route based on content like paths and headers.","related":["OSI Model","Layer 4","Application Load Balancer","Envoy"]},{"term":"Gateway","abbr":null,"category":"Networking","definition":"A network node that connects different networks and routes traffic between them, often performing translation or policy enforcement.","related":["Router","API Gateway","NAT"]},{"term":"Router","abbr":null,"category":"Networking","definition":"A device that forwards data packets between networks based on IP addresses and routing tables.","related":["Switch","Gateway","Subnet"]},{"term":"Switch","abbr":null,"category":"Networking","definition":"A device that connects devices within a local network and forwards frames based on MAC addresses.","related":["Router","MAC Address"]},{"term":"MAC Address","abbr":null,"category":"Networking","definition":"A hardware identifier assigned to a network interface, used for communication within a local network segment.","related":["Switch","IP Address"]},{"term":"Tunnel","abbr":null,"category":"Networking","definition":"Encapsulating one network protocol within another to securely or transparently carry traffic across a network, as VPNs do.","related":["VPN","Encryption in Transit"]},{"term":"Proxy","abbr":null,"category":"Networking","definition":"An intermediary server that forwards requests between clients and servers, providing caching, security, load balancing or anonymity.","related":["Reverse Proxy","Forward Proxy","Service Proxy"]},{"term":"Algorithm","abbr":null,"category":"Compute & Runtime","definition":"A finite, well-defined sequence of steps for solving a problem or performing a computation.","related":["Data Structure","Big O Notation"]},{"term":"Data Structure","abbr":null,"category":"Compute & Runtime","definition":"A way of organizing and storing data for efficient access and modification, such as arrays, trees, hash tables and queues.","related":["Algorithm","B-Tree","Queue"]},{"term":"Big O Notation","abbr":null,"category":"Compute & Runtime","definition":"A notation describing how an algorithm's time or space requirements grow with input size, used to compare efficiency.","related":["Algorithm","Data Structure"]},{"term":"B-Tree","abbr":null,"category":"Databases","definition":"A balanced tree data structure that keeps data sorted for efficient lookups, range queries and updates; the basis of many database indexes.","related":["Index (Database)","Data Structure"]},{"term":"Queue","abbr":null,"category":"Compute & Runtime","definition":"A first-in-first-out data structure (and infrastructure pattern) for buffering work between producers and consumers.","related":["Message Queue","Worker","Backpressure"]},{"term":"Worker","abbr":null,"category":"Compute & Runtime","definition":"A process or thread that pulls tasks from a queue and executes them, enabling asynchronous and scalable background processing.","related":["Queue","Job Queue","Thread Pool"]},{"term":"Job Queue","abbr":null,"category":"Data & Streaming","definition":"A queue of units of work waiting to be processed by workers, decoupling task submission from execution.","related":["Queue","Worker","Message Queue"]},{"term":"Mutex","abbr":null,"category":"Compute & Runtime","definition":"A mutual-exclusion lock that ensures only one thread accesses a shared resource at a time, preventing race conditions.","related":["Semaphore","Lock Contention","Race Condition"]},{"term":"Semaphore","abbr":null,"category":"Compute & Runtime","definition":"A synchronization primitive that limits how many threads can access a resource concurrently, generalizing the mutex.","related":["Mutex","Concurrency"]},{"term":"Atomic Operation","abbr":null,"category":"Compute & Runtime","definition":"An operation that completes entirely or not at all with no observable intermediate state, fundamental to safe concurrency.","related":["Concurrency","ACID","Mutex"]},{"term":"Memoization","abbr":null,"category":"Compute & Runtime","definition":"Caching the results of expensive function calls so repeated calls with the same inputs return instantly.","related":["Caching","Cache (CPU/App)"]},{"term":"Idempotent","abbr":null,"category":"Compute & Runtime","definition":"Describing an operation that can be applied multiple times without changing the result beyond the first application; key for safe retries.","related":["Idempotence","Retry","Idempotency Key"]},{"term":"Race Detector","abbr":null,"category":"Compute & Runtime","definition":"A tool that detects data races in concurrent programs by observing memory access patterns at runtime.","related":["Race Condition","Concurrency","Profiler"]},{"term":"Documentation","abbr":null,"category":"DevOps & CI/CD","definition":"Written guidance describing how systems work and how to operate them; good docs reduce toil and speed incident response.","related":["Runbook","Markdown","Service Catalog"]},{"term":"Observable (System)","abbr":null,"category":"Fundamentals","definition":"Describing a system that emits enough high-quality telemetry to let operators understand its internal state and debug novel problems.","related":["Observability","Instrumentation","White-Box Monitoring"]},{"term":"ITOps","abbr":null,"category":"IT Operations","definition":"IT Operations — the people, processes and tools that run, maintain and support an organization's IT infrastructure and services day to day.","related":["AIOps","ITSM","NOC"]},{"term":"ITSM","abbr":"ITSM","category":"IT Operations","definition":"IT Service Management — the practices for designing, delivering, operating and improving IT services to meet business needs, often guided by ITIL.","related":["ITIL","Service Desk","Change Management"]},{"term":"ITIL","abbr":"ITIL","category":"IT Operations","definition":"A widely adopted framework of best practices for IT service management, covering incident, problem, change and service-level processes.","related":["ITSM","Change Management","Problem Management"]},{"term":"Service Desk","abbr":null,"category":"IT Operations","definition":"The single point of contact between users and IT, handling incidents, service requests and communications, often via a ticketing system.","related":["ITSM","Ticket","Incident Management"]},{"term":"Ticket","abbr":null,"category":"IT Operations","definition":"A tracked record of an issue, request or task in a service-management or issue-tracking system, with status, owner and history.","related":["Service Desk","Incident","Change Management"]},{"term":"Change Management","abbr":null,"category":"IT Operations","definition":"The ITSM process for requesting, reviewing, approving and tracking changes to IT systems to minimize risk and disruption.","related":["Change Failure Rate","ITIL","Change Event"]},{"term":"Change Event","abbr":null,"category":"AIOps","definition":"A recorded change to a system (deploy, config update, scaling) correlated with telemetry to explain anomalies and accelerate root cause analysis.","related":["Root Cause Analysis","Deployment","Change Management"]},{"term":"Problem Management","abbr":null,"category":"IT Operations","definition":"The ITIL process of identifying and addressing the underlying causes of recurring incidents to prevent them, distinct from immediate incident response.","related":["Incident Management","Root Cause Analysis","ITIL"]},{"term":"CMDB","abbr":"CMDB","category":"IT Operations","definition":"Configuration Management Database — a repository of IT assets (configuration items) and their relationships, used for impact analysis and change planning.","related":["Configuration Item","Service Catalog","Topology"]},{"term":"Configuration Item","abbr":"CI","category":"IT Operations","definition":"Any component tracked in a CMDB — server, application, network device, service — along with its attributes and dependencies.","related":["CMDB","Asset Management"]},{"term":"NOC","abbr":"NOC","category":"IT Operations","definition":"Network Operations Center — a centralized team and facility that monitors infrastructure and responds to events around the clock.","related":["SOC","Monitoring","On-Call"]},{"term":"SOC","abbr":"SOC","category":"Security & SIEM","definition":"Security Operations Center — a team and facility that continuously monitors, detects and responds to security threats.","related":["NOC","SIEM","Incident Response"]},{"term":"SLA Breach","abbr":null,"category":"IT Operations","definition":"A failure to meet the committed service-level targets in an SLA, which may trigger penalties and reviews.","related":["SLA","SLO","Error Budget"]},{"term":"Uptime","abbr":null,"category":"Reliability","definition":"The amount or percentage of time a system is operational and available, the complement of downtime.","related":["Availability","Downtime","Heartbeat"]},{"term":"Downtime","abbr":null,"category":"Reliability","definition":"A period during which a system is unavailable or not functioning, planned or unplanned; minimizing it is the goal of availability engineering.","related":["Uptime","Maintenance Window","Availability"]},{"term":"Nines","abbr":null,"category":"Reliability","definition":"A shorthand for availability levels by number of nines — 99.9% (three nines) allows ~8.7 hours of downtime/year, 99.99% allows ~52 minutes.","related":["Availability","SLA","Uptime"]},{"term":"Asset Management","abbr":null,"category":"IT Operations","definition":"Tracking and managing IT hardware, software and licenses throughout their lifecycle for cost, compliance and operational control.","related":["CMDB","Configuration Item","Compliance"]},{"term":"Capacity Management","abbr":null,"category":"IT Operations","definition":"Ensuring IT resources meet current and future demand cost-effectively, combining monitoring, forecasting and planning.","related":["Capacity Planning","Forecasting","Right-Sizing"]},{"term":"Service Level Management","abbr":null,"category":"IT Operations","definition":"The ITSM practice of defining, agreeing, monitoring and reporting on service levels (SLAs, SLOs) with stakeholders.","related":["SLA","SLO","ITIL"]},{"term":"Escalation Policy","abbr":null,"category":"Incident","definition":"A defined sequence and timing for routing unacknowledged alerts to additional responders or higher tiers to ensure incidents are handled.","related":["Escalation","On-Call","PagerDuty"]},{"term":"Incident Commander","abbr":null,"category":"Incident","definition":"The person who leads the response to a major incident, coordinating responders, communication and decisions until resolution.","related":["Incident Management","Severity","War Room"]},{"term":"War Room","abbr":null,"category":"Incident","definition":"A dedicated space or virtual channel where responders collaborate intensively to resolve a major incident.","related":["Incident Commander","Incident Management"]},{"term":"Blameless Postmortem","abbr":null,"category":"Reliability","definition":"A retrospective focused on systemic causes and improvements rather than individual blame, encouraging candor and learning after incidents.","related":["Postmortem","Blameless Culture","Root Cause Analysis"]},{"term":"Service Catalog (ITSM)","abbr":null,"category":"IT Operations","definition":"A curated list of IT services available to users with descriptions, request options and service levels; an ITSM counterpart to the engineering service catalog.","related":["Service Catalog","ITSM","Service Desk"]},{"term":"Observability-Driven Development","abbr":"ODD","category":"Fundamentals","definition":"A practice of instrumenting and validating telemetry during development so services are observable from the moment they ship.","related":["Instrumentation","Shift Left","Observability"]},{"term":"Synthetic Baseline","abbr":null,"category":"AIOps","definition":"A reference performance profile built from synthetic tests, used to detect regressions against expected behavior.","related":["Baseline","Synthetic Monitoring","Anomaly Detection"]},{"term":"Topology Mapping","abbr":null,"category":"Visualization","definition":"Discovering and visualizing the entities in an environment and their relationships, foundational to impact analysis and root cause analysis.","related":["Topology","Service Map","CMDB"]},{"term":"Dependency Map","abbr":null,"category":"Visualization","definition":"A visualization of how services and components depend on one another, used to understand impact and trace failures to their source.","related":["Service Map","Topology","Cascading Failure"]},{"term":"Health Check","abbr":null,"category":"Reliability","definition":"An endpoint or probe that reports whether a component is functioning, used by load balancers and orchestrators to route traffic and trigger recovery.","related":["Liveness Probe","Readiness Probe","Load Balancing"]},{"term":"Synthetic Location","abbr":null,"category":"Digital Experience","definition":"A geographic vantage point from which synthetic tests run, enabling measurement of performance and availability as experienced in different regions.","related":["Synthetic Monitoring","Point of Presence","Latency"]},{"term":"Observability Cost","abbr":null,"category":"Standards & Tools","definition":"The spend associated with collecting, storing and querying telemetry; controlling it via sampling, filtering and tiering is a growing discipline.","related":["Data Tiering","Sampling","Telemetry Pipeline","FinOps"]},{"term":"Data Volume","abbr":null,"category":"Standards & Tools","definition":"The amount of telemetry generated and ingested, a primary driver of observability cost and a target for reduction via filtering and aggregation.","related":["Observability Cost","Sampling","Cardinality"]},{"term":"Kubernetes","abbr":"K8s","category":"Kubernetes","definition":"An open-source container-orchestration platform that automates deployment, scaling, networking and management of containerized applications across a cluster of machines.","related":["Cluster","Pod","Control Plane (K8s)","kubelet"]},{"term":"Cluster","abbr":null,"category":"Kubernetes","definition":"A set of worker machines (nodes) that run containerized applications, managed together by a Kubernetes control plane. The fundamental unit of a Kubernetes deployment.","related":["Node","Control Plane (K8s)","Kubernetes"]},{"term":"Control Plane (K8s)","abbr":null,"category":"Kubernetes","definition":"The set of components that govern a Kubernetes cluster — API server, scheduler, controller manager and etcd — making global decisions and maintaining desired state.","related":["API Server","Scheduler","etcd","Controller Manager"]},{"term":"Node","abbr":null,"category":"Kubernetes","definition":"A worker machine (physical or virtual) in a Kubernetes cluster that runs pods, managed by the control plane and running the kubelet and a container runtime.","related":["Pod","kubelet","Cluster","kube-proxy"]},{"term":"Pod","abbr":null,"category":"Kubernetes","definition":"The smallest deployable unit in Kubernetes — one or more containers that share network and storage and are scheduled together on a node.","related":["Container","Node","ReplicaSet","Sidecar Container"]},{"term":"API Server","abbr":null,"category":"Kubernetes","definition":"The front end of the Kubernetes control plane that exposes the Kubernetes API, validates and processes requests, and is the single point through which all components communicate.","related":["Control Plane (K8s)","etcd","kubectl"]},{"term":"etcd","abbr":null,"category":"Kubernetes","definition":"A distributed, consistent key-value store that serves as Kubernetes' backing store for all cluster data and state, using the Raft consensus algorithm.","related":["Control Plane (K8s)","Raft","API Server"]},{"term":"Scheduler","abbr":null,"category":"Kubernetes","definition":"The control-plane component (kube-scheduler) that assigns newly created pods to nodes based on resource requirements, constraints, affinity rules and availability.","related":["Pod","Node","Affinity","Taint and Toleration"]},{"term":"Controller Manager","abbr":null,"category":"Kubernetes","definition":"A control-plane component that runs controller loops which watch cluster state and drive it toward the desired state, handling nodes, replication, endpoints and more.","related":["Controller","Reconciliation","Control Plane (K8s)"]},{"term":"Controller","abbr":null,"category":"Kubernetes","definition":"A control loop that watches the state of a resource through the API server and makes changes to move the current state toward the desired state.","related":["Reconciliation","Operator","Controller Manager"]},{"term":"kubelet","abbr":null,"category":"Kubernetes","definition":"The primary node agent that runs on every node, ensuring the containers described in pod specs are running and healthy, and reporting status back to the control plane.","related":["Node","Pod","Container Runtime","CRI"]},{"term":"kube-proxy","abbr":null,"category":"Kubernetes","definition":"A network proxy running on each node that maintains network rules to implement the Kubernetes Service concept, enabling traffic routing to pods.","related":["Service (K8s)","Node","Networking"]},{"term":"kubectl","abbr":null,"category":"Kubernetes","definition":"The command-line tool for interacting with a Kubernetes cluster through the API server — creating, inspecting, updating and deleting resources.","related":["API Server","Manifest","Kubernetes"]},{"term":"Deployment","abbr":null,"category":"Kubernetes","definition":"A Kubernetes object that declaratively manages a set of identical pods via ReplicaSets, handling rollouts, rollbacks and scaling of stateless applications.","related":["ReplicaSet","Pod","Rolling Update","Stateless Apps"]},{"term":"ReplicaSet","abbr":null,"category":"Kubernetes","definition":"A Kubernetes controller that ensures a specified number of identical pod replicas are running at any time, typically managed by a Deployment.","related":["Deployment","Pod","Controller"]},{"term":"StatefulSet","abbr":null,"category":"Kubernetes","definition":"A workload object for managing stateful applications, giving pods stable, unique network identities and persistent storage that survive rescheduling.","related":["Stateful Apps","Persistent Volume","Headless Service"]},{"term":"DaemonSet","abbr":null,"category":"Kubernetes","definition":"A controller that ensures a copy of a pod runs on all (or selected) nodes, commonly used for node-level agents like log collectors and monitoring daemons.","related":["Node","Pod","Agent"]},{"term":"Job","abbr":null,"category":"Kubernetes","definition":"A Kubernetes object that runs one or more pods to completion for a finite task, retrying until the specified number of successful completions is reached.","related":["CronJob","Pod"]},{"term":"CronJob","abbr":null,"category":"Kubernetes","definition":"A Kubernetes object that creates Jobs on a repeating schedule, similar to cron, for periodic or recurring tasks.","related":["Job","Scheduler"]},{"term":"Service (K8s)","abbr":null,"category":"Kubernetes","definition":"An abstraction that defines a stable network endpoint and load-balancing policy for a logical set of pods, decoupling clients from individual pod IPs.","related":["Pod","kube-proxy","Ingress","ClusterIP"]},{"term":"ClusterIP","abbr":null,"category":"Kubernetes","definition":"The default Service type that exposes a service on an internal cluster IP, reachable only from within the cluster.","related":["Service (K8s)","NodePort","LoadBalancer (K8s)"]},{"term":"NodePort","abbr":null,"category":"Kubernetes","definition":"A Service type that exposes a service on a static port on every node's IP, making it reachable from outside the cluster.","related":["Service (K8s)","ClusterIP","LoadBalancer (K8s)"]},{"term":"LoadBalancer (K8s)","abbr":null,"category":"Kubernetes","definition":"A Service type that provisions an external load balancer (via the cloud provider) to route outside traffic to the service's pods.","related":["Service (K8s)","NodePort","Load Balancing"]},{"term":"Headless Service","abbr":null,"category":"Kubernetes","definition":"A Service with no cluster IP that returns the individual pod IPs via DNS, used when clients need direct, stable addressing of each pod (e.g., StatefulSets).","related":["Service (K8s)","StatefulSet","DNS"]},{"term":"Ingress","abbr":null,"category":"Kubernetes","definition":"A Kubernetes object that manages external HTTP/HTTPS access to services, providing routing rules, TLS termination and virtual hosting via an ingress controller.","related":["Ingress Controller","Service (K8s)","API Gateway"]},{"term":"Ingress Controller","abbr":null,"category":"Kubernetes","definition":"The component (e.g., NGINX or Traefik) that fulfills Ingress rules by configuring a load balancer or proxy to route external traffic to services.","related":["Ingress","Reverse Proxy","Load Balancing"]},{"term":"Gateway API","abbr":null,"category":"Kubernetes","definition":"A newer, more expressive Kubernetes standard for managing ingress and traffic routing, designed to supersede Ingress with role-oriented, extensible resources.","related":["Ingress","Service Mesh","API Gateway"]},{"term":"Namespace (K8s)","abbr":null,"category":"Kubernetes","definition":"A virtual cluster within a physical cluster used to divide resources among multiple users or teams, providing scoping for names, quotas and access control.","related":["RBAC","Resource Quota","Multitenancy"]},{"term":"ConfigMap","abbr":null,"category":"Kubernetes","definition":"A Kubernetes object that stores non-confidential configuration data as key-value pairs, which pods consume as environment variables, command args or files.","related":["Secret","Pod","Configuration as Code"]},{"term":"Secret","abbr":null,"category":"Kubernetes","definition":"A Kubernetes object for storing sensitive data such as passwords, tokens and keys, kept separate from pod specs and optionally encrypted at rest.","related":["ConfigMap","Secrets Management","Encryption at Rest"]},{"term":"Label","abbr":null,"category":"Kubernetes","definition":"A key-value pair attached to Kubernetes objects used to organize and select subsets of resources, for example matching pods to a Service or Deployment.","related":["Selector","Annotation","Tag"]},{"term":"Selector","abbr":null,"category":"Kubernetes","definition":"A query that matches Kubernetes objects by their labels, used by Services, Deployments and other controllers to identify the resources they act on.","related":["Label","Service (K8s)","ReplicaSet"]},{"term":"Annotation","abbr":null,"category":"Kubernetes","definition":"A key-value pair attached to Kubernetes objects for storing arbitrary non-identifying metadata, often consumed by tools and controllers rather than for selection.","related":["Label","Metadata"]},{"term":"Persistent Volume","abbr":"PV","category":"Kubernetes","definition":"A cluster-level storage resource provisioned by an administrator or dynamically, whose lifecycle is independent of any individual pod.","related":["Persistent Volume Claim","Storage Class","StatefulSet"]},{"term":"Persistent Volume Claim","abbr":"PVC","category":"Kubernetes","definition":"A user's request for storage that binds to a Persistent Volume, specifying size and access mode so pods can consume durable storage.","related":["Persistent Volume","Storage Class"]},{"term":"Storage Class","abbr":null,"category":"Kubernetes","definition":"A Kubernetes object that defines a class of storage (performance, backend, reclaim policy) enabling dynamic provisioning of Persistent Volumes on demand.","related":["Persistent Volume","Persistent Volume Claim"]},{"term":"CSI","abbr":"CSI","category":"Kubernetes","definition":"The Container Storage Interface — a standard for exposing arbitrary storage systems to containerized workloads in Kubernetes and other orchestrators.","related":["Persistent Volume","Storage Class","CNI"]},{"term":"CNI","abbr":"CNI","category":"Kubernetes","definition":"The Container Network Interface — a specification and plugins for configuring network connectivity of containers, used by Kubernetes for pod networking.","related":["Networking","CSI","Pod"]},{"term":"CRI","abbr":"CRI","category":"Kubernetes","definition":"The Container Runtime Interface — the API by which the kubelet talks to container runtimes like containerd and CRI-O, decoupling Kubernetes from any single runtime.","related":["Container Runtime","containerd","kubelet"]},{"term":"Custom Resource Definition","abbr":"CRD","category":"Kubernetes","definition":"A mechanism to extend the Kubernetes API with your own resource types, enabling controllers and operators to manage custom objects declaratively.","related":["Operator","Custom Resource","API Group"]},{"term":"Custom Resource","abbr":"CR","category":"Kubernetes","definition":"An instance of a resource type added to a cluster via a CRD, extending Kubernetes with domain-specific objects managed like native ones.","related":["Custom Resource Definition","Operator"]},{"term":"Operator","abbr":null,"category":"Kubernetes","definition":"A method of packaging, deploying and managing a Kubernetes application using custom resources and controllers that encode operational knowledge to automate day-2 tasks.","related":["Custom Resource Definition","Controller","Reconciliation"]},{"term":"Helm","abbr":null,"category":"Kubernetes","definition":"A package manager for Kubernetes that bundles related manifests into versioned, configurable 'charts' for easy installation, upgrade and rollback of applications.","related":["Helm Chart","Manifest","kubectl"]},{"term":"Helm Chart","abbr":null,"category":"Kubernetes","definition":"A packaged, templated collection of Kubernetes manifests plus default values that Helm installs as a release, parameterized for different environments.","related":["Helm","Manifest"]},{"term":"Manifest","abbr":null,"category":"Kubernetes","definition":"A YAML or JSON file that declares the desired state of one or more Kubernetes objects, applied to the cluster via kubectl or a GitOps tool.","related":["Declarative Configuration","kubectl","Helm Chart"]},{"term":"Kustomize","abbr":null,"category":"Kubernetes","definition":"A built-in Kubernetes tool for customizing manifests via overlays and patches without templates, enabling environment-specific configuration from a common base.","related":["Manifest","Helm","GitOps"]},{"term":"Liveness Probe","abbr":null,"category":"Kubernetes","definition":"A periodic health check that tells Kubernetes whether a container is still running correctly; failing it triggers a restart of the container.","related":["Readiness Probe","Startup Probe","Self Healing"]},{"term":"Readiness Probe","abbr":null,"category":"Kubernetes","definition":"A health check that determines whether a container is ready to receive traffic; failing it removes the pod from Service endpoints until it recovers.","related":["Liveness Probe","Service (K8s)","Startup Probe"]},{"term":"Startup Probe","abbr":null,"category":"Kubernetes","definition":"A probe that checks whether a slow-starting container has finished initializing, deferring liveness and readiness checks until startup completes.","related":["Liveness Probe","Readiness Probe"]},{"term":"Horizontal Pod Autoscaler","abbr":"HPA","category":"Kubernetes","definition":"A controller that automatically scales the number of pod replicas up or down based on observed CPU, memory or custom metrics.","related":["Autoscaling","Vertical Pod Autoscaler","Cluster Autoscaler"]},{"term":"Vertical Pod Autoscaler","abbr":"VPA","category":"Kubernetes","definition":"A component that automatically adjusts the CPU and memory requests/limits of pods based on usage, right-sizing workloads.","related":["Horizontal Pod Autoscaler","Resource Limits"]},{"term":"Cluster Autoscaler","abbr":null,"category":"Kubernetes","definition":"A component that automatically adds or removes nodes from a cluster based on pending pods and utilization, adjusting cluster capacity to demand.","related":["Horizontal Pod Autoscaler","Node","Autoscaling"]},{"term":"Resource Limits","abbr":null,"category":"Kubernetes","definition":"Maximum CPU and memory a container may use; exceeding the memory limit causes the container to be terminated (OOMKilled), while CPU is throttled.","related":["Resource Requests","cgroup","OOMKilled"]},{"term":"Resource Requests","abbr":null,"category":"Kubernetes","definition":"The minimum CPU and memory guaranteed to a container, used by the scheduler to place pods on nodes with sufficient capacity.","related":["Resource Limits","Scheduler","QoS Class"]},{"term":"QoS Class","abbr":null,"category":"Kubernetes","definition":"A quality-of-service classification (Guaranteed, Burstable, BestEffort) Kubernetes assigns pods based on their resource requests and limits, influencing eviction order.","related":["Resource Requests","Resource Limits","Eviction"]},{"term":"Taint and Toleration","abbr":null,"category":"Kubernetes","definition":"A mechanism where nodes repel pods (taints) unless the pods explicitly tolerate them, used to dedicate nodes or keep workloads off certain nodes.","related":["Affinity","Scheduler","Node"]},{"term":"Affinity","abbr":null,"category":"Kubernetes","definition":"Scheduling rules that attract pods toward (or away from) nodes or other pods based on labels, controlling co-location and spread.","related":["Anti-Affinity","Taint and Toleration","Scheduler"]},{"term":"Admission Controller","abbr":null,"category":"Kubernetes","definition":"A plugin that intercepts requests to the Kubernetes API after authentication to validate or mutate objects before they are persisted, enforcing policy.","related":["API Server","OPA","Policy as Code"]},{"term":"RBAC","abbr":"RBAC","category":"Kubernetes","definition":"Role-Based Access Control — a method of regulating access to Kubernetes resources by binding roles (sets of permissions) to users, groups or service accounts.","related":["Service Account","Namespace (K8s)","Least Privilege"]},{"term":"Service Account","abbr":null,"category":"Kubernetes","definition":"An identity used by pods/processes to authenticate to the Kubernetes API, distinct from human user accounts and governed by RBAC.","related":["RBAC","Secret","Identity and Access Management"]},{"term":"Resource Quota","abbr":null,"category":"Kubernetes","definition":"A policy that limits aggregate resource consumption (CPU, memory, object counts) per namespace, preventing one team from exhausting the cluster.","related":["Namespace (K8s)","Limit Range","Multitenancy"]},{"term":"Eviction","abbr":null,"category":"Kubernetes","definition":"The process of terminating pods to reclaim resources on a node under pressure, or via API for maintenance, prioritized by QoS class and priority.","related":["QoS Class","Drain","OOMKilled"]},{"term":"OOMKilled","abbr":null,"category":"Kubernetes","definition":"A pod/container termination status indicating the kernel killed it for exceeding its memory limit (Out Of Memory), a common cause of restarts.","related":["Resource Limits","Eviction","cgroup"]},{"term":"CrashLoopBackOff","abbr":null,"category":"Kubernetes","definition":"A pod status indicating a container keeps crashing and Kubernetes is backing off (waiting increasing intervals) before restarting it, signaling a persistent failure.","related":["Liveness Probe","Pod","Restart Policy"]},{"term":"Rolling Update","abbr":null,"category":"Kubernetes","definition":"A deployment strategy that incrementally replaces old pods with new ones, maintaining availability during application updates.","related":["Deployment","Blue Green Deployment","Canary Deployment"]},{"term":"Drain","abbr":null,"category":"Kubernetes","definition":"Safely evicting all pods from a node (cordoning it first) so it can be maintained or removed without disrupting workloads abruptly.","related":["Eviction","Cordon","Node"]},{"term":"Pod Disruption Budget","abbr":"PDB","category":"Kubernetes","definition":"A policy that limits how many pods of an application can be voluntarily disrupted at once, protecting availability during node drains and upgrades.","related":["Drain","Eviction","Availability"]},{"term":"Aggregation Layer","abbr":null,"category":"Kubernetes","definition":"A Kubernetes feature that lets additional APIs be registered with the main API server, extending the API surface beyond CRDs.","related":["API Server","API Group","Custom Resource Definition"]},{"term":"cAdvisor","abbr":null,"category":"Kubernetes","definition":"Container Advisor — an agent built into the kubelet that collects, aggregates and exposes resource-usage and performance metrics for running containers.","related":["kubelet","Metrics","Infrastructure Monitoring"]},{"term":"Metrics Server","abbr":null,"category":"Kubernetes","definition":"A cluster add-on that aggregates resource-usage data from kubelets and exposes it via the Metrics API, powering kubectl top and the Horizontal Pod Autoscaler.","related":["cAdvisor","Horizontal Pod Autoscaler","Metrics"]},{"term":"Kube-state-metrics","abbr":null,"category":"Kubernetes","definition":"A service that listens to the Kubernetes API and generates metrics about the state of objects (deployments, pods, nodes), commonly scraped by Prometheus.","related":["Prometheus","Metrics","Metrics Server"]},{"term":"Minikube","abbr":null,"category":"Kubernetes","definition":"A tool that runs a single-node Kubernetes cluster locally for development and learning, supporting most cluster features on a laptop.","related":["kind","Kubernetes","Cluster"]},{"term":"kind","abbr":null,"category":"Kubernetes","definition":"Kubernetes IN Docker — a tool for running local Kubernetes clusters using Docker containers as nodes, popular for testing and CI.","related":["Minikube","Docker","Cluster"]},{"term":"Container Network Policy","abbr":null,"category":"Kubernetes","definition":"A Kubernetes resource that controls which pods may communicate with each other and with external endpoints, providing pod-level network segmentation.","related":["CNI","Zero Trust Architecture","Firewall"]},{"term":"DNS","abbr":"DNS","category":"Networking","definition":"The Domain Name System — the internet's directory that translates human-readable domain names into the IP addresses machines use to locate each other.","related":["IP Address","DNS Record","Resolver","TTL"]},{"term":"DNS Record","abbr":null,"category":"Networking","definition":"An entry in a DNS zone that maps a name to data — A/AAAA records to IPs, CNAME to aliases, MX to mail servers, TXT to arbitrary text.","related":["DNS","CNAME","A Record"]},{"term":"A Record","abbr":null,"category":"Networking","definition":"A DNS record that maps a domain name to an IPv4 address; AAAA records do the same for IPv6.","related":["DNS Record","DNS","IP Address"]},{"term":"CNAME","abbr":"CNAME","category":"Networking","definition":"A Canonical Name DNS record that aliases one domain name to another, so multiple names can resolve to the same target.","related":["DNS Record","DNS"]},{"term":"Resolver","abbr":null,"category":"Networking","definition":"A DNS client or server that queries the DNS hierarchy on behalf of applications to resolve names into IP addresses, often caching results.","related":["DNS","TTL","Caching"]},{"term":"IP Address","abbr":null,"category":"Networking","definition":"A numerical label assigned to each device on a network (IPv4 or IPv6) that identifies it and enables routing of traffic to and from it.","related":["DNS","Subnet","CIDR","NAT"]},{"term":"CIDR","abbr":"CIDR","category":"Networking","definition":"Classless Inter-Domain Routing — a notation (e.g., 10.0.0.0/16) for specifying IP address ranges and subnet masks, used to allocate and route address blocks.","related":["Subnet","IP Address","VPC"]},{"term":"Subnet","abbr":null,"category":"Networking","definition":"A logically subdivided portion of a larger network's IP address space, used to segment, organize and secure traffic.","related":["CIDR","VPC","IP Address"]},{"term":"NAT","abbr":"NAT","category":"Networking","definition":"Network Address Translation — remapping IP addresses as traffic crosses a router, commonly letting many private hosts share one public IP.","related":["IP Address","Firewall","Gateway"]},{"term":"TCP","abbr":"TCP","category":"Networking","definition":"Transmission Control Protocol — a connection-oriented transport protocol that provides reliable, ordered, error-checked delivery of a byte stream.","related":["UDP","IP Address","Three-Way Handshake"]},{"term":"UDP","abbr":"UDP","category":"Networking","definition":"User Datagram Protocol — a lightweight, connectionless transport protocol that sends datagrams without delivery guarantees, favoring speed over reliability.","related":["TCP","QUIC","Packet"]},{"term":"QUIC","abbr":null,"category":"Networking","definition":"A modern transport protocol built on UDP that reduces connection latency and improves performance, serving as the basis for HTTP/3.","related":["UDP","HTTP/3","TLS"]},{"term":"HTTP","abbr":"HTTP","category":"Networking","definition":"HyperText Transfer Protocol — the request/response application protocol that powers the web, used by clients and servers to exchange resources.","related":["HTTPS","HTTP/2","REST","Status Code"]},{"term":"HTTPS","abbr":"HTTPS","category":"Networking","definition":"HTTP secured with TLS, encrypting traffic between client and server to protect confidentiality and integrity.","related":["HTTP","TLS","Certificate"]},{"term":"HTTP/2","abbr":null,"category":"Networking","definition":"A major HTTP revision that multiplexes multiple requests over one connection, compresses headers and supports server push, improving performance.","related":["HTTP","HTTP/3","Multiplexing"]},{"term":"HTTP/3","abbr":null,"category":"Networking","definition":"The latest HTTP version, running over QUIC/UDP to reduce latency and head-of-line blocking compared with HTTP/2 over TCP.","related":["QUIC","HTTP/2","UDP"]},{"term":"Status Code","abbr":null,"category":"Networking","definition":"A three-digit HTTP response code indicating the result of a request — 2xx success, 3xx redirect, 4xx client error, 5xx server error.","related":["HTTP","Error Rate","5xx"]},{"term":"TLS","abbr":"TLS","category":"Networking","definition":"Transport Layer Security — the cryptographic protocol that encrypts and authenticates network communication, securing HTTPS and many other protocols.","related":["HTTPS","mTLS","Certificate","Encryption in Transit"]},{"term":"Certificate","abbr":null,"category":"Networking","definition":"A digital document that binds a public key to an identity, signed by a certificate authority, used to establish trust and enable TLS encryption.","related":["TLS","Certificate Authority","Public Key Infrastructure"]},{"term":"Certificate Authority","abbr":"CA","category":"Security & SIEM","definition":"A trusted entity that issues and vouches for digital certificates, enabling parties to verify each other's identities in TLS and PKI.","related":["Certificate","Public Key Infrastructure","TLS"]},{"term":"Load Balancing","abbr":null,"category":"Networking","definition":"Distributing incoming network traffic across multiple servers or instances to improve responsiveness, availability and capacity utilization.","related":["Load Balancer","Round Robin","Health Check"]},{"term":"Load Balancer","abbr":null,"category":"Networking","definition":"A device or service that spreads client requests across a pool of backend servers, often performing health checks and TLS termination.","related":["Load Balancing","Application Load Balancer","Reverse Proxy"]},{"term":"Application Load Balancer","abbr":"ALB","category":"Cloud Providers","definition":"A Layer 7 (HTTP/HTTPS) load balancer that routes requests based on content such as path or host headers; AWS's ALB is a common example.","related":["Load Balancer","Network Load Balancer","Reverse Proxy"]},{"term":"Network Load Balancer","abbr":"NLB","category":"Cloud Providers","definition":"A Layer 4 (TCP/UDP) load balancer that routes traffic at the connection level for high throughput and low latency.","related":["Load Balancer","Application Load Balancer"]},{"term":"Reverse Proxy","abbr":null,"category":"Networking","definition":"A server that sits in front of backend servers and forwards client requests to them, providing load balancing, caching, TLS termination and security.","related":["Forward Proxy","Load Balancer","API Gateway","Nginx"]},{"term":"Forward Proxy","abbr":null,"category":"Networking","definition":"A proxy that sits between clients and the internet, forwarding their outbound requests, often for filtering, caching or anonymity.","related":["Reverse Proxy","Proxy"]},{"term":"Nginx","abbr":null,"category":"Networking","definition":"A high-performance web server, reverse proxy and load balancer widely used to serve content and front applications.","related":["Reverse Proxy","Load Balancer","Web Server"]},{"term":"CDN","abbr":"CDN","category":"Networking","definition":"A Content Delivery Network — a geographically distributed set of caching servers that deliver web content from locations close to users to reduce latency.","related":["Edge Computing","Caching","Latency","Point of Presence"]},{"term":"Point of Presence","abbr":"PoP","category":"Networking","definition":"A physical access point or edge location in a network (such as a CDN) where content is cached and served close to end users.","related":["CDN","Edge Computing"]},{"term":"Caching","abbr":null,"category":"Networking","definition":"Storing copies of data or responses closer to consumers so future requests are served faster, reducing latency and backend load.","related":["CDN","Cache Hit Ratio","TTL","Redis"]},{"term":"Cache Hit Ratio","abbr":null,"category":"Networking","definition":"The percentage of requests served from cache rather than the origin; a higher ratio means better performance and lower backend load.","related":["Caching","CDN"]},{"term":"TTL","abbr":"TTL","category":"Networking","definition":"Time To Live — a value that limits how long data is considered valid, such as how long a DNS record or cached item may be retained before refresh.","related":["Caching","DNS","Resolver"]},{"term":"Rate Limiting","abbr":null,"category":"Networking","definition":"Restricting how many requests a client may make in a time window to protect services from overload and abuse.","related":["Throttling","API Gateway","Backpressure"]},{"term":"Throttling","abbr":null,"category":"Networking","definition":"Deliberately slowing or limiting the rate of requests or resource use to keep a system within safe operating limits.","related":["Rate Limiting","Backpressure","Saturation"]},{"term":"Backpressure","abbr":null,"category":"Distributed Systems","definition":"A flow-control mechanism where a downstream component signals upstream to slow down when it cannot keep up, preventing overload and cascading failure.","related":["Throttling","Load Shedding","Queue"]},{"term":"Load Shedding","abbr":null,"category":"Reliability","definition":"Deliberately dropping or rejecting some requests when a system is overloaded so that it can keep serving the rest, protecting overall availability.","related":["Backpressure","Circuit Breaker","Saturation"]},{"term":"Firewall","abbr":null,"category":"Security & SIEM","definition":"A network security control that monitors and filters incoming and outgoing traffic based on configured rules, separating trusted from untrusted networks.","related":["Security Group","Network Policy","WAF"]},{"term":"WAF","abbr":"WAF","category":"Security & SIEM","definition":"Web Application Firewall — a security layer that inspects and filters HTTP traffic to protect web apps from attacks like SQL injection and cross-site scripting.","related":["Firewall","CDN","OWASP"]},{"term":"VPN","abbr":"VPN","category":"Networking","definition":"Virtual Private Network — an encrypted tunnel that securely connects remote users or networks over the public internet as if on a private network.","related":["Encryption in Transit","Zero Trust Architecture","Tunnel"]},{"term":"Latency (Network)","abbr":null,"category":"Networking","definition":"The time it takes for a packet to travel from source to destination across a network, a major contributor to overall request response time.","related":["Round-Trip Time","Jitter","Bandwidth"]},{"term":"Round-Trip Time","abbr":"RTT","category":"Networking","definition":"The time for a signal to travel to a destination and back; a fundamental measure of network latency.","related":["Latency (Network)","Ping","Jitter"]},{"term":"Bandwidth","abbr":null,"category":"Networking","definition":"The maximum rate at which data can be transferred over a network link, typically measured in bits per second.","related":["Throughput","Latency (Network)","Packet Loss"]},{"term":"Jitter","abbr":null,"category":"Networking","definition":"Variation in packet delay over time; high jitter degrades real-time applications like voice and video even when average latency is acceptable.","related":["Latency (Network)","Packet Loss","Round-Trip Time"]},{"term":"Packet Loss","abbr":null,"category":"Networking","definition":"The failure of packets to reach their destination, causing retransmissions and degraded performance; a key network-health signal.","related":["Jitter","Bandwidth","Network Performance Monitoring"]},{"term":"Packet","abbr":null,"category":"Networking","definition":"The basic unit of data transmitted over a network, containing a header (addressing/control) and payload (the data being carried).","related":["TCP","UDP","Packet Loss"]},{"term":"Ping","abbr":null,"category":"Networking","definition":"A utility and ICMP-based test that measures reachability and round-trip time to a host, used for basic connectivity checks.","related":["Round-Trip Time","Uptime Check","Heartbeat"]},{"term":"Port","abbr":null,"category":"Networking","definition":"A numbered endpoint on a host that identifies a specific service or process for network communication (e.g., 80 for HTTP, 443 for HTTPS).","related":["TCP","Socket","Firewall"]},{"term":"Socket","abbr":null,"category":"Networking","definition":"An endpoint for sending and receiving data across a network, identified by an IP address and port and used by applications to communicate.","related":["Port","TCP","WebSocket"]},{"term":"WebSocket","abbr":null,"category":"Networking","definition":"A protocol providing full-duplex, persistent communication over a single TCP connection, enabling real-time bidirectional data between client and server.","related":["HTTP","Socket","Event-Driven Architecture"]},{"term":"gRPC","abbr":null,"category":"Networking","definition":"A high-performance, open-source RPC framework using HTTP/2 and Protocol Buffers for efficient, strongly typed service-to-service communication.","related":["Protocol Buffers","RPC","HTTP/2","API"]},{"term":"RPC","abbr":"RPC","category":"Networking","definition":"Remote Procedure Call — a pattern where a program invokes a function on a remote service as if it were local, abstracting the network communication.","related":["gRPC","API","Microservices Architecture"]},{"term":"REST","abbr":"REST","category":"Networking","definition":"Representational State Transfer — an architectural style for web APIs using standard HTTP methods and resources, valued for simplicity and statelessness.","related":["API","HTTP","GraphQL"]},{"term":"GraphQL","abbr":null,"category":"Networking","definition":"A query language and runtime for APIs that lets clients request exactly the data they need in a single call, reducing over- and under-fetching.","related":["REST","API","Schema"]},{"term":"API","abbr":"API","category":"Networking","definition":"Application Programming Interface — a defined contract that lets software components communicate, specifying the operations, inputs and outputs available.","related":["REST","gRPC","API Gateway","SDK"]},{"term":"Protocol Buffers","abbr":"protobuf","category":"Networking","definition":"A compact, language-neutral binary serialization format from Google for structured data, commonly used with gRPC for efficient message encoding.","related":["gRPC","Serialization","Schema"]},{"term":"Multiplexing","abbr":null,"category":"Networking","definition":"Carrying multiple independent streams of data over a single connection, as HTTP/2 does, improving efficiency and reducing connection overhead.","related":["HTTP/2","QUIC"]},{"term":"Service Level Telemetry","abbr":null,"category":"Networking","definition":"Network and service measurements (latency, errors, throughput) collected to monitor the quality of communication between components.","related":["Network Performance Monitoring","Golden Signals","Latency (Network)"]},{"term":"Anycast","abbr":null,"category":"Networking","definition":"A routing method where one IP address is advertised from multiple locations, and the network delivers traffic to the nearest one, used by CDNs and DNS.","related":["CDN","DNS","Point of Presence"]},{"term":"Egress","abbr":null,"category":"Networking","definition":"Outbound traffic leaving a network or cloud environment; egress controls and costs are important considerations in cloud architectures.","related":["Ingress","NAT","Network Policy"]},{"term":"Three-Way Handshake","abbr":null,"category":"Networking","definition":"The TCP connection-establishment process (SYN, SYN-ACK, ACK) by which client and server synchronize before exchanging data.","related":["TCP","Socket"]},{"term":"Alertmanager","abbr":null,"category":"Standards & Tools","definition":"The Prometheus component that handles alerts sent by the server — deduplicating, grouping, silencing, inhibiting and routing them to receivers like email, Slack or PagerDuty.","related":["Prometheus","Alerting","Silence","Deduplication"]},{"term":"Recording Rule","abbr":null,"category":"Standards & Tools","definition":"A Prometheus rule that precomputes frequently used or expensive queries into new time series, speeding up dashboards and alerts.","related":["PromQL","Prometheus","Alerting Rule"]},{"term":"Alerting Rule","abbr":null,"category":"Standards & Tools","definition":"A Prometheus rule that fires an alert when a PromQL expression is true for a defined duration, forwarding it to Alertmanager.","related":["Alertmanager","PromQL","Threshold"]},{"term":"Remote Write","abbr":null,"category":"Standards & Tools","definition":"A Prometheus feature that streams scraped samples to a remote long-term storage backend such as Thanos, Cortex or VictoriaMetrics.","related":["Prometheus","Thanos","Long-Term Storage"]},{"term":"Exemplar","abbr":null,"category":"Standards & Tools","definition":"A reference attached to a metric data point that links it to a specific trace (via trace ID), enabling a jump from a latency spike to an example trace.","related":["Histogram","Trace ID","Correlation"]},{"term":"Prometheus Exporter","abbr":null,"category":"Standards & Tools","definition":"A component that exposes metrics from a third-party system (databases, hardware, services) in a format Prometheus can scrape.","related":["Prometheus","Scrape","Node Exporter","Exporter"]},{"term":"Node Exporter","abbr":null,"category":"Standards & Tools","definition":"A Prometheus exporter that exposes hardware and OS-level metrics (CPU, memory, disk, network) from a host.","related":["Exporter","Prometheus","Infrastructure Monitoring"]},{"term":"Pushgateway","abbr":null,"category":"Standards & Tools","definition":"A Prometheus component that lets short-lived batch jobs push their metrics to an intermediary that Prometheus then scrapes.","related":["Prometheus","Scrape","Batch Processing"]},{"term":"Thanos","abbr":null,"category":"Standards & Tools","definition":"An open-source system that extends Prometheus with long-term storage, global query view and high availability across clusters.","related":["Prometheus","Remote Write","Cortex","Long-Term Storage"]},{"term":"Cortex","abbr":null,"category":"Standards & Tools","definition":"A horizontally scalable, multi-tenant, long-term storage backend for Prometheus metrics, a basis for managed Prometheus offerings.","related":["Prometheus","Thanos","Mimir","Remote Write"]},{"term":"Mimir","abbr":null,"category":"Standards & Tools","definition":"Grafana Mimir — a scalable, multi-tenant long-term storage system for Prometheus and OpenTelemetry metrics.","related":["Prometheus","Cortex","Grafana","Remote Write"]},{"term":"VictoriaMetrics","abbr":null,"category":"Standards & Tools","definition":"A fast, cost-efficient open-source time-series database and long-term storage backend compatible with Prometheus.","related":["Time Series Database","Prometheus","Remote Write"]},{"term":"InfluxDB","abbr":null,"category":"Standards & Tools","definition":"A popular open-source time-series database for metrics and events, with its own query languages (InfluxQL, Flux).","related":["Time Series Database","Telegraf","Metric"]},{"term":"Graphite","abbr":null,"category":"Standards & Tools","definition":"An early, widely adopted open-source time-series metrics system with a simple data model and the StatsD ecosystem.","related":["StatsD","Time Series","Metric"]},{"term":"StatsD","abbr":null,"category":"Standards & Tools","definition":"A simple daemon and protocol for aggregating application metrics (counters, timers, gauges) sent over UDP, popularized by Graphite.","related":["Graphite","Counter","Gauge"]},{"term":"Telegraf","abbr":null,"category":"Standards & Tools","definition":"A plugin-driven agent for collecting and reporting metrics from systems and services, part of the InfluxData stack.","related":["InfluxDB","Agent","Collector"]},{"term":"Long-Term Storage","abbr":null,"category":"Standards & Tools","definition":"Durable, cost-efficient storage of telemetry (especially metrics) beyond the short retention of the collection system, enabling historical analysis.","related":["Thanos","Cortex","Retention","Downsampling"]},{"term":"Cardinality Explosion","abbr":null,"category":"Standards & Tools","definition":"An uncontrolled surge in unique time series caused by high-cardinality labels, which can overwhelm storage and degrade query performance and cost.","related":["Cardinality","Dimension","Label"]},{"term":"Semantic Conventions","abbr":null,"category":"Standards & Tools","definition":"OpenTelemetry's standardized naming and attributes for telemetry (e.g., http.method, db.system), ensuring consistency across instrumentation and tools.","related":["OpenTelemetry","Resource Attributes","Span"]},{"term":"Resource Attributes","abbr":null,"category":"Standards & Tools","definition":"OpenTelemetry attributes describing the entity producing telemetry (service name, version, host, region), used to identify and group signals.","related":["Semantic Conventions","OpenTelemetry","Tag"]},{"term":"Span Attributes","abbr":null,"category":"Tracing","definition":"Key-value metadata attached to a span (HTTP route, status, DB statement) that enriches traces and powers filtering and analysis.","related":["Span","Semantic Conventions","Span Events"]},{"term":"Span Events","abbr":null,"category":"Tracing","definition":"Timestamped annotations within a span marking notable occurrences (such as an exception) at a point during the operation.","related":["Span","Span Attributes","Exception Tracking"]},{"term":"Span Kind","abbr":null,"category":"Tracing","definition":"A classification of a span's role — server, client, producer, consumer or internal — that shapes how trace relationships are interpreted.","related":["Span","Distributed Tracing"]},{"term":"Jaeger","abbr":null,"category":"Standards & Tools","definition":"A CNCF open-source distributed-tracing system for collecting, storing and visualizing traces, originally created at Uber.","related":["Distributed Tracing","Zipkin","OpenTelemetry"]},{"term":"Zipkin","abbr":null,"category":"Standards & Tools","definition":"An early open-source distributed-tracing system, inspired by Google Dapper, for collecting and looking up trace data.","related":["Jaeger","Distributed Tracing","OpenTracing"]},{"term":"Tempo","abbr":null,"category":"Standards & Tools","definition":"Grafana Tempo — a highly scalable, cost-efficient distributed-tracing backend that stores traces in object storage.","related":["Distributed Tracing","Grafana","Loki"]},{"term":"OpenTracing","abbr":null,"category":"Standards & Tools","definition":"A former CNCF vendor-neutral tracing API that merged with OpenCensus to form OpenTelemetry.","related":["OpenTelemetry","OpenCensus","Distributed Tracing"]},{"term":"OpenCensus","abbr":null,"category":"Standards & Tools","definition":"A Google-originated set of libraries for metrics and tracing that merged with OpenTracing to create OpenTelemetry.","related":["OpenTelemetry","OpenTracing"]},{"term":"Loki","abbr":null,"category":"Standards & Tools","definition":"Grafana Loki — a horizontally scalable log-aggregation system that indexes only labels (not full text) for cost-efficient logging.","related":["Log Aggregation","Grafana","Tempo"]},{"term":"Fluentd","abbr":null,"category":"Standards & Tools","definition":"A CNCF open-source data collector that unifies log collection and routing across sources and destinations via a plugin ecosystem.","related":["Fluent Bit","Log Aggregation","Pipeline"]},{"term":"Fluent Bit","abbr":null,"category":"Standards & Tools","definition":"A lightweight, high-performance log and metrics processor and forwarder, often used as an edge collector alongside or instead of Fluentd.","related":["Fluentd","Collector","Log Aggregation"]},{"term":"Logstash","abbr":null,"category":"Standards & Tools","definition":"The data-processing pipeline component of the Elastic Stack that ingests, transforms and ships logs and events to destinations like Elasticsearch.","related":["Elasticsearch","Grok","Pipeline"]},{"term":"Elasticsearch","abbr":null,"category":"Standards & Tools","definition":"A distributed search and analytics engine commonly used to store, index and query logs and observability data at scale.","related":["Kibana","ELK Stack","Index (Logs)"]},{"term":"Kibana","abbr":null,"category":"Standards & Tools","definition":"The visualization and exploration UI of the Elastic Stack for searching, charting and dashboarding data stored in Elasticsearch.","related":["Elasticsearch","ELK Stack","Dashboard"]},{"term":"ELK Stack","abbr":null,"category":"Standards & Tools","definition":"The combination of Elasticsearch, Logstash and Kibana (often with Beats) widely used for centralized logging and analytics.","related":["Elasticsearch","Logstash","Kibana"]},{"term":"Vector","abbr":null,"category":"Standards & Tools","definition":"A high-performance open-source observability data pipeline for collecting, transforming and routing logs, metrics and traces.","related":["Observability Pipeline","Collector","Pipeline"]},{"term":"Pyroscope","abbr":null,"category":"Standards & Tools","definition":"An open-source continuous-profiling backend (now part of Grafana) for storing and querying profiling data over time.","related":["Continuous Profiling","Flame Graph","Grafana"]},{"term":"PagerDuty","abbr":null,"category":"Incident","definition":"A popular incident-management and on-call platform that routes alerts, manages escalations and coordinates response.","related":["On-Call","Escalation","Incident Management","Opsgenie"]},{"term":"Opsgenie","abbr":null,"category":"Incident","definition":"An on-call and alerting platform (by Atlassian) for routing alerts, scheduling on-call and managing escalations.","related":["PagerDuty","On-Call","Escalation"]},{"term":"Silence","abbr":null,"category":"Incident","definition":"A temporary suppression of specific alerts (e.g., in Alertmanager) so they do not notify, used during maintenance or known issues.","related":["Alertmanager","Maintenance Window","Alert Suppression"]},{"term":"Alert Suppression","abbr":null,"category":"Incident","definition":"Preventing certain alerts from firing or notifying under defined conditions to reduce noise during expected disruptions or dependencies.","related":["Silence","Noise Reduction","Inhibition"]},{"term":"Inhibition","abbr":null,"category":"Incident","definition":"An Alertmanager mechanism that suppresses lower-priority alerts when a related higher-priority alert is already firing, cutting noise.","related":["Alertmanager","Alert Suppression","Event Correlation"]},{"term":"Error Tracking","abbr":null,"category":"APM","definition":"Capturing, grouping and alerting on application exceptions and crashes with stack traces and context, to find and fix code defects fast.","related":["Exception Tracking","Sentry","Crash Reporting"]},{"term":"Exception Tracking","abbr":null,"category":"APM","definition":"Recording unhandled errors and exceptions with their stack traces, frequency and affected users for prioritized debugging.","related":["Error Tracking","Span Events","Stack Trace"]},{"term":"Sentry","abbr":null,"category":"Standards & Tools","definition":"A widely used open-source error-tracking and performance-monitoring platform that captures exceptions with rich context and release tracking.","related":["Error Tracking","Exception Tracking","Source Map"]},{"term":"Crash Reporting","abbr":null,"category":"Digital Experience","definition":"Capturing details of application crashes (especially mobile/desktop) — stack traces, device state — to diagnose and fix stability issues.","related":["Error Tracking","Real User Monitoring","Stack Trace"]},{"term":"Source Map","abbr":null,"category":"Digital Experience","definition":"A file mapping minified/transpiled front-end code back to original source, so errors and traces reference readable code locations.","related":["Error Tracking","Real User Monitoring","Stack Trace"]},{"term":"Stack Trace","abbr":null,"category":"APM","definition":"A report of the active function call stack at a point in execution (often an error), showing the path of calls that led there.","related":["Exception Tracking","Error Tracking","Profiling"]},{"term":"Largest Contentful Paint","abbr":"LCP","category":"Digital Experience","definition":"A Core Web Vital measuring how long until the largest visible content element renders, indicating perceived load speed. Good is under 2.5s.","related":["Core Web Vitals","First Contentful Paint","Real User Monitoring"]},{"term":"Interaction to Next Paint","abbr":"INP","category":"Digital Experience","definition":"A Core Web Vital measuring overall responsiveness — the latency of user interactions to the next visual update. Lower is better.","related":["Core Web Vitals","Total Blocking Time","Real User Monitoring"]},{"term":"Cumulative Layout Shift","abbr":"CLS","category":"Digital Experience","definition":"A Core Web Vital measuring visual stability — how much page content unexpectedly shifts during load. Lower scores are better.","related":["Core Web Vitals","Real User Monitoring"]},{"term":"First Contentful Paint","abbr":"FCP","category":"Digital Experience","definition":"The time from navigation until the browser renders the first piece of content, an early indicator of perceived load speed.","related":["Largest Contentful Paint","Time to First Byte","Core Web Vitals"]},{"term":"Time to First Byte","abbr":"TTFB","category":"Digital Experience","definition":"The time from a request until the first byte of the response arrives, reflecting server and network responsiveness.","related":["First Contentful Paint","Latency","Real User Monitoring"]},{"term":"Total Blocking Time","abbr":"TBT","category":"Digital Experience","definition":"The total time the main thread was blocked long enough to prevent input responsiveness during load, correlated with INP.","related":["Interaction to Next Paint","Core Web Vitals"]},{"term":"LLM Observability","abbr":null,"category":"AIOps","definition":"Monitoring large language model applications — capturing prompts, responses, token usage, latency, cost, quality and failures — to operate them reliably.","related":["Token Usage","Prompt","Hallucination","Model Drift"]},{"term":"AI Observability","abbr":null,"category":"AIOps","definition":"Observing AI/ML systems end to end — data, models, inference and outcomes — to ensure performance, reliability, cost control and trustworthy behavior.","related":["LLM Observability","Model Drift","Model Monitoring"]},{"term":"Model Monitoring","abbr":null,"category":"AIOps","definition":"Tracking a deployed model's inputs, predictions and performance over time to detect degradation, drift, bias and data-quality issues.","related":["Model Drift","Data Drift","AI Observability"]},{"term":"Token Usage","abbr":null,"category":"AIOps","definition":"The count of tokens consumed by prompts and completions in an LLM call, the basis for cost and latency, and a key thing to monitor.","related":["LLM Observability","Prompt","Cost Optimization"]},{"term":"Prompt","abbr":null,"category":"AIOps","definition":"The input text or instructions given to a language model; capturing and versioning prompts is central to LLM observability and evaluation.","related":["LLM Observability","Token Usage","Prompt Engineering"]},{"term":"Guardrails","abbr":null,"category":"AIOps","definition":"Controls that constrain AI model inputs and outputs — filtering unsafe content, enforcing formats, blocking policy violations — to keep behavior safe and reliable.","related":["Hallucination","LLM Observability"]},{"term":"Evaluation (AI)","abbr":null,"category":"AIOps","definition":"Systematically scoring AI/LLM outputs for quality, accuracy and safety using test sets, human review or model-based judges.","related":["Hallucination","LLM Observability","Benchmark"]},{"term":"Trace Sampling Rate","abbr":null,"category":"Tracing","definition":"The fraction of traces retained out of all generated, controlling data volume and cost; expressed as a percentage or ratio.","related":["Sampling","Head-Based Sampling","Tail-Based Sampling"]},{"term":"Span Duration","abbr":null,"category":"Tracing","definition":"The elapsed time of a single span from start to end, the basic timing measurement that composes a trace's latency breakdown.","related":["Span","Latency","Waterfall View"]},{"term":"Service Level","abbr":null,"category":"Reliability","definition":"A measured quality of service experienced by users, the basis for SLIs, SLOs and SLAs.","related":["SLI","SLO","SLA"]},{"term":"Black-Box Monitoring","abbr":null,"category":"Fundamentals","definition":"Observing a system purely from the outside — its external behavior and responses — without insight into internal workings, as synthetic checks do.","related":["White-Box Monitoring","Synthetic Monitoring","Uptime Check"]},{"term":"White-Box Monitoring","abbr":null,"category":"Fundamentals","definition":"Monitoring based on internal signals exposed by the system itself (metrics, logs, traces), giving insight into why something happens.","related":["Black-Box Monitoring","Instrumentation","Observability"]},{"term":"Unified Observability","abbr":null,"category":"Fundamentals","definition":"Bringing metrics, logs, traces and other signals into one correlated platform so teams investigate without switching tools or losing context.","related":["Single Pane of Glass","Correlation","MELT"]},{"term":"Telemetry Pipeline","abbr":null,"category":"Standards & Tools","definition":"A processing layer that collects, transforms, reduces, redacts and routes telemetry to one or more destinations, controlling cost and governance.","related":["Observability Pipeline","Vector","Pipeline"]},{"term":"Data Tiering","abbr":null,"category":"Standards & Tools","definition":"Routing telemetry to different storage classes by value and access frequency — hot indexed storage versus cheap archives — to balance cost and speed.","related":["Indexing Tier","Cold Storage","Retention"]},{"term":"Synthetic Transaction","abbr":null,"category":"Digital Experience","definition":"A scripted, simulated multi-step user journey run on a schedule to proactively validate critical flows and measure performance.","related":["Synthetic Monitoring","Browser Test","Business Transaction"]},{"term":"Golden Path","abbr":null,"category":"DevOps & CI/CD","definition":"A recommended, well-supported, paved route for building and deploying software that bakes in best practices, reducing friction and risk.","related":["Platform Engineering","Internal Developer Platform"]},{"term":"Data Point","abbr":null,"category":"Metrics","definition":"A single timestamped value in a time series, the atomic unit of metric data.","related":["Time Series","Metric","Sample"]},{"term":"Sample","abbr":null,"category":"Metrics","definition":"An individual measurement of a metric at a moment in time, collected at the scrape or reporting interval.","related":["Data Point","Scrape","Resolution"]},{"term":"Resolution","abbr":null,"category":"Metrics","definition":"The granularity of time-series data — how frequently points are recorded; higher resolution gives detail at greater storage cost.","related":["Downsampling","Sample","Granularity"]},{"term":"Granularity","abbr":null,"category":"Metrics","definition":"The level of detail in data — fine granularity captures more nuance, coarse granularity summarizes; a trade-off against volume and cost.","related":["Resolution","Cardinality","Downsampling"]},{"term":"Pull vs Push","abbr":null,"category":"Metrics","definition":"Two metric-collection models: pull (the server scrapes targets, as Prometheus does) and push (agents send metrics to a collector, as StatsD does).","related":["Scrape","Pushgateway","Agent"]},{"term":"Scrape Interval","abbr":null,"category":"Metrics","definition":"How often a pull-based system like Prometheus collects metrics from targets; shorter intervals increase resolution and load.","related":["Scrape","Resolution","Prometheus"]},{"term":"Staleness","abbr":null,"category":"Metrics","definition":"A condition where a time series stops receiving new samples; monitoring systems mark such series stale to avoid using outdated values.","related":["Sample","Scrape Interval","Heartbeat"]},{"term":"Counter Reset","abbr":null,"category":"Metrics","definition":"When a monotonic counter restarts at zero (e.g., on process restart); rate functions detect and account for resets to compute correct rates.","related":["Counter","Rate","Monotonic"]},{"term":"Monotonic","abbr":null,"category":"Metrics","definition":"A value that only ever increases (or only decreases), the defining property of counters, important for correct rate calculation.","related":["Counter","Counter Reset","Rate"]},{"term":"Cumulative vs Delta","abbr":null,"category":"Metrics","definition":"Two temporality models for sums: cumulative reports a running total since start, delta reports the change since the last report; OpenTelemetry supports both.","related":["Counter","OpenTelemetry","Aggregation"]},{"term":"Quantile","abbr":null,"category":"Metrics","definition":"A value below which a given fraction of observations fall (e.g., the 0.95 quantile is p95); the basis of latency percentiles.","related":["Percentile","Histogram","Summary"]},{"term":"Bucket","abbr":null,"category":"Metrics","definition":"A range into which a histogram counts observations; bucket boundaries determine the precision of percentile estimates.","related":["Histogram","Quantile","Heatmap"]},{"term":"Metric Label","abbr":null,"category":"Metrics","definition":"A key-value dimension attached to a metric that creates distinct time series; the primary driver of cardinality.","related":["Dimension","Cardinality","Label"]},{"term":"Metric Namespace","abbr":null,"category":"Metrics","definition":"A prefix or naming scheme that groups related metrics (e.g., http_server_*), improving organization and discoverability.","related":["Metric","Semantic Conventions"]},{"term":"Unit (Metric)","abbr":null,"category":"Metrics","definition":"The measurement unit of a metric (seconds, bytes, requests), which should be consistent and documented for correct interpretation and conversion.","related":["Metric","Semantic Conventions"]},{"term":"Composite Metric","abbr":null,"category":"Metrics","definition":"A metric derived by combining or computing over other metrics (e.g., error rate = errors / requests), often via a query or recording rule.","related":["Recording Rule","Aggregation","Error Rate"]},{"term":"Log-Based Metric","abbr":null,"category":"Metrics","definition":"A metric generated by counting or measuring matching log events, turning high-volume logs into efficient, queryable time series.","related":["Log","Metric","Pipeline"]},{"term":"Log Line","abbr":null,"category":"Logging","definition":"A single record in a log stream, typically one event with a timestamp, severity and message, optionally structured as fields.","related":["Log","Structured Logging","Log Level"]},{"term":"Log Shipper","abbr":null,"category":"Logging","definition":"An agent that collects logs from files or streams and forwards them to a central system (e.g., Fluent Bit, Filebeat, Vector).","related":["Fluent Bit","Vector","Log Aggregation"]},{"term":"Syslog","abbr":null,"category":"Logging","definition":"A long-standing standard protocol and format for system logging, widely supported by devices and services for forwarding log messages.","related":["Log","Log Shipper","Log Aggregation"]},{"term":"Access Log","abbr":null,"category":"Logging","definition":"A log recording each request a server handles (client, path, status, latency), foundational for traffic analysis and troubleshooting.","related":["Log","Status Code","Application Log"]},{"term":"Application Log","abbr":null,"category":"Logging","definition":"Logs emitted by application code describing its behavior and errors, key for debugging business logic.","related":["Log","Access Log","Structured Logging"]},{"term":"Log Rotation","abbr":null,"category":"Logging","definition":"Periodically archiving and starting fresh log files to bound disk usage, often by size or time, with old files compressed or deleted.","related":["Log Retention","Log"]},{"term":"Log Sampling","abbr":null,"category":"Logging","definition":"Keeping only a representative subset of high-volume, repetitive logs to reduce cost while preserving signal.","related":["Sampling","Logging without Limits","Data Volume"]},{"term":"Log Pattern","abbr":null,"category":"Logging","definition":"A recurring template extracted from many similar log lines by grouping on their structure, used to summarize and detect anomalies in log volume.","related":["Log Clustering","Parsing","Anomaly Detection"]},{"term":"Log Clustering","abbr":null,"category":"AIOps","definition":"Automatically grouping similar log messages into patterns to reduce noise and surface unusual or new events.","related":["Log Pattern","Anomaly Detection","Noise Reduction"]},{"term":"Full-Text Search","abbr":null,"category":"Logging","definition":"Searching the complete text of logs for arbitrary terms, powerful but storage-intensive; some systems index only labels to save cost.","related":["Index (Logs)","Elasticsearch","Loki"]},{"term":"Faceted Search","abbr":null,"category":"Logging","definition":"Filtering and drilling into telemetry by selecting values across multiple fields (facets), enabling fast exploratory analysis.","related":["Full-Text Search","Dimension","Tag"]},{"term":"Critical Path","abbr":null,"category":"Tracing","definition":"The sequence of spans that determines a trace's total duration; optimizing work off the critical path doesn't reduce end-to-end latency.","related":["Span","Waterfall View","Latency"]},{"term":"Entry Span","abbr":null,"category":"Tracing","definition":"The first span recorded by a service when it receives a request, marking that service's portion of a distributed trace.","related":["Root Span","Span Kind","Service Map"]},{"term":"Orphan Span","abbr":null,"category":"Tracing","definition":"A span whose parent is missing from the collected trace, often due to sampling or instrumentation gaps, complicating trace reconstruction.","related":["Span","Trace","Context Propagation"]},{"term":"Trace Completeness","abbr":null,"category":"Tracing","definition":"The degree to which all spans of a request were captured; incomplete traces hinder accurate latency and dependency analysis.","related":["Orphan Span","Sampling","Distributed Tracing"]},{"term":"Trace Analytics","abbr":null,"category":"Tracing","definition":"Aggregating and querying across many traces to compute metrics, find patterns and locate slow or failing operations at scale.","related":["Distributed Tracing","Service Map","Trace Sampling Rate"]},{"term":"B3 Propagation","abbr":null,"category":"Tracing","definition":"A trace-context propagation format (originating from Zipkin) using B3 HTTP headers to carry trace and span IDs across services.","related":["Context Propagation","W3C Trace Context","Zipkin"]},{"term":"Trace Retention","abbr":null,"category":"Tracing","definition":"How long collected traces are stored before deletion; balanced against cost and the need to investigate past incidents.","related":["Retention","Sampling","Trace Analytics"]},{"term":"User Session","abbr":null,"category":"Digital Experience","definition":"A period of continuous user interaction with an application, grouping page views and events to analyze experience and behavior.","related":["Real User Monitoring","Session Replay","Page View"]},{"term":"Page View","abbr":null,"category":"Digital Experience","definition":"A single load or render of a page by a user, the basic unit of web RUM analysis along with timing and error data.","related":["Real User Monitoring","User Session","Core Web Vitals"]},{"term":"First Input Delay","abbr":"FID","category":"Digital Experience","definition":"A legacy responsiveness metric measuring the delay between a user's first interaction and the browser's response; succeeded by INP.","related":["Interaction to Next Paint","Core Web Vitals"]},{"term":"Time to Interactive","abbr":"TTI","category":"Digital Experience","definition":"The time until a page is fully interactive and reliably responds to input, a measure of perceived usability.","related":["Total Blocking Time","First Contentful Paint"]},{"term":"Rage Click","abbr":null,"category":"Digital Experience","definition":"A frustration signal where a user rapidly clicks the same element repeatedly, indicating something is broken or unresponsive.","related":["Frustration Signal","Dead Click","Session Replay"]},{"term":"Dead Click","abbr":null,"category":"Digital Experience","definition":"A user click that produces no response, signaling a broken or confusing UI element, captured by RUM tools.","related":["Rage Click","Frustration Signal","Session Replay"]},{"term":"Frustration Signal","abbr":null,"category":"Digital Experience","definition":"An RUM-detected indicator of poor user experience — rage clicks, dead clicks, error clicks or repeated reloads.","related":["Rage Click","Dead Click","Real User Monitoring"]},{"term":"Conversion Funnel","abbr":null,"category":"Digital Experience","definition":"A modeled sequence of steps toward a goal (e.g., signup, checkout) with drop-off measured at each stage to find friction.","related":["User Session","A/B Testing","Business Observability"]},{"term":"Bounce Rate","abbr":null,"category":"Digital Experience","definition":"The share of sessions where a user leaves after viewing a single page without interacting, a signal of engagement or experience problems.","related":["User Session","Page View"]},{"term":"Response Time","abbr":null,"category":"APM","definition":"The total time to fully handle a request and return a response, the headline performance metric for applications.","related":["Latency","Apdex","Throughput"]},{"term":"Slow Transaction","abbr":null,"category":"APM","definition":"A transaction whose response time exceeds a threshold or baseline, flagged by APM for investigation and code-level analysis.","related":["Transaction","Slow Query","Latency"]},{"term":"External Call","abbr":null,"category":"APM","definition":"A call from a service to an external dependency (API, database, queue); APM measures these to attribute latency and detect failures.","related":["Dependency","Span","Database Monitoring"]},{"term":"Call Graph","abbr":null,"category":"APM","definition":"A representation of which methods or services call which, with timing, used to find where time is spent within a transaction.","related":["Method-Level Tracing","Flame Graph","Hot Path"]},{"term":"Snapshot","abbr":null,"category":"APM","definition":"A captured detailed record of a single transaction's execution (call stack, timings, context) taken when a problem or threshold breach occurs.","related":["Transaction","Stack Trace","Slow Transaction"]},{"term":"Deadlock","abbr":null,"category":"APM","definition":"A situation where two or more threads each wait on resources the others hold, so none can proceed, stalling the application.","related":["Thread","Concurrency","Lock Contention"]},{"term":"Lock Contention","abbr":null,"category":"APM","definition":"When multiple threads compete for the same lock, causing waiting and reduced throughput; a target of continuous profiling.","related":["Deadlock","Continuous Profiling","Thread Pool"]},{"term":"Service Health","abbr":null,"category":"APM","definition":"A summarized status of a service derived from its golden signals and SLOs, often shown as a color or score on dashboards.","related":["Golden Signals","SLO","Apdex"]},{"term":"Baseline Deviation","abbr":null,"category":"AIOps","definition":"The amount by which a current metric diverges from its learned baseline, used to score and prioritize anomalies.","related":["Baseline","Anomaly Detection","Anomaly Score"]},{"term":"Anomaly Score","abbr":null,"category":"AIOps","definition":"A numeric measure of how unusual a data point or pattern is relative to expected behavior, used to rank and threshold anomalies.","related":["Anomaly Detection","Baseline Deviation","Confidence"]},{"term":"Alert Grouping","abbr":null,"category":"AIOps","definition":"Combining related alerts into a single notification or incident based on time, topology or similarity to reduce noise.","related":["Event Correlation","Deduplication","Alert Storm"]},{"term":"Alert Enrichment","abbr":null,"category":"AIOps","definition":"Automatically adding context (owner, runbook, recent changes, topology) to alerts so responders can act faster.","related":["Enrichment","Change Event","Runbook"]},{"term":"Topology-Based Correlation","abbr":null,"category":"AIOps","definition":"Correlating events using a model of system dependencies so symptoms across related components are tied to one root cause.","related":["Event Correlation","Topology","Causal AI"]},{"term":"Fingerprint","abbr":null,"category":"AIOps","definition":"A signature that uniquely characterizes an alert or event so duplicates and recurrences can be matched and grouped.","related":["Deduplication","Alert Grouping"]},{"term":"Signal-to-Noise Ratio","abbr":null,"category":"AIOps","definition":"The proportion of actionable, meaningful alerts to total alerts; improving it is the central aim of AIOps noise reduction.","related":["Noise Reduction","Alert Fatigue","False Positive"]},{"term":"Predictive Alerting","abbr":null,"category":"AIOps","definition":"Raising alerts before a threshold is breached by forecasting trends, giving teams time to act before users are affected.","related":["Forecasting","Predictive Analytics","Burn Rate"]},{"term":"Confidence (AIOps)","abbr":null,"category":"AIOps","definition":"A measure of how certain a model is about a detection or root-cause conclusion, used to prioritize and to decide on automated action.","related":["Anomaly Score","Causal AI","Auto-Remediation"]},{"term":"Remediation Action","abbr":null,"category":"AIOps","definition":"A corrective step — restart, scale, roll back, failover — executed (manually or automatically) to resolve a detected problem.","related":["Auto-Remediation","Runbook Automation","Closed-Loop Automation"]},{"term":"Business Observability","abbr":null,"category":"AIOps","definition":"Connecting technical telemetry to business metrics (revenue, conversions, orders) so teams understand the real-world impact of system behavior.","related":["Conversion Funnel","Business Transaction","Service Health"]},{"term":"SIEM","abbr":"SIEM","category":"Security & SIEM","definition":"Security Information and Event Management — a platform that aggregates and correlates security logs and events across an organization to detect, investigate and report threats.","related":["SOAR","Log Aggregation","Threat Detection","Correlation"]},{"term":"SOAR","abbr":"SOAR","category":"Security & SIEM","definition":"Security Orchestration, Automation and Response — tools that automate and coordinate incident-response workflows and playbooks across security tools.","related":["SIEM","Playbook","Auto-Remediation","Incident Response"]},{"term":"XDR","abbr":"XDR","category":"Security & SIEM","definition":"Extended Detection and Response — a unified platform that correlates telemetry across endpoints, network, cloud and identity to detect and respond to threats.","related":["EDR","SIEM","Threat Detection"]},{"term":"EDR","abbr":"EDR","category":"Security & SIEM","definition":"Endpoint Detection and Response — software that continuously monitors endpoints for malicious activity and enables investigation and remediation.","related":["XDR","Threat Detection","Antivirus"]},{"term":"Threat Detection","abbr":null,"category":"Security & SIEM","definition":"Identifying malicious activity or indicators of compromise within an environment using signatures, behavioral analytics and threat intelligence.","related":["SIEM","Anomaly Detection","Indicator of Compromise","Detection Engineering"]},{"term":"Detection Engineering","abbr":null,"category":"Security & SIEM","definition":"The discipline of designing, building and tuning detections (rules, analytics, correlation) to reliably surface real threats while minimizing false positives.","related":["Threat Detection","SIEM","False Positive"]},{"term":"Incident Response","abbr":"IR","category":"Security & SIEM","definition":"The organized process of detecting, containing, eradicating and recovering from a security incident, followed by lessons learned.","related":["SOAR","Playbook","Incident Management","Forensics"]},{"term":"Playbook","abbr":null,"category":"Security & SIEM","definition":"A predefined, often automated, set of steps for responding to a specific type of security alert or incident, executed manually or via SOAR.","related":["SOAR","Runbook","Incident Response"]},{"term":"Indicator of Compromise","abbr":"IOC","category":"Security & SIEM","definition":"Forensic evidence that a system may have been breached — such as malicious IPs, file hashes or domains — used to detect and hunt threats.","related":["Threat Detection","Threat Intelligence","Threat Hunting"]},{"term":"Threat Intelligence","abbr":null,"category":"Security & SIEM","definition":"Curated information about adversaries, their techniques and indicators, used to inform detection, prioritization and response.","related":["Indicator of Compromise","MITRE ATT&CK","Threat Hunting"]},{"term":"Threat Hunting","abbr":null,"category":"Security & SIEM","definition":"Proactively searching through telemetry for hidden threats that evaded automated detection, guided by hypotheses and threat intelligence.","related":["Threat Intelligence","Indicator of Compromise","SIEM"]},{"term":"MITRE ATT&CK","abbr":null,"category":"Security & SIEM","definition":"A globally used knowledge base of adversary tactics and techniques observed in the real world, used to map detections and assess coverage.","related":["Threat Detection","Threat Intelligence","Kill Chain"]},{"term":"Kill Chain","abbr":null,"category":"Security & SIEM","definition":"A model describing the stages of a cyberattack from reconnaissance to exfiltration, used to understand and disrupt adversary activity.","related":["MITRE ATT&CK","Threat Detection"]},{"term":"Vulnerability","abbr":null,"category":"Security & SIEM","definition":"A weakness in software, configuration or process that an attacker can exploit to compromise a system's confidentiality, integrity or availability.","related":["CVE","CVSS","Patch","Exploit"]},{"term":"CVE","abbr":"CVE","category":"Security & SIEM","definition":"Common Vulnerabilities and Exposures — a standardized identifier (e.g., CVE-2021-44228) for a publicly disclosed security vulnerability.","related":["Vulnerability","CVSS","Patch"]},{"term":"CVSS","abbr":"CVSS","category":"Security & SIEM","definition":"Common Vulnerability Scoring System — a 0–10 framework for rating the severity of vulnerabilities to help prioritize remediation.","related":["CVE","Vulnerability","Severity"]},{"term":"Exploit","abbr":null,"category":"Security & SIEM","definition":"Code or a technique that takes advantage of a vulnerability to cause unintended behavior, such as gaining unauthorized access.","related":["Vulnerability","Zero-Day","Patch"]},{"term":"Zero-Day","abbr":null,"category":"Security & SIEM","definition":"A vulnerability unknown to the vendor (or unpatched) and actively exploitable, giving defenders zero days to prepare a fix.","related":["Vulnerability","Exploit","Patch"]},{"term":"Patch","abbr":null,"category":"Security & SIEM","definition":"A software update that fixes a vulnerability or bug; timely patch management is fundamental to reducing security risk.","related":["Vulnerability","CVE","Patch Management"]},{"term":"Penetration Testing","abbr":"Pentest","category":"Security & SIEM","definition":"Authorized simulated attacks against a system to find and demonstrate exploitable vulnerabilities before real adversaries do.","related":["Vulnerability","Red Team","Exploit"]},{"term":"Red Team","abbr":null,"category":"Security & SIEM","definition":"A group that emulates real attackers to test an organization's defenses and detection capabilities, opposite the defensive blue team.","related":["Blue Team","Penetration Testing","Purple Team"]},{"term":"Blue Team","abbr":null,"category":"Security & SIEM","definition":"The defensive security group responsible for detecting, responding to and preventing attacks, working against red-team exercises.","related":["Red Team","Purple Team","Incident Response"]},{"term":"Identity and Access Management","abbr":"IAM","category":"Security & SIEM","definition":"The framework of policies and tools that ensures the right identities have the right access to the right resources, covering authentication and authorization.","related":["Authentication","Authorization","RBAC","Least Privilege"]},{"term":"Authentication","abbr":"AuthN","category":"Security & SIEM","definition":"Verifying the identity of a user or system — proving you are who you claim to be — via passwords, keys, tokens or biometrics.","related":["Authorization","MFA","SSO","Identity and Access Management"]},{"term":"Authorization","abbr":"AuthZ","category":"Security & SIEM","definition":"Determining what an authenticated identity is allowed to do, enforced through permissions, roles and policies.","related":["Authentication","RBAC","Least Privilege","OPA"]},{"term":"MFA","abbr":"MFA","category":"Security & SIEM","definition":"Multi-Factor Authentication — requiring two or more independent credentials (something you know, have or are) to verify identity, greatly improving security.","related":["Authentication","SSO","Identity and Access Management"]},{"term":"SSO","abbr":"SSO","category":"Security & SIEM","definition":"Single Sign-On — letting users authenticate once and access multiple applications without re-entering credentials, often via SAML or OIDC.","related":["Authentication","OAuth","SAML","OIDC"]},{"term":"OAuth","abbr":null,"category":"Security & SIEM","definition":"An open standard for delegated authorization that lets applications access resources on a user's behalf without sharing their password, via access tokens.","related":["OIDC","Authorization","Token"]},{"term":"OIDC","abbr":"OIDC","category":"Security & SIEM","definition":"OpenID Connect — an identity layer on top of OAuth 2.0 that lets applications verify user identity and obtain basic profile information.","related":["OAuth","SSO","Authentication"]},{"term":"SAML","abbr":"SAML","category":"Security & SIEM","definition":"Security Assertion Markup Language — an XML-based standard for exchanging authentication and authorization data, commonly used for enterprise SSO.","related":["SSO","Authentication","Identity Provider"]},{"term":"Identity Provider","abbr":"IdP","category":"Security & SIEM","definition":"A service that creates, maintains and verifies user identities and issues authentication assertions to applications (e.g., Okta, Azure AD).","related":["SSO","SAML","OIDC"]},{"term":"Least Privilege","abbr":null,"category":"Security & SIEM","definition":"The principle of granting each identity only the minimum permissions needed to perform its function, reducing the impact of compromise.","related":["Authorization","RBAC","Zero Trust Architecture"]},{"term":"Secrets Management","abbr":null,"category":"Security & SIEM","definition":"Securely storing, distributing, rotating and auditing sensitive credentials like API keys and passwords, using tools such as HashiCorp Vault.","related":["Secret","Encryption at Rest","Vault"]},{"term":"Vault","abbr":null,"category":"Security & SIEM","definition":"HashiCorp Vault — a tool for securely storing and tightly controlling access to secrets such as tokens, passwords and certificates.","related":["Secrets Management","Encryption at Rest"]},{"term":"Encryption at Rest","abbr":null,"category":"Security & SIEM","definition":"Encrypting stored data so it is unreadable without keys, protecting it if storage media or backups are stolen.","related":["Encryption in Transit","Key Management","Secrets Management"]},{"term":"Encryption in Transit","abbr":null,"category":"Security & SIEM","definition":"Encrypting data while it moves across networks (typically via TLS) so it cannot be read or tampered with in transit.","related":["TLS","mTLS","Encryption at Rest"]},{"term":"Key Management","abbr":null,"category":"Security & SIEM","definition":"The processes and systems for generating, storing, rotating and revoking cryptographic keys throughout their lifecycle.","related":["Encryption at Rest","KMS","Public Key Infrastructure"]},{"term":"Public Key Infrastructure","abbr":"PKI","category":"Security & SIEM","definition":"The framework of certificates, authorities and policies that manages public-key encryption and digital identities for secure communication.","related":["Certificate","Certificate Authority","TLS"]},{"term":"Audit Log","abbr":null,"category":"Security & SIEM","definition":"An immutable, chronological record of security-relevant actions (who did what, when) used for compliance, forensics and detection.","related":["Log","Compliance","Forensics"]},{"term":"Compliance","abbr":null,"category":"Security & SIEM","definition":"Adhering to regulatory and industry standards (e.g., SOC 2, PCI DSS, GDPR, HIPAA) governing how data and systems must be protected and operated.","related":["Audit Log","Policy as Code","Governance"]},{"term":"Forensics","abbr":null,"category":"Security & SIEM","definition":"The investigation of a security incident by collecting and analyzing evidence (logs, memory, disk) to determine scope, cause and impact.","related":["Incident Response","Audit Log","Indicator of Compromise"]},{"term":"Malware","abbr":null,"category":"Security & SIEM","definition":"Malicious software — viruses, worms, ransomware, trojans, spyware — designed to damage, disrupt or gain unauthorized access to systems.","related":["Ransomware","EDR","Antivirus"]},{"term":"Ransomware","abbr":null,"category":"Security & SIEM","definition":"Malware that encrypts a victim's data and demands payment for the decryption key, a major modern threat to availability and continuity.","related":["Malware","Backup","Incident Response"]},{"term":"Phishing","abbr":null,"category":"Security & SIEM","definition":"A social-engineering attack that tricks people into revealing credentials or installing malware, usually via deceptive emails or sites.","related":["Social Engineering","MFA","Malware"]},{"term":"Social Engineering","abbr":null,"category":"Security & SIEM","definition":"Manipulating people into divulging information or performing actions that compromise security, exploiting human trust rather than technical flaws.","related":["Phishing","Threat Detection"]},{"term":"DDoS","abbr":"DDoS","category":"Security & SIEM","definition":"Distributed Denial of Service — an attack that overwhelms a target with traffic from many sources to make it unavailable to legitimate users.","related":["WAF","Rate Limiting","CDN"]},{"term":"Intrusion Detection System","abbr":"IDS","category":"Security & SIEM","definition":"A system that monitors network or host activity for signs of malicious behavior and raises alerts; an IPS additionally blocks it.","related":["Intrusion Prevention System","Threat Detection","Firewall"]},{"term":"Intrusion Prevention System","abbr":"IPS","category":"Security & SIEM","definition":"A security control that detects malicious activity and actively blocks or prevents it inline, extending IDS with enforcement.","related":["Intrusion Detection System","Firewall"]},{"term":"Security Posture","abbr":null,"category":"Security & SIEM","definition":"The overall security status of an organization's systems and ability to defend against and respond to threats, continuously assessed and improved.","related":["Compliance","Vulnerability","CSPM"]},{"term":"CSPM","abbr":"CSPM","category":"Security & SIEM","definition":"Cloud Security Posture Management — tools that continuously assess cloud configurations against best practices to find misconfigurations and risks.","related":["Security Posture","CWPP","Compliance"]},{"term":"CWPP","abbr":"CWPP","category":"Security & SIEM","definition":"Cloud Workload Protection Platform — security for workloads (VMs, containers, serverless) across environments, covering vulnerability and runtime protection.","related":["CSPM","Container Security","Runtime Security"]},{"term":"Container Security","abbr":null,"category":"Security & SIEM","definition":"Securing the container lifecycle — image scanning, registry controls, runtime protection and least-privilege configuration.","related":["Image Scanning","Runtime Security","CWPP"]},{"term":"Image Scanning","abbr":null,"category":"Security & SIEM","definition":"Analyzing container images for known vulnerabilities, secrets and misconfigurations before deployment, part of a secure supply chain.","related":["Container Security","Vulnerability","SBOM"]},{"term":"Runtime Security","abbr":null,"category":"Security & SIEM","definition":"Detecting and blocking malicious behavior in running workloads in real time, for example with eBPF-based tools like Falco.","related":["Container Security","eBPF","Falco"]},{"term":"Falco","abbr":null,"category":"Security & SIEM","definition":"A CNCF open-source runtime-security tool that uses kernel events (via eBPF) to detect anomalous and malicious behavior in containers and hosts.","related":["Runtime Security","eBPF","Threat Detection"]},{"term":"False Positive","abbr":null,"category":"Security & SIEM","definition":"An alert that flags benign activity as malicious; high false-positive rates cause alert fatigue and erode trust in detections.","related":["False Negative","Alert Fatigue","Detection Engineering"]},{"term":"False Negative","abbr":null,"category":"Security & SIEM","definition":"A real threat or problem that goes undetected by a system; minimizing false negatives is critical for security coverage.","related":["False Positive","Threat Detection"]},{"term":"Data Loss Prevention","abbr":"DLP","category":"Security & SIEM","definition":"Technologies and policies that detect and prevent the unauthorized transmission or leakage of sensitive data.","related":["Compliance","Encryption at Rest","Audit Log"]},{"term":"Honeypot","abbr":null,"category":"Security & SIEM","definition":"A decoy system deliberately exposed to attract and study attackers, providing early warning and threat intelligence.","related":["Threat Detection","Threat Intelligence","Deception"]},{"term":"PII","abbr":"PII","category":"Security & SIEM","definition":"Personally Identifiable Information — data that can identify an individual; handling it triggers privacy obligations and often requires redaction in logs.","related":["Compliance","Redaction","Data Loss Prevention"]},{"term":"Redaction","abbr":null,"category":"Security & SIEM","definition":"Removing or masking sensitive data (such as PII or secrets) from logs and telemetry before storage to meet privacy and compliance requirements.","related":["PII","Pipeline","Compliance"]},{"term":"Microservices","abbr":null,"category":"Cloud Native","definition":"Small, independently deployable services that each handle one capability and communicate over the network; the plural shorthand for a microservices architecture.","related":["Microservices Architecture","Service","Distributed System"]},{"term":"Child Span","abbr":null,"category":"Tracing","definition":"A span whose parent is another span, representing a sub-operation nested within it; child spans form the tree structure of a trace.","related":["Span","Root Span","Trace"]},{"term":"Span ID","abbr":null,"category":"Tracing","definition":"A unique identifier for an individual span within a trace, used together with the trace ID to establish parent-child relationships.","related":["Trace ID","Span","Span Context"]},{"term":"Rollup","abbr":null,"category":"Metrics","definition":"Aggregating fine-grained metric data into coarser summaries (by time or dimension) to reduce storage and speed up long-range queries.","related":["Aggregation","Downsampling","Resolution"]},{"term":"Centralized Logging","abbr":null,"category":"Logging","definition":"Collecting logs from many systems into one platform for unified search, correlation and retention, the foundation of log management.","related":["Log Aggregation","Log Shipper","ELK Stack"]},{"term":"User Experience","abbr":"UX","category":"Digital Experience","definition":"The overall quality of a user's interaction with a product, which observability measures through performance, errors and behavioral signals.","related":["Real User Monitoring","Apdex","Core Web Vitals"]},{"term":"Fault Domain","abbr":null,"category":"Reliability","definition":"A set of components that share a common point of failure (e.g., a rack, host or zone); spreading workloads across fault domains limits impact.","related":["Blast Radius","Availability Zone","Topology Spread"]},{"term":"Backward Compatibility","abbr":null,"category":"DevOps & CI/CD","definition":"A change that allows existing clients or data to keep working without modification, essential for safe rollouts and schema evolution.","related":["Schema Evolution","Data Contract","Rolling Update"]},{"term":"Migration","abbr":null,"category":"DevOps & CI/CD","definition":"Moving systems, data or workloads from one environment, version or platform to another, ideally incrementally and reversibly.","related":["Strangler Fig Pattern","Rollback","Backward Compatibility"]},{"term":"Integration","abbr":null,"category":"Standards & Tools","definition":"A prebuilt connector that lets an observability or other platform collect data from, or interact with, a specific technology or service.","related":["Agent","Exporter","API"]},{"term":"Web Server","abbr":null,"category":"Networking","definition":"Software that serves web content over HTTP, handling requests for pages, assets and APIs; examples include Nginx and Apache HTTP Server.","related":["Nginx","Reverse Proxy","HTTP"]},{"term":"Antivirus","abbr":null,"category":"Security & SIEM","definition":"Software that detects, blocks and removes malware using signatures and heuristics; modern endpoint security extends this with EDR.","related":["Malware","EDR","Endpoint"]},{"term":"Patch Management","abbr":null,"category":"Security & SIEM","definition":"The process of acquiring, testing and deploying software updates to fix vulnerabilities and bugs across an environment.","related":["Patch","Vulnerability","Compliance"]},{"term":"Poison Message","abbr":null,"category":"Data & Streaming","definition":"A message that repeatedly fails processing and can block or disrupt a queue; typically routed to a dead-letter queue after retries.","related":["Dead Letter Queue","Retry","Message Queue"]},{"term":"Endpoint (Security)","abbr":null,"category":"Security & SIEM","definition":"A user or server device (laptop, phone, VM) that connects to a network and is a common target requiring protection and monitoring.","related":["EDR","Antivirus","Zero Trust Architecture"]},{"term":"Experimentation","abbr":null,"category":"DevOps & CI/CD","definition":"Systematically testing changes on subsets of users (A/B or multivariate) and measuring outcomes to make data-driven product decisions.","related":["A/B Testing","Feature Flag","Progressive Delivery"]},{"term":"Cycle Time","abbr":null,"category":"DevOps & CI/CD","definition":"The time from starting work on a change to delivering it; a lean/flow metric closely related to lead time.","related":["Lead Time","Value Stream","DORA Metrics"]},{"term":"RASP","abbr":"RASP","category":"Security & SIEM","definition":"Runtime Application Self-Protection — security built into an application that detects and blocks attacks from within at runtime.","related":["WAF","DAST","Runtime Security"]},{"term":"IAST","abbr":"IAST","category":"Security & SIEM","definition":"Interactive Application Security Testing — analyzing an application for vulnerabilities from inside during normal testing, combining SAST and DAST strengths.","related":["SAST","DAST","RASP"]},{"term":"Sandboxing","abbr":null,"category":"Security & SIEM","definition":"Isolating code or files in a restricted environment so suspicious behavior can run and be analyzed without harming the host.","related":["Isolation","Honeypot","Container Security"]},{"term":"OpenMetrics","abbr":null,"category":"Standards & Tools","definition":"An open standard, derived from the Prometheus exposition format, for transmitting metrics at scale in a consistent, tool-neutral way.","related":["Prometheus","Metric","OpenTelemetry"]},{"term":"Pod Security Standards","abbr":null,"category":"Kubernetes","definition":"Kubernetes-defined policies (privileged, baseline, restricted) that constrain pod security settings to reduce risk.","related":["Admission Controller","RBAC","Container Security"]},{"term":"Connection Pooling","abbr":null,"category":"Networking","definition":"Reusing a pool of established connections (e.g., to a database) instead of opening new ones per request, reducing latency and resource use.","related":["Socket","Latency","Thread Pool"]},{"term":"Keepalive","abbr":null,"category":"Networking","definition":"A mechanism that keeps a connection open and verifies it is still alive across idle periods, avoiding repeated setup costs.","related":["TCP","Connection Pooling","Heartbeat"]},{"term":"MTU","abbr":"MTU","category":"Networking","definition":"Maximum Transmission Unit — the largest packet size a network link can carry; mismatches cause fragmentation and performance issues.","related":["Packet","Bandwidth"]},{"term":"BGP","abbr":"BGP","category":"Networking","definition":"Border Gateway Protocol — the routing protocol that exchanges reachability information between autonomous systems, directing traffic across the internet.","related":["Router","Anycast","IP Address"]},{"term":"Failback","abbr":null,"category":"Reliability","definition":"Returning operations to the primary system after a failover, once it has recovered, ideally without disruption.","related":["Failover","Disaster Recovery","High Availability"]},{"term":"Isolation","abbr":null,"category":"Distributed Systems","definition":"Separating components, tenants or workloads so they cannot interfere with each other, improving security, reliability and predictability.","related":["Namespace (Linux)","Multitenancy","Bulkhead"]},{"term":"Hot Storage","abbr":null,"category":"Standards & Tools","definition":"Fast, immediately queryable storage for recent, frequently accessed telemetry, contrasted with cheaper warm and cold tiers.","related":["Data Tiering","Cold Storage","Indexing Tier"]},{"term":"Warm Storage","abbr":null,"category":"Standards & Tools","definition":"A middle storage tier offering moderate cost and access speed for telemetry that is no longer hot but still queried occasionally.","related":["Hot Storage","Cold Storage","Data Tiering"]},{"term":"Observability Maturity","abbr":null,"category":"Fundamentals","definition":"A model describing an organization's progression from basic monitoring to advanced, correlated, automated observability practices.","related":["Observability","AIOps","MELT"]},{"term":"Service Catalog Entry","abbr":null,"category":"Visualization","definition":"A record in a service catalog describing one service's ownership, dependencies, SLOs, runbooks and health in one place.","related":["Service Catalog","Ownership","SLO"]},{"term":"Ownership","abbr":null,"category":"Visualization","definition":"The clear assignment of responsibility for a service or component to a team, essential for routing alerts and accountability.","related":["Service Catalog","On-Call","Escalation"]},{"term":"Golden Metrics","abbr":null,"category":"Metrics","definition":"A small, curated set of the most important metrics for a service (often the golden signals) surfaced for quick health assessment.","related":["Golden Signals","Service Health","Dashboard"]},{"term":"Trace Context","abbr":null,"category":"Tracing","definition":"The identifiers and flags propagated across services to associate spans with the same distributed trace; standardized by W3C Trace Context.","related":["W3C Trace Context","Span Context","Context Propagation"]},{"term":"Sampling Decision","abbr":null,"category":"Tracing","definition":"The choice of whether to record a given trace, made at the head or tail, that controls trace data volume and cost.","related":["Sampling","Head-Based Sampling","Tail-Based Sampling"]},{"term":"ESB","abbr":"ESB","category":"Architecture","definition":"Enterprise Service Bus — a centralized middleware that integrates applications by routing and transforming messages between them, associated with SOA.","related":["Service-Oriented Architecture","Message Queue","API Gateway"]},{"term":"Command and Control","abbr":"C2","category":"Security & SIEM","definition":"The infrastructure attackers use to communicate with and control compromised systems; detecting C2 traffic is a key defensive goal.","related":["Kill Chain","Threat Detection","Lateral Movement"]},{"term":"Anomaly","abbr":null,"category":"AIOps","definition":"A data point or pattern that deviates significantly from expected behavior, the thing anomaly detection aims to surface.","related":["Anomaly Detection","Anomaly Score","Outlier Detection"]},{"term":"Saturation Point","abbr":null,"category":"Reliability","definition":"The load level at which a resource or system can no longer keep up and performance degrades sharply; a key capacity threshold.","related":["Saturation","Capacity Headroom","Bottleneck"]},{"term":"Telemetry Agent","abbr":null,"category":"Standards & Tools","definition":"A process deployed on hosts or containers to collect and forward telemetry to a backend; examples include the Datadog and Grafana agents.","related":["Agent","Collector","Telemetry Pipeline"]},{"term":"Heatmap Visualization","abbr":null,"category":"Visualization","definition":"A density-based chart using color to show how values (such as latency) distribute across many series over time, revealing patterns averages hide.","related":["Heatmap","Histogram","Tail Latency"]}];
